-- Poems batch 184
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('00b9444b-778a-4f27-a3db-0e242af69b9a','和章父兄春歸韵','徐僑','宋','宋诗','song-poetry','','[]','元化渾淪迹已希，不緣風雨翳明輝。',32,'全唐诗/poet.song.178000.json','["元化渾淪迹已希，不緣風雨翳明輝。", "靜中會得生生意，滿眼春光未始歸。"]'),
('1c9e8f1f-eee9-4c54-ae86-f1da5d88e2a1','倚門','徐僑','宋','宋诗','song-poetry','','[]','碧松窩裏著吾身，風在襟裙月在門。',32,'全唐诗/poet.song.178000.json','["碧松窩裏著吾身，風在襟裙月在門。", "燈火未殘絃誦習，一團清興許誰論。"]'),
('91b4ec23-52cb-4411-8bde-d71798399367','酒後','徐僑','宋','宋诗','song-poetry','','[]','酒正醺人苦不禁，詩來撩我可無吟。',32,'全唐诗/poet.song.178000.json','["酒正醺人苦不禁，詩來撩我可無吟。", "輕紈不動清風在，况有松聲醒醉心。"]'),
('36768d7e-a68b-47c6-ac34-dbc6d56b5ca2','有感','徐僑','宋','宋诗','song-poetry','','[]','擎拳伺色紫朱前，極愛殫憂衽席邊。',32,'全唐诗/poet.song.178000.json','["擎拳伺色紫朱前，極愛殫憂衽席邊。", "能合此心移膝下，未慚舜聖與參賢。"]'),
('b5ab8c7a-01e0-4ada-9c89-872dee5eefa0','夏日即事','徐僑','宋','宋诗','song-poetry','','[]','桃藤下上蟻行暑，竹影浮沉龜蔭涼。',32,'全唐诗/poet.song.178000.json','["桃藤下上蟻行暑，竹影浮沉龜蔭涼。", "步緩幽塘成小立，清風微度藕花香。"]'),
('10fa9ee8-8e82-4ff4-936f-7d88fc654446','題六和塔','徐僑','宋','宋诗','song-poetry','','[]','慈恩昔日寄題名，此作江頭長短亭。',32,'全唐诗/poet.song.178000.json','["慈恩昔日寄題名，此作江頭長短亭。", "潮去潮來知幾恨，酣歌漁父許誰聽。"]'),
('32f2b29a-0fb8-421d-a880-99ff7180923f','歸自壽昌','徐僑','宋','宋诗','song-poetry','','[]','舟子長歌下急灘，江風吹我怯衣單。',32,'全唐诗/poet.song.178000.json','["舟子長歌下急灘，江風吹我怯衣單。", "一輪明月爲誰好，無限清光照夜寒。"]'),
('305a1242-a100-4645-98b1-f332c3ba36fc','過吳江','徐僑','宋','宋诗','song-poetry','','[]','北風獵獵送吾船，夜過吳江炯不眠。',32,'全唐诗/poet.song.178000.json','["北風獵獵送吾船，夜過吳江炯不眠。", "月色微明天覆水，倚看銀浪欲無邊。"]'),
('a86ded53-fbcc-46ab-9142-251ab4dd6f8f','西湖','徐僑','宋','宋诗','song-poetry','','["\u897f\u6e56"]','羣巒回照紫瀰漫，坐攬湖光風不寒。',32,'全唐诗/poet.song.178000.json','["羣巒回照紫瀰漫，坐攬湖光風不寒。", "最惜傍欄鳬鷺狎，往來不作眼生看。"]'),
('9c6070c4-22b8-40c6-b644-b9b35856511f','立春以詩并酒送滕知丞','徐僑','宋','宋诗','song-poetry','','[]','草殘木盡又春來，辜負梅花與酒杯。',32,'全唐诗/poet.song.178000.json','["草殘木盡又春來，辜負梅花與酒杯。", "政要詩翁裁好句，爲從今日洗塵埃。"]'),
('3d63b1ec-7aa8-45dd-b313-c4ab50330e60','和吳子開訪省中韵','徐僑','宋','宋诗','song-poetry','','[]','自公不退準爲常，永晝深簾坐此堂。',32,'全唐诗/poet.song.178000.json','["自公不退準爲常，永晝深簾坐此堂。", "今日與君添轉語，共參雲石與風篁。"]'),
('450683f0-6ef9-4a37-8c9c-af1d7b9b6924','晚步','徐僑','宋','宋诗','song-poetry','','[]','夕無下照澹雲亭，暝入前除獨自行。',32,'全唐诗/poet.song.178000.json','["夕無下照澹雲亭，暝入前除獨自行。", "棲樹喧沉砌吟迥，雨留微潤作秋清。"]'),
('ac34c251-133e-4969-a2da-28a7800e01d2','詠漁父  其一','徐僑','宋','宋诗','song-poetry','','[]','占得江湖汗漫天，了無鄉縣挂民編。',32,'全唐诗/poet.song.178000.json','["占得江湖汗漫天，了無鄉縣挂民編。", "賣魚買酒醉日日，長是太平無事年。"]'),
('26fd5305-f917-452c-9d09-f368f30e106c','詠漁父  其二','徐僑','宋','宋诗','song-poetry','','[]','只把絲綸當酒金，世間萬事不關心。',32,'全唐诗/poet.song.178000.json','["只把絲綸當酒金，世間萬事不關心。", "月移篷影醒未醒，人在蘆花深更深。"]'),
('02caa85b-9128-4aec-aaed-d0051c017070','晚望','徐僑','宋','宋诗','song-poetry','','[]','陂沼盈盈閑綠水，郊原浩浩湧青禾。',32,'全唐诗/poet.song.178000.json','["陂沼盈盈閑綠水，郊原浩浩湧青禾。", "煙連山際無人語，只有晚歸樵牧歌。"]'),
('bf7f188d-c7f4-451d-ab67-74244f58a5c1','竹間納凉','徐僑','宋','宋诗','song-poetry','','[]','拙哉百事不如人，天畀清閑適我真。',32,'全唐诗/poet.song.178000.json','["拙哉百事不如人，天畀清閑適我真。", "好是山深林密處，且還康濟比天民。"]'),
('9440741e-db3c-4f80-babe-b273552d52f0','趙昌父詩來舉似慈湖話頭次韵答之','徐僑','宋','宋诗','song-poetry','','[]','身在五雲雲自閑，相娛石友與蒼官。',32,'全唐诗/poet.song.178000.json','["身在五雲雲自閑，相娛石友與蒼官。", "山林老去方知味，加我五年當挂冠。"]'),
('c90f8070-b32f-41c4-b146-19b43f6d5b2c','刪後坡繁枝出四山剡溪陳正仲作詩有白雲移向青林外讓與幽人不敢爭之句因次其韵','徐僑','宋','宋诗','song-poetry','','[]','爲嫌遠目礙雙明，只許蒼松一幹橫。',32,'全唐诗/poet.song.178000.json','["爲嫌遠目礙雙明，只許蒼松一幹橫。", "盡對羣巒坐高爽，月來分席不渠爭。"]'),
('15755623-b305-4364-b4a8-b94ec7501718','約喻叔厚總幹會於香山','徐僑','宋','宋诗','song-poetry','','[]','鄉居唯我與君閑，相見俱緣一出慳。',32,'全唐诗/poet.song.178000.json','["鄉居唯我與君閑，相見俱緣一出慳。", "此去君家無十里，杖藜明日會香山。"]'),
('bb9c4048-31d8-4030-aa52-8bd43e38b431','對雷峰','徐僑','宋','宋诗','song-poetry','','[]','雷峰頂上兩三松，挺秀扶疎印碧空。',32,'全唐诗/poet.song.178000.json','["雷峰頂上兩三松，挺秀扶疎印碧空。", "坐石倚筇看不足，此心游泊太虛中。"]'),
('b500074d-a66d-472e-a391-42835d8f4695','雲入窗牖','徐僑','宋','宋诗','song-poetry','','[]','白雲入戶牖，幽趣頗相關。',24,'全唐诗/poet.song.178000.json','["白雲入戶牖，幽趣頗相關。", "俗遠人無累，心夷物自閑。"]'),
('da98429b-cd08-4613-ac6b-779171473d06','懶書問','徐僑','宋','宋诗','song-poetry','','[]','避閙深違俗，耽閑懶作書。',24,'全唐诗/poet.song.178000.json','["避閙深違俗，耽閑懶作書。", "故人無誚我，丘壑政關渠。"]'),
('556c0ce4-a0a4-4417-92f7-7e7d63375f9e','欲雨雪而晴','徐僑','宋','宋诗','song-poetry','','[]','雲凍雨無脚，寒凝霜有毛。',24,'全唐诗/poet.song.178000.json','["雲凍雨無脚，寒凝霜有毛。", "却能開霽色，愛日炫初晴。"]'),
('7483da61-70dc-462c-a10b-74b77ca49efe','題杜仲高松杉檜圖','徐僑','宋','宋诗','song-poetry','','[]','老幹矗無容，虬枝蔚相倚。',24,'全唐诗/poet.song.178000.json','["老幹矗無容，虬枝蔚相倚。", "圖以歸草堂，怡怡有深旨。"]'),
('6fbaf3fd-bd12-45f1-a26e-b616ab9ac519','和徐敬伯知縣別喻伯經韵','徐僑','宋','宋诗','song-poetry','','[]','深院楊花閑暇，小亭林影清微。',28,'全唐诗/poet.song.178000.json','["深院楊花閑暇，小亭林影清微。", "忙裏不知客去，病中無柰春歸。"]'),
('16bd3cfc-b9b4-4a9c-8a8a-23f80c21d921','竹門','徐僑','宋','宋诗','song-poetry','','[]','竹門何爲設，護此自在身。',192,'全唐诗/poet.song.178000.json','["竹門何爲設，護此自在身。", "而有不知者，謂隔一切人。", "門有閉有開，人有疏與親。", "閉以謝俗客，開以納嘉賓。", "或方計財利，我方甘窶貧。", "或方圖宦達，我方埋隠淪。", "豈惟乖趨尚，誠亦困糾紛。", "若夫道義交，開益所願聞。", "清幽能共適，淡薄能相因。", "與夫學問徒，講說敢辭勤。", "義理滋我悅，詩書陶我真。", "俱不役殽酌，且無昏精神。", "然當時省己，勿或浪尤人。", "古人重晚節，氣衰當志新。", "古人貴老成，齒頹資德尊。", "初心苟無負，斯不愧斯門。"]'),
('d9d2ca4d-7c21-4cb2-aca5-c60631d04528','虎邱謁和靖祠','徐僑','宋','宋诗','song-poetry','','[]','涵養當用敬，進學在致知。',144,'全唐诗/poet.song.178000.json','["涵養當用敬，進學在致知。", "如車去隻輪，跬步不可移。", "夫子受師說，惟敬實所持。", "升堂逮易簀，參倚日在茲。", "遺言落人間，考論極研幾。", "是心要收斂，中不容毫釐。", "大學著明法，格物及楷梯。", "放心苟不收，窮格將安施。", "古人貴爲己，末俗多外馳。", "豈無實踐者，茲焉當反思。", "晚生拜遺像，敷衽跪陳詞。", "願言服予膺，沒齒以爲期。"]'),
('ffef8454-7833-4cab-88d9-1569128803b4','偶書  其一','徐僑','宋','宋诗','song-poetry','','[]','有原一本流無窮，有物萬殊生不同。',32,'全唐诗/poet.song.178000.json','["有原一本流無窮，有物萬殊生不同。", "自從太極兩儀後，往古來今感應中。"]'),
('74be0f19-7e9a-45e2-bd63-74f5764ca95e','偶書  其二','徐僑','宋','宋诗','song-poetry','','[]','日月東西遞往還，四時遷易不曾閒。',32,'全唐诗/poet.song.178000.json','["日月東西遞往還，四時遷易不曾閒。", "要知天地生成妙，只在陰陽進退間。"]'),
('e8723684-fbc2-4bbf-b24e-262f7be01f5f','游石洞','徐僑','宋','宋诗','song-poetry','','[]','我來叩石洞，嶄絕何從登。',132,'全唐诗/poet.song.178000.json','["我來叩石洞，嶄絕何從登。", "天開一間路，崖列兩連屏。", "有水泠泠來，委蛇貫中行。", "五丁修磴道，引步若余迎。", "昏暮坐危閣，蕭颼風雨聲。", "不知身何許，似有通山靈。", "晨興窮所歷，石轉泉逾清。", "絕頂一带垂，方諸函明泓。", "想當春夏交，雪練輸浮輕。", "欲去重倚徙，拳石提蒲生。", "歸與置窗几，聊以誌餘情。"]'),
('1f9e748b-390e-4593-a9f5-3ca272ccc7f6','登城陽山','許文蔚','宋','宋诗','song-poetry','','[]','我祖有遺迹，振屐訪南嶺。',48,'全唐诗/poet.song.178000.json','["我祖有遺迹，振屐訪南嶺。", "憑高一以眺，萬壑皆雲烟。", "谷鳥猶嚶嚶，遼鶴無時旋。", "一飲丹池水，心中塵慮捐。"]'),
('695c095e-0375-417e-9e22-e511831b22a2','和金表叔中秋題月','朱申','宋','宋诗','song-poetry','','[]','平分秋半月華圓，玉碾無聲靜轉旋。',32,'全唐诗/poet.song.178000.json','["平分秋半月華圓，玉碾無聲靜轉旋。", "月桂從攀由我捷，姮娥不解是誰先。"]'),
('5873471c-1b6d-46e7-a471-8f8afaa43658','曾公道夫出示先世手澤歛衽拜觀之餘敬題二小詩  其一','聶子述','宋','宋诗','song-poetry','','[]','香瓣平生滿意熏，更參曲阜問關津。',32,'全唐诗/poet.song.178000.json','["香瓣平生滿意熏，更參曲阜問關津。", "祇宜黄閣官尊貴，不敢近前丞相嗔。"]'),
('2b9755cb-bd60-47af-a009-bc79045fb030','曾公道夫出示先世手澤歛衽拜觀之餘敬題二小詩  其二','聶子述','宋','宋诗','song-poetry','','[]','一門翰墨森圭璧，諸老題評粲錦花。',32,'全唐诗/poet.song.178000.json','["一門翰墨森圭璧，諸老題評粲錦花。", "珍重雲仍好收拾，夜虹貫月定君家。"]'),
('599a5c45-41c1-4192-8115-6f0689d27446','雪谷潭','張嗣古','宋','宋诗','song-poetry','','[]','崎嶇鳥道開烟蘿，長松偃蹇聲蕩摩。',64,'全唐诗/poet.song.178000.json','["崎嶇鳥道開烟蘿，長松偃蹇聲蕩摩。", "白龍怒吼挂絕壁，蒼兕離立迎清波。", "枯筇拄破青苔色，雷雨收功神歛迹。", "窮源不得空歸來，掬雪摶珠三太息。"]'),
('a47e4f3c-16b1-4ed4-b624-548c193058b0','登妙高亭','張嗣古','宋','宋诗','song-poetry','','[]','雨餘山石洗孱顔，卧虎蹲羊各自閑。',32,'全唐诗/poet.song.178000.json','["雨餘山石洗孱顔，卧虎蹲羊各自閑。", "杖屨貪穿秋色好，不知衣惹蘚痕斑。"]'),
('5027bd48-22e5-41bd-8443-85749c34f071','瑞峰','余復','宋','宋诗','song-poetry','','[]','海上一峰高插天，山頭眼力窮大千。',32,'全唐诗/poet.song.178000.json','["海上一峰高插天，山頭眼力窮大千。", "飛來鴻鵠下霄漢，掩翼縮足今三年。"]'),
('3d5a097a-a1c0-4988-95ef-40574185a5a5','仙霞嶺','余復','宋','宋诗','song-poetry','','[]','二十年前過此間，旅囊羞澀筆頭慳。',64,'全唐诗/poet.song.178000.json','["二十年前過此間，旅囊羞澀筆頭慳。", "時來山色與人好，我亦詩腸似海寬。", "舊事消除身後夢，新聲慚愧路旁官。", "乘車衣錦渾閑事，留此功名竹帛看。"]'),
('83691fd0-cf70-4867-9c38-5ee04b918b40','文筆峰','余復','宋','宋诗','song-poetry','','[]','一飛一飛知幾時，斗酒落魄誰共知。',32,'全唐诗/poet.song.178000.json','["一飛一飛知幾時，斗酒落魄誰共知。", "胸中造物飽星斗，筆下文字盤蛟螭。"]'),
('204e9485-55dc-45de-adf3-cd500e97456c','西陂','余復','宋','宋诗','song-poetry','','[]','涉海波濤險，登山足力疲。',288,'全唐诗/poet.song.178000.json','["涉海波濤險，登山足力疲。", "胡爲赤鑑遊，海角山之涯。", "崎嶇亂石間，况復乘船危。", "茲遊固有意，訪古傷今時。", "荒陂存遺跡，缺處十丈餘。", "父老向我言，先疇爲農師。", "當時大父行，相與築此堤。", "堤成百物豐，師承及見之。", "稻蟹不論錢，况敢論糠粃。", "一朝壞不修，驚心傷鼓鼙。", "田家歲作苦，土狹何由支。", "憶昔禾黍地，石水數斗泥。", "前功嗟已廢，繼者今其誰。", "曾聞部使者，詢問及故基。", "水利固可究，具文怨徒欺。", "又聞勸農吏，楚楚多奇姿。", "朝遊暮始還，山水窮清暉。", "有念不及此，但見冠蓋飛。", "公家急相歛，星火驚文移。", "農無地可耕，歲入何從規。", "今幸長官賢，願言拯我饑。", "作書白太守，經營得如茲。", "珍重父老言，豈爲兒童戲。", "皇華如觀風，此老誠可資。"]'),
('8906f320-9507-46d7-8b96-5f0d57a404a2','霍童山','余復','宋','宋诗','song-poetry','','[]','霍童山峰凡六六，不知仙子在何山。',64,'全唐诗/poet.song.178000.json','["霍童山峰凡六六，不知仙子在何山。", "秋風萬里一黄鶴，返照半林雙白鷴。", "長劍氣橫霄漢外，飛泉影落畫圖間。", "自憐懶作朝陽客，訪道尋真日往返。"]'),
('185d6d0e-ca29-4190-afb7-f7158e485453','金鰲橋','余復','宋','宋诗','song-poetry','','[]','吾閩三山妙天下，靈鰲背上羅高峯。',32,'全唐诗/poet.song.178000.json','["吾閩三山妙天下，靈鰲背上羅高峯。", "山環水繞龍虎伏，人在縹渺烟霞中。"]'),
('8f230e26-eeb0-48de-bbec-001aa655f111','報恩寺','余復','宋','宋诗','song-poetry','','[]','大山奔到海之濱，中有輝光佛剎新。',32,'全唐诗/poet.song.178000.json','["大山奔到海之濱，中有輝光佛剎新。", "前後二三皆梵侶，不知誰是報恩人。"]'),
('5a9f7d17-d091-4350-ac66-837fd5cfea18','和御賜登第','余復','宋','宋诗','song-poetry','','[]','風虎雲龍豈偶然，信知盛世士多賢。',64,'全唐诗/poet.song.178000.json','["風虎雲龍豈偶然，信知盛世士多賢。", "虞庠教育蒙深澤，漢殿咨詢愧首延。", "釋褐遽沾瓊宴寵，錫詩齊聽玉音宣。", "愛君憂國平生志，敢負周王宴樂篇。"]'),
('3a0f1882-4ccc-48b0-bcd0-b921faa21de3','敬題濂溪先生書堂  其一','柴中行','宋','宋诗','song-poetry','','[]','有生同宇宙，所欠好江山。',48,'全唐诗/poet.song.178000.json','["有生同宇宙，所欠好江山。", "因自舂陵至，留居廬阜間。", "斯文傳墜緒，太極妙循環。", "希聖誠何事，懷哉伊與顔。"]'),
('afb9ed80-bf2a-4046-8412-4b01b9989454','敬題濂溪先生書堂  其二','柴中行','宋','宋诗','song-poetry','','[]','出城三四里，矯首愜遐觀。',48,'全唐诗/poet.song.178000.json','["出城三四里，矯首愜遐觀。", "頓覺市聲絕，忻從天宇寬。", "康山書几浄，湓浦硯泓寒。", "一誦愛蓮說，塵埃百不干。"]'),
('aa000d30-ed46-4f75-9a4d-808713522864','送許郎中出知漳州','柴中行','宋','宋诗','song-poetry','','[]','君子重出處，兒女多依違。',148,'全唐诗/poet.song.178000.json','["君子重出處，兒女多依違。", "孰知退有義，一辭若發機。", "刑部今其人，識遠渺造微。", "時方事疾走，而我心獨非。", "老色未上面，健筆駃于飛。", "宛然傲霜菊，燦燦黄金輝。", "勉留鵷鷺行，夫豈少輕肥。", "一麾即得請，衆目駭見稀。", "了不露纖芥，舒卷流清{山/徽}。", "凉風稱歸棹，灝氣浥征衣。", "婆娑慰邱園，咳唾落珠璣。", "因風來錦囊，猶足慰依依。"]'),
('79383d3c-1013-491c-9c71-258db5f8e60b','句  其一','柴中行','宋','宋诗','song-poetry','','[]','一簇人家起暮煙。',8,'全唐诗/poet.song.178000.json','["一簇人家起暮煙。"]'),
('8c194e9e-50ba-4ef7-9599-5c3528317985','句  其二','柴中行','宋','宋诗','song-poetry','','[]','郭外春山明錦繡。',8,'全唐诗/poet.song.178000.json','["郭外春山明錦繡。"]'),
('f791f1b1-c748-460d-90dd-31a2b059d346','句  其三','柴中行','宋','宋诗','song-poetry','','[]','想得彭園富春色。',8,'全唐诗/poet.song.178000.json','["想得彭園富春色。"]'),
('811c2c6d-8b2d-4690-a5c2-0d91eb3257c4','跋山谷書范滂傳帖','柴中守','宋','宋诗','song-poetry','','[]','小春晝日如春晚，飲罷披圖清興遠。',224,'全唐诗/poet.song.178000.json','["小春晝日如春晚，飲罷披圖清興遠。", "夜光照屋四座驚，金薤銀鈎真墨本。", "當年太史謫宜州，腸斷梅花棲戍樓。", "拾遺不逢東道主，翰林長作夜郎囚。", "蠻烟瘴雨森鈇鉞，更值韓盧搜兔窟。", "老色上面懽去心，惟有忠肝懸日月。", "郡丞嗜好殊世人，投箋乞字傳兒孫。", "平生孟博是知己，筆下寫出精神騫。", "興亡萬古同一轍，黨論到頭不堪說。", "刊章下郡漢道微，清流入河唐祚絕。", "先朝白晝狐亦鳴，正氣消盡邪氣生。", "殿門斷碑仆未起，中原戎馬來縱橫。", "生蛟入手不敢玩，往事凄涼重三歎。", "蘭亭瘞鶴徒爾爲，好刻此書裨廟算。"]'),
('2c9503c9-8ac3-4f50-8529-ceeb7d2e7cd5','題薛教授靖軒','豐有俊','宋','宋诗','song-poetry','','[]','小船行行過靖軒，衾紬帷楮興悠然。',32,'全唐诗/poet.song.178000.json','["小船行行過靖軒，衾紬帷楮興悠然。", "如何打疊江湖志，甘守陳編隠几眠。"]'),
('f800d25f-529c-4cf3-b1ec-e2465506da7d','教授兩爲玉蘂花賦長韻富贍清新老病無以奉酬輒用楊史君韻爲謝','林迪','宋','宋诗','song-poetry','','[]','廣行行實稱才華，如節鸞和馭寶車。',64,'全唐诗/poet.song.178000.json','["廣行行實稱才華，如節鸞和馭寶車。", "曾燕瓊林天一幄，却吟玉蘂市三家。", "大篇追補唐詩闕，盛事常流魯頖誇。", "別有冰姿延客住，白池賸種白蓮花。"]'),
('7fcc071f-e50a-49f3-968b-a1ec2fb2591a','次韻廷秀待制玉蘂','林迪','宋','宋诗','song-poetry','','[]','姑射山前雪照人，長安水畔態尤真。',64,'全唐诗/poet.song.178000.json','["姑射山前雪照人，長安水畔態尤真。", "步摇翹玉中心整，瓔珞塗金四面勻。", "常笑荼䕷藏浪蕊，獨陪芍藥殿餘春。", "自從唐代來天女，直到平園見後陳。"]'),
('d8da752b-30fb-4d6c-9504-7b180e6d37d9','去夏孫從之示玉蘂佳篇時過未敢賡和今年此花盛開輒次嚴韻并以新刻辯證爲獻','林迪','宋','宋诗','song-poetry','','[]','食菜曾饕三百囷，種花重看一番新。',64,'全唐诗/poet.song.178000.json','["食菜曾饕三百囷，種花重看一番新。", "洞仙舊賞輪無迹，工部高吟筆有神。", "疊雪雅宜歌白雪，送春仍欲買青春。", "向來僞帖今冰釋，從此嘉名徧廣輪。"]'),
('63e00caa-24fa-46ca-9098-adf59bc5ed0a','大滌洞天留題','林迪','宋','宋诗','song-poetry','','[]','暇日來游九鎖山，登龍踞虎恣躋攀。',64,'全唐诗/poet.song.178000.json','["暇日來游九鎖山，登龍踞虎恣躋攀。", "方瞳皓豁小天下，仙隠清越非人間。", "秘籍瓊科輝映簇，白雲朱鶴鎮長閑。", "洞中丹竈開還未，願覓刀圭駐瘠顔。"]'),
('de195141-bbd9-4659-b0aa-7cf48b6494ed','方壺別墅','汪楚材','宋','宋诗','song-poetry','','[]','面面軒窗好，溪山不待招。',48,'全唐诗/poet.song.178000.json','["面面軒窗好，溪山不待招。", "清風修竹徑，細雨綠荷橋。", "地僻人烟少，天恢景象饒。", "襟懷無一事，終老樂簞瓢。"]'),
('86dac7b2-23ee-4036-9723-a57d027616b1','贈胡彥忠','吳豐','宋','宋诗','song-poetry','','[]','古羊人物舜風餘，子姓傳來祇舊廬。',32,'全唐诗/poet.song.178000.json','["古羊人物舜風餘，子姓傳來祇舊廬。", "爲愛一門能守義，相承五世不分居。"]'),
('32775354-c418-48f1-bb08-737f6c70cd53','南溪暮春','戴蒙','宋','宋诗','song-poetry','','[]','家住南溪欲盡頭，茂林脩竹幾清幽。',64,'全唐诗/poet.song.178000.json','["家住南溪欲盡頭，茂林脩竹幾清幽。", "菰蒲漲綠蛙專夜，樹葉吹寒麥半秋。", "修褉從教非節物，舞雩元自有風流。", "明朝酒醒春猶在，更向長潭上小舟。"]'),
('60e671d4-b1c0-4998-a1b2-5a4a48bbfd39','極目亭','徐次鐸','宋','宋诗','song-poetry','','[]','幾點歸舟破暮烟，數行雁字落霞邊。',32,'全唐诗/poet.song.178000.json','["幾點歸舟破暮烟，數行雁字落霞邊。", "世間安得王摩詰，爲寫琴川作輞川。"]'),
('4a62def7-5f90-4be5-bfb4-f5bf8d265eeb','重建東堂','程九萬','宋','宋诗','song-poetry','','[]','宦遊偶落雲水鄉，耻以貪墨爲吏商。',112,'全唐诗/poet.song.178000.json','["宦遊偶落雲水鄉，耻以貪墨爲吏商。", "三年寄傲南窗月，一瓣爲炷東堂香。", "翛然清風揖佳客，好古博雅真揚揚。", "舊題湔祓古寺壁，濁酒呼索鄰家牆。", "淋浪醉墨鸞鳳舞，警語峭厲凌冰霜。", "大碑小碑共檢校，次第安置堂中央。", "朅來絃歌有餘暇，逸興賸欲希韓湘。"]'),
('398d42b5-b65a-412a-a2cd-56182b4cfb37','松桂亭','程九萬','宋','宋诗','song-poetry','','[]','松桂移栽滿，園亭改築新。',48,'全唐诗/poet.song.178000.json','["松桂移栽滿，園亭改築新。", "詩書千古事，松桂四時心。", "蕭瑟風成韻，扶疎月滿陰。", "一琴聊自託，山水是知音。"]'),
('a5d8bb17-06bf-4430-a919-ae8ab078ef54','烟霞塢二首  其一','程九萬','宋','宋诗','song-poetry','','[]','山深何限好，客到輒同登。',48,'全唐诗/poet.song.178000.json','["山深何限好，客到輒同登。", "泉壑嵐光冷，烟林霽色凝。", "韻艱詩益健，杯數量難勝。", "老矣功名穩，何須歎沔澠。"]'),
('ce968328-867d-4b7a-b747-11204028c5e6','烟霞塢二首  其二','程九萬','宋','宋诗','song-poetry','','[]','鬢髮幾星星，風霜抑飽經。',48,'全唐诗/poet.song.178000.json','["鬢髮幾星星，風霜抑飽經。", "年華輕過鳥，身世俯危亭。", "寒碧還相照，飛湍盍暫停。", "平生愛山眼，分外爲渠清。"]'),
('32ecc0e5-7a28-4776-bb59-8c052036bc69','證道寺','程九萬','宋','宋诗','song-poetry','','[]','二載塵勞薄宦身，雙峰幾憶舊家鄰。',32,'全唐诗/poet.song.178000.json','["二載塵勞薄宦身，雙峰幾憶舊家鄰。", "甫能再上陽城考，更有一年孤負春。"]'),
('93409023-6564-4248-8cd0-663405540fa0','銅山','程九萬','宋','宋诗','song-poetry','','[]','飛鳥投林去復還，臨風恒憶舊家山。',32,'全唐诗/poet.song.178000.json','["飛鳥投林去復還，臨風恒憶舊家山。", "平生杖履經行處，杳在雲烟髣髴間。"]'),
('230008c8-e2d1-4f76-9a25-7a6406fc743b','石頤寺','程九萬','宋','宋诗','song-poetry','','[]','聞法師來杖錫東，於菟蹭蹬奮雷風。',32,'全唐诗/poet.song.178000.json','["聞法師來杖錫東，於菟蹭蹬奮雷風。", "當時地裂泉隨動，一酌清甘萬慮空。"]'),
('797d846c-9296-4fc1-9c85-e487d3ef4d55','翠峰寺和毛澤堂韻','程九萬','宋','宋诗','song-poetry','','[]','巖石玲瓏翠竹斜，木犀依約又殘花。',32,'全唐诗/poet.song.178000.json','["巖石玲瓏翠竹斜，木犀依約又殘花。", "長官媿我無才思，却憶東堂舊作家。"]'),
('21b1e300-a17d-4d27-9727-a1a85237c53e','峴石寺','程九萬','宋','宋诗','song-poetry','','[]','蒼巖絕頂俯晴川，佳處潛開小洞天。',64,'全唐诗/poet.song.178000.json','["蒼巖絕頂俯晴川，佳處潛開小洞天。", "琴几棋臺誰是伴，霞棲月嘯恍如仙。", "□山□□□多石，□□□□□引泉。", "獨取懸崖□□□，□□已自□燕然。"]'),
('97098567-8ba8-40e5-98d8-5234b4fb3ba7','謝李宏齋先生','毛友誠','宋','宋诗','song-poetry','','[]','何以答夫子，力學窮朝曛。',36,'全唐诗/poet.song.178000.json','["何以答夫子，力學窮朝曛。", "瞬息纔不學，老與衰相親。", "誓參舞雩樂，胸中長暮春。"]'),
('a8c13483-bbc6-45fb-a7e7-8f85f34a5722','仙人橋石刻','方暹','宋','宋诗','song-poetry','','[]','鄉村十里少人家，手掬清泉嚼細茶。',32,'全唐诗/poet.song.178000.json','["鄉村十里少人家，手掬清泉嚼細茶。", "洞口春深却無酒，故人相贈以桃花。"]'),
('1827ac3e-9d61-4fc3-bb53-0ca79c3a9095','里中張氏母出與邑宰母宴餞以詩','方輗','宋','宋诗','song-poetry','','[]','張氏母袁稱壽星，生紹興庚申今有百五齡。',139,'全唐诗/poet.song.178000.json','["張氏母袁稱壽星，生紹興庚申今有百五齡。", "子孫耕稼食可飽，女婦紡織衣稱情。", "白髮既脫生黑髮，耳目聰明長步行。", "五朝皇帝恩廣大，一老平時身太平。", "鄉里皆慶喜，縣官問姓名。", "闔門漏屋下，上詣縣官廳。", "太夫人之面可識，太夫人之堂可升。", "即前再拜問起居，謝官下念田里氓。", "尊高年以長其長，凡爲人子沸歡聲。"]'),
('301f6b1b-1181-46b7-ae5c-b80a807a8b66','道巖','方輗','宋','宋诗','song-poetry','','[]','太極巖圖出道州，茲巖名道實相猶。',32,'全唐诗/poet.song.178000.json','["太極巖圖出道州，茲巖名道實相猶。", "元公圖說茲巖具，好向巖中仔細求。"]'),
('8f635d59-537a-4bdd-9f49-d7f9822dc064','省墓','黄瑄','宋','宋诗','song-poetry','','[]','長因風木起悲酸，省墓歸來痛忍言。',64,'全唐诗/poet.song.178000.json','["長因風木起悲酸，省墓歸來痛忍言。", "雖得青衫聯子貴，深慚白髮負親恩。", "璜溪猶有家居舊，蕭寺尋來手澤存。", "墨迹依然逾二紀，摩挲塵壁黯銷魂。"]'),
('94f1a728-da76-4215-a981-fbcd679bb7c0','句','黄治','宋','宋诗','song-poetry','','[]','威稄赤壁千尋峻，德量黄陂萬頃寬。',16,'全唐诗/poet.song.178000.json','["威稄赤壁千尋峻，德量黄陂萬頃寬。"]'),
('c82adc7d-187e-49d2-8e52-f6252440e27f','過黄楊奧孝子董公墓','葉澄','宋','宋诗','song-poetry','','[]','我陟黄楊奧，我懷董孝君。',24,'全唐诗/poet.song.178000.json','["我陟黄楊奧，我懷董孝君。", "懷君君不見，冢草裹晴雲。"]'),
('571cf883-7647-4e96-bdc7-94b78b9ad827','陽華巖','桂如虎','宋','宋诗','song-poetry','','[]','天作高山勢已空，地開巖竇巧玲瓏。',64,'全唐诗/poet.song.178000.json','["天作高山勢已空，地開巖竇巧玲瓏。", "卷成璆屋垂瓊珮，擘破蒼崖潄玉虹。", "雲氣擁時來座上，塵埃飛不到亭中。", "品題自有元郎句，我輩聊書一笑同。"]'),
('12775cc2-1cb6-4ad3-be60-c9d462340901','藍溪次曾狀元韻','林伯春','宋','宋诗','song-poetry','','[]','羊腸路入最高峰，倦倚東風點瘦筇。',64,'全唐诗/poet.song.178000.json','["羊腸路入最高峰，倦倚東風點瘦筇。", "芳草有情春意遠，青山依舊暮雲重。", "新來梵閣添奇觀，前度詩人带老容。", "寄我此身天地裏，夢回林杪一聲鐘。"]'),
('4cb88896-893c-45ea-9e03-a423cd47427c','丹崖','鄭瀛','宋','宋诗','song-poetry','','[]','丹崖之山丹氣浮，葛洪老仙居上頭。',64,'全唐诗/poet.song.178000.json','["丹崖之山丹氣浮，葛洪老仙居上頭。", "丹成一去幾千載，至今猿鶴生清愁。", "丹井有泉石有拇，流芳直與天地久。", "我來問山山不知，坐費山僧一盃酒。"]'),
('cd62595c-71d1-4bf0-8e45-c7aad09675e9','南野暮鎔','鄭瀛','宋','宋诗','song-poetry','','[]','村南野老亦多伎，兩鬢髼鬆狀如鬼。',64,'全唐诗/poet.song.178000.json','["村南野老亦多伎，兩鬢髼鬆狀如鬼。", "嬴顛秦蹶了不聞，一心只向紅爐裏。", "風鞴在手金在鎔，等閒變化天無工。", "日暮歡呼走妻子，買魚沽酒歌春風。"]'),
('1476ac5f-1acf-4e1d-adba-6eb95ceb31d1','伏虎崖','鄭瀛','宋','宋诗','song-poetry','','[]','西崖有虎憑其威，凜然百獸不敢窺。',64,'全唐诗/poet.song.178000.json','["西崖有虎憑其威，凜然百獸不敢窺。", "衆山壓倒勢莫敵，磅礴萬古誰能驅。", "鄉人好利不知計，翦毛伐骨何太厲。", "安知此虎不汝欺，長作吾家一屏蔽。"]'),
('03e5befa-fe32-4d9f-b947-49f0f2bd23ad','葛井涵秋','鄭瀛','宋','宋诗','song-poetry','','[]','吾鄉葛氏真好奇，鑿開石井山之湄。',64,'全唐诗/poet.song.178000.json','["吾鄉葛氏真好奇，鑿開石井山之湄。", "寒波清冽不受暑，主人愛取沁詩脾。", "百年興廢事非昔，莓苔剝落土花碧。", "我來拂拭已忘言，落葉西風秋析析。"]'),
('f5f80c26-758a-4298-a2c8-0647883d036c','官塘競渡','鄭瀛','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江百里濃於醅，天風吹作雲濤堆。',64,'全唐诗/poet.song.178000.json','["長江百里濃於醅，天風吹作雲濤堆。", "吾鄉好事重佳節，龍舟兩兩爭喧豗。", "今人不識靈均意，祇作龍舟多競渡。", "汨羅舊事付蒼煙，空有遺歌寫哀些。"]'),
('a278f0ad-bed6-4e71-9e65-2225152a3933','四澤曉罾','鄭瀛','宋','宋诗','song-poetry','','[]','澤水迴環六七里，中流擁出一廛市。',64,'全唐诗/poet.song.178000.json','["澤水迴環六七里，中流擁出一廛市。", "桃花吹浪鱖魚肥，紅蓼翻風蟹螯美。", "漁郎業漁相忌猜，欲曉未曉江上來。", "舉罾交錯不知倦，欵乃又入雲濤堆。"]'),
('768c117e-489e-4bc8-b42e-6922251adce0','溪上賞芙蓉','曹絳','宋','宋诗','song-poetry','','[]','嬌紅膩綠暖生春，步繞清溪錦帳新。',32,'全唐诗/poet.song.178000.json','["嬌紅膩綠暖生春，步繞清溪錦帳新。", "花意不須羞白髮，五朝得見太平人。"]'),
('7f6244d8-1671-4fbd-a70b-34b97c7f8f78','題錦浪亭','曹叔遠','宋','宋诗','song-poetry','','[]','瀘江東山山更奇，騎鯨飛仙歸未歸。',32,'全唐诗/poet.song.178000.json','["瀘江東山山更奇，騎鯨飛仙歸未歸。", "桃花千樹爛春晝，莫作韓子荒唐譏。"]'),
('7408a7ba-7137-403e-b45b-940b83bb357c','通玄洞','曹叔遠','宋','宋诗','song-poetry','','[]','遨游倦聽水聲潺，却愛靈巖引憇間。',64,'全唐诗/poet.song.178000.json','["遨游倦聽水聲潺，却愛靈巖引憇間。", "樹擁倒暉穿嶂曲，風牽斜雨灑藤彎。", "半袈裟裏須彌現，隙滹阿中法界寬。", "爲納千僧渾不見，欲於此地扣禪關。"]'),
('a58bcb96-d6e7-49c3-ac39-5bb6f80418fb','劉伶巷','陳煒','宋','宋诗','song-poetry','','[]','有酒宜成頌，知君恥獨醒。',48,'全唐诗/poet.song.178000.json','["有酒宜成頌，知君恥獨醒。", "回車經巷口，荷鍤信丘冥。", "死豈人埋得，言猶婦可聽。", "閉關當日飲，想象只忘形。"]'),
('7180acbf-202d-4d54-ba40-e8251c0ed01e','句  其一','陳與行','宋','宋诗','song-poetry','','[]','椒蘭平酒酌，簠簋散香箕。',12,'全唐诗/poet.song.178000.json','["椒蘭平酒酌，簠簋散香箕。"]'),
('1ebd8038-82dd-4dd4-9773-f2acdf247a6c','句  其二','陳與行','宋','宋诗','song-poetry','','[]','霜間開紫蒂，露下發金英。',12,'全唐诗/poet.song.178000.json','["霜間開紫蒂，露下發金英。"]'),
('57fe652e-7a4c-40e7-9030-d93fdbc18193','題飛雪亭','曾煥','宋','宋诗','song-poetry','','[]','玉虬垂處雪花翻，四序雷聲六月寒。',32,'全唐诗/poet.song.178000.json','["玉虬垂處雪花翻，四序雷聲六月寒。", "憑檻未窮千丈勢，請君巖下舉頭看。"]'),
('3c5a8103-2b68-401e-ba40-6b2794ba9b72','浯溪磨崖','曾煥','宋','宋诗','song-poetry','','[]','元頌顔書山谷詩，還鎸我宋中興碑。',32,'全唐诗/poet.song.178000.json','["元頌顔書山谷詩，還鎸我宋中興碑。", "慇懃三讀重回首，萬□□□江渺瀰。"]'),
('c79432f6-648f-476d-b919-0912e22d13e6','春膏紙','陳槱','宋','宋诗','song-poetry','','[]','膏潤滋松雨，孤高表竹君。',48,'全唐诗/poet.song.178000.json','["膏潤滋松雨，孤高表竹君。", "夜碪寒擣玉，春几瑩鋪雲。", "越地雖呈瑞，吳天乃策勳。", "莫言名晚出，端可大斯文。"]'),
('78e91062-03b7-4b33-a454-471d82869108','題澹山巖','董與幾','宋','宋诗','song-poetry','','[]','厥初誰剖混沌殻，光明僅透天一握。',64,'全唐诗/poet.song.178000.json','["厥初誰剖混沌殻，光明僅透天一握。", "龍門鑿斷工有餘，劖劃巉巖開灑落。", "我來沆碭千崖高，溜雨萬丈聲蕭騷。", "巖上風煙巖下水，晚尋丹竈夜漁舠。"]'),
('00ee7837-b5fa-4f1d-840d-2b1795d3493e','偶題','張伯威','宋','宋诗','song-poetry','','[]','壺中別景絕塵埃，不是山靈閟不開。',32,'全唐诗/poet.song.178000.json','["壺中別景絕塵埃，不是山靈閟不開。", "午夜月華冬夜雪，爲無人向此時來。"]'),
('09d9971f-ea96-4684-86ff-4853e553f51e','句  其一','薛舜俞','宋','宋诗','song-poetry','','[]','丘壑胸中事。',6,'全唐诗/poet.song.178000.json','["丘壑胸中事。"]'),
('21b0e5ed-a794-4b8d-9740-78084c7a6be6','句  其二','薛舜俞','宋','宋诗','song-poetry','','[]','舊邑浮航外。',6,'全唐诗/poet.song.178000.json','["舊邑浮航外。"]'),
('a63cbe61-55e2-468a-a7bf-b94606f67425','句  其三','薛舜俞','宋','宋诗','song-poetry','','[]','軒窗眼界開。',6,'全唐诗/poet.song.178000.json','["軒窗眼界開。"]'),
('29f5e4d1-9a74-4b91-bac8-4a6c9076dcba','嘲韓侂胄','慶元士人','宋','宋诗','song-poetry','','[]','一在廬陵一豫章，文忠文穆兩相望。',32,'全唐诗/poet.song.178000.json','["一在廬陵一豫章，文忠文穆兩相望。", "大家飛上梧桐樹，自有旁人說短長。"]'),
('f9a205dd-8888-421e-b8ff-1bc54537184c','白馬湖','李𡌴','宋','宋诗','song-poetry','','[]','白馬湖光綠染衣，蘭舟溶漾綵鴛飛。',32,'全唐诗/poet.song.178000.json','["白馬湖光綠染衣，蘭舟溶漾綵鴛飛。", "閑愁不到秋風後，聽唱蠻歌月下歸。"]'),
('2bb78739-4b71-42ec-90cb-54f07f6dd5b0','竹齋題事','李𡌴','宋','宋诗','song-poetry','','[]','低齋結空野，小竹移孤林。',120,'全唐诗/poet.song.178000.json','["低齋結空野，小竹移孤林。", "齋閑竹浄好，日媚幽人心。", "南方夏厭暑，獨此留殘陰。", "戞雨挫促夢，穿風搜凉襟。", "長茵展麗蘚，亂歌奏歡禽。", "侍奴裹村服，語客拋塵簪。", "志高成利犇，思爽生詩淫。", "值聖喜盈卷，感古悲入琴。", "山迎穩履遠，月勸澄杯深。", "榮名雖未染，幸亦非煙沉。"]'),
('36071734-cbb6-48e5-a07b-88119b3d1cce','四恩巖','李𡌴','宋','宋诗','song-poetry','','[]','疲筇捫石上，大野俯欄窺。',24,'全唐诗/poet.song.178000.json','["疲筇捫石上，大野俯欄窺。", "洞穴通諸頂，泉流接兩池。"]'),
('6b0fb15c-9cc2-45c1-83ef-a968c980a61b','離巫山晚泊棹石灘下','李𡌴','宋','宋诗','song-poetry','','[]','黄昏風雨阻江濱，翠綰羣峯莫色勻。',32,'全唐诗/poet.song.178000.json','["黄昏風雨阻江濱，翠綰羣峯莫色勻。", "一夜子規啼到曉，孤舟愁殺未歸人。"]'),
('08a1a6ee-4547-45db-92a0-0b9ed3aa4663','上巳從史巫山𥘬飲江臯','李𡌴','宋','宋诗','song-poetry','','[]','風沙一夜卷冥冥，曉色曈曚上翠屏。',64,'全唐诗/poet.song.178000.json','["風沙一夜卷冥冥，曉色曈曚上翠屏。", "薄宦驅人成老大，佳時得酒慰飄零。", "紅餘晚樹迷幽谷，綠漲晴波失遠汀。", "却是崇山兼峻嶺，看來渾不減蘭亭。"]'),
('46a18e3e-0f20-4aef-a675-1c43c1383fc2','句','李𡌴','宋','宋诗','song-poetry','','[]','日射紅鸞扇，風清白獸樽。',12,'全唐诗/poet.song.178000.json','["日射紅鸞扇，風清白獸樽。"]'),
('4038c756-baa4-4c89-8d44-864983a795fb','題龍吟寺','葉秀發','宋','宋诗','song-poetry','','[]','曉色明征轡，疎鐘忽斷林。',48,'全唐诗/poet.song.178000.json','["曉色明征轡，疎鐘忽斷林。", "譚經驚虎伏，說法引龍吟。", "竹影殘鐙暗，苔痕落葉深。", "客懷無處適，欹枕聽霜砧。"]'),
('f03ab94b-2bff-4549-9c46-2242443968d8','廣福寺','葉秀發','宋','宋诗','song-poetry','','[]','細問黄山事，荒唐半不傳。',48,'全唐诗/poet.song.178000.json','["細問黄山事，荒唐半不傳。", "諸峰幾林壑，十日九雲煙。", "笙斷空中籟，丹留澗底泉。", "相招媿猿鶴，何日謝塵緣。"]'),
('aa70e106-1f75-49ab-a1ca-c7b54c25e3b3','登古城山觀','葉秀發','宋','宋诗','song-poetry','','[]','飛觀干霄出，疎松隔塢聞。',48,'全唐诗/poet.song.178000.json','["飛觀干霄出，疎松隔塢聞。", "水聲高下澗，山色去來雲。", "露舄行秋杪，天花落葉分。", "小窗吟不就，清殺病休文。"]'),
('3e41f420-e5b4-4e1f-ae68-2895a4522a4f','黄山喜晴即事','葉秀發','宋','宋诗','song-poetry','','[]','一春鳩婦不停鳴，遠岫雲歸喜得晴。',64,'全唐诗/poet.song.178000.json','["一春鳩婦不停鳴，遠岫雲歸喜得晴。", "水拍秧田釵股細，風吹麥隴浪紋輕。", "天應憐我倦行役，山亦多情互送迎。", "三十六峰如好客，相逢便覺眼增明。"]'),
('3934cbbb-b9fb-4b07-be02-7fe0062ff2d8','興國寺','葉秀發','宋','宋诗','song-poetry','','[]','雖無酒令與詩籌，喜約新盟訪舊遊。',64,'全唐诗/poet.song.178000.json','["雖無酒令與詩籌，喜約新盟訪舊遊。", "寒露正催黄菊晚，斷雲不鎖碧山秋。", "機於空處鷗方下，節到寒時蝶也愁。", "聚散摶沙多少恨，一詩三嘆寄湯休。"]'),
('56383ab1-7fa1-4647-a63b-dfbcf65d93cf','翠微寺','葉秀發','宋','宋诗','song-poetry','','[]','茫茫宇宙幾分離，晚識真人曆數歸。',32,'全唐诗/poet.song.178000.json','["茫茫宇宙幾分離，晚識真人曆數歸。", "五閏都無半抔土，清風千古一麻衣。"]'),
('a0c982df-54ee-43df-8322-a2d96feb6a93','游涪溪','宋之源','宋','宋诗','song-poetry','','[]','不因黨論到元符，安得溪山著一儒。',64,'全唐诗/poet.song.178000.json','["不因黨論到元符，安得溪山著一儒。", "時有詘伸須直道，天開靈傑豈歸愚。", "泉疏陰澗詩餘派，手拓蒼崖節轉孤。", "自送江西仙袂遠，神遊應過此間無。"]'),
('b42f26c4-e6f3-4213-a23d-dc13590b7d1a','石堂歌','元在庵主人','宋','宋诗','song-poetry','','[]','吾斲石堂無變怪，土缶瓦鼓閑遊戲。',376,'全唐诗/poet.song.178000.json','["吾斲石堂無變怪，土缶瓦鼓閑遊戲。", "一钁相隨萬事空，十二時中牢捉繫。", "牢捉繫，不在三閒前後際。", "拍將兩手笑呵呵，這箇消息不容易。", "不容易，拈起石頭拈不住，放下石頭放不去。", "去與住，認取石堂門前路。", "不開窗，不閉戶，塞破世界無覓處。", "煖則乘風凉則眠，烟霞雲外朝還暮。", "朝還暮，不貪榮，不貪富，不戀妻帑及兒女。", "隨緣自在度時光，看著古今都錯誤。", "皇天后土莫相瞞，翻來覆去能幾許。", "前賢後聖說多般，千經萬論從頭注。", "渠不省，渠不悟，一任從渠失故步。", "我自知，我自顧，富貴渾如草頭露。", "人與我，愛與妬，對境不生無喜怒。", "清涼世界乃吾臺，是非海裏終不覷。", "不向君王殿上行，不入豪家問尊貴。", "紅妝豔粉任安排，誇逞從他鬭能會。", "英雄强弱只一般，嘍囉巧拙說甚彩。", "少年才子漫風流，絕代佳人臭囊袋。", "一息不來何所尋，萬兩黄金不容带。", "都是空，必竟敗。", "唇鏘舌劍遞相欺，縱使金印如斗大。", "儘數收拾滿倉箱，不知前面能幾歲。"]'),
('bcee3ab3-02e4-42ac-935a-ea2479cd5199','詠海棠','于倞','宋','宋诗','song-poetry','','[]','和風春滿園，草木皆芳薰。',24,'全唐诗/poet.song.178000.json','["和風春滿園，草木皆芳薰。", "君看十八葉，肯與凡卉羣。"]'),
('0b8d0ae9-6c8a-4c46-a73a-ec177d2651da','投楊帥長孺','黄子信','宋','宋诗','song-poetry','','[]','六年兩度拜宸旒，換得青衫白上頭。',64,'全唐诗/poet.song.178000.json','["六年兩度拜宸旒，換得青衫白上頭。", "飛鵲祇因無樹繞，窮猿何暇擇林投。", "明知著脚當來誤，幾欲抽身不自由。", "安得有錢了官債，便無三徑也歸休。"]'),
('85baef69-60c6-4f8f-b5ef-8b2e4cdd3c71','歸時作','黄子信','宋','宋诗','song-poetry','','[]','笑倩西風拂舊埃，歸時行李似初來。',32,'全唐诗/poet.song.178000.json','["笑倩西風拂舊埃，歸時行李似初來。", "也知三載清貧好，博得一家强健回。"]'),
('d502e8f9-05b2-400a-af7a-913d4fe38e16','句','葉祐之','宋','宋诗','song-poetry','','[]','木葉臨風皆好色，稻田流水亦新聲。',16,'全唐诗/poet.song.178000.json','["木葉臨風皆好色，稻田流水亦新聲。"]'),
('6615df7b-36f1-46cb-bbb1-d8c22cfe17e7','三里塘掐梅','葉樾','宋','宋诗','song-poetry','','[]','扶疎不耐繁華，意足自然清絕。',28,'全唐诗/poet.song.178000.json','["扶疎不耐繁華，意足自然清絕。", "壁間幻出橫斜，祇欠紗窗明月。"]'),
('9cdc6b0f-83b3-440d-add3-62348dd7f20e','送太守傅尚書易鎮當塗二十韻','徐璣','宋','宋诗','song-poetry','','[]','帝業江淮表，丕承七十年。',240,'全唐诗/poet.song.178000.json','["帝業江淮表，丕承七十年。", "太平南北共，內禪子孫傳。", "弓矢深櫜橐，桑麻鬰壠阡。", "江河春混混，雨露夜涓涓。", "治久情多縱，才卑氣或偏。", "穹蒼宜予弼，淵默正思賢。", "四世忠勳積，三朝節概全。", "威儀新禹服，光彩舊星躔。", "本以文爲治，尤知政有權。", "粟紅初穰穰，榆散亦翩翩。", "國似傳東魯，名能躐潁川。", "殊恩方錫馬，盛美又臨軒。", "易鎮旌旗遠，趨朝劍履便。", "想知環去旆，咸似渴思泉。", "典誥黄麻出，衣冠紫禁聯。", "安危看去就，扶掖頼精專。", "江岸梅花小，山城桂影圓。", "歌思惟兩地，動化及無邊。", "相復中興舊，書重說命篇。", "元勳列青史，焜燿祖宗前。"]'),
('20dc28d5-e195-4faf-88cd-7a61f598a57a','上葉侍郎十二韻','徐璣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','侍從西湖宅，安閑近水心。',144,'全唐诗/poet.song.178000.json','["侍從西湖宅，安閑近水心。", "門開春郭靜，橋度野池深。", "山翠連龍起，雲樓學虎臨。", "芙蓉通遠渚，槐柳步回陰。", "盛業歸宗匠，斯文並古今。", "典謨存大雅，金石振餘音。", "疇昔留藩管，江淮擁带襟。", "雍容平宇宙，瀟洒在園林。", "玉富淵難測，仙癯鶴可尋。", "步趨垂雜組，言笑響鳴琴。", "補衮心無替，彈冠迹未沉。", "于今幽興極，正可辨清吟。"]'),
('b139246e-8f96-463f-ae06-71f1065e7e62','送蔡侍郎鎮建寧','徐璣','宋','宋诗','song-poetry','','[]','熙洽壬辰際，剛明十載初。',120,'全唐诗/poet.song.178000.json','["熙洽壬辰際，剛明十載初。", "祥風開宇宙，粹質産瓊琚。", "年齒終童右，文章兩漢餘。", "體將時格變，名向榜頭書。", "多病侵絲鬢，清顔侍玉除。", "溫恭扶國是，端直屏姦渠。", "良月春先暖，豐年日自舒。", "潜藩來騎鼎，故里去程徐。", "北虜盟方締，蠻陬孽已鋤。", "願言歸補衮，敷澤徧坤輿。"]'),
('cce8887f-5a7a-4316-8bd5-97f39f6f862e','漳州送王益統制謫歸時方收峒寇','徐璣','宋','宋诗','song-poetry','','[]','京口丘都督，江淮第一人。',120,'全唐诗/poet.song.178000.json','["京口丘都督，江淮第一人。", "竭心安宋代，决策斬蘇嚚。", "猛將親經選，高材近莫倫。", "六鈞來有力，一騎去無塵。", "塞靜良弓隠，時明枉事伸。", "遷車行地遠，歸詔及春新。", "恃險猺奴蠢，招亡鼠技貧。", "衆情懽殺賊，國本在安民。", "功過今方使，忠誠正可陳。", "能言學李固，茲日願亡身。"]'),
('84c75f3f-1073-45be-a984-6da528151dec','送張尚書出鎮建寧','徐璣','宋','宋诗','song-poetry','','[]','焚罷南坡藁，星華接履聲。',168,'全唐诗/poet.song.178000.json','["焚罷南坡藁，星華接履聲。", "艱時曾倚重，鉤黨頼持平。", "仲甫思全衮，元戎正本兵。", "丰儀麟閣貴，威重犬戎驚。", "聖主憂遐遠，朝端擇老成。", "邇臣宣惠化，七嶺動懽情。", "風俗移刀劍，田閭遂鑿耕。", "試茶龍井碧，開硯鳳潭清。", "秋日江沙渺，晴天鼓角鳴。", "稻香隨使驛，桂影伴仙程。", "美玉非藏韞，黄金笑滿籝。", "寬和無白髮，卑遜有高名。", "登用唐三世，樞機漢九卿。", "鼎司虛正席，丹扆待忠誠。"]'),
('eb65a91e-93cc-4788-a268-b07a8e5567aa','傳胡報二十韻','徐璣','宋','宋诗','song-poetry','','[]','胡虜無仁義，興衰匪百年。',240,'全唐诗/poet.song.178000.json','["胡虜無仁義，興衰匪百年。", "如何憑氣力，久欲靖中邊。", "異類依天角，黄頭住海𤲬。", "愚堪呼鹿豕，健每學鷹鸇。", "猰狄時方憊，燕雲耗頗傳。", "姦臣貪拓境，黠計落空拳。", "氈毳分伊水，旌旗濕汴川。", "鶑花春自老，風雨夜相連。", "文物東南盛，舟車蜀廣聯。", "規模垂翼翼，鼎石頼乾乾。", "五福祥光近，千齡厚澤綿。", "雨晴均化日，豐穰慶秋田。", "禽獸聞相噬，干戈鬭欲纏。", "瓜分爭塊壤，鼎沸逐埃涓。", "亡北惟堪伺，良圖盍自堅。", "藩籬兼謹守，閫外勿輕捐。", "晉趙非殊異，山河本渾全。", "人心方激切，天道有回旋。", "王佐存諸葛，中興仰孝宣。", "何當渭橋下，拱揖看駢闐。"]'),
('d37f5b89-806f-4ec3-815d-c9af6ec0f03a','哭朱嚴伯','徐璣','宋','宋诗','song-poetry','','[]','脩麓長髯客，風儀野老邊。',144,'全唐诗/poet.song.178000.json','["脩麓長髯客，風儀野老邊。", "夕陽烏袖薄，細雨葛巾偏。", "握手相從日，寒雲未雪天。", "釅醅篘不盡，鮓醢罄無捐。", "共舸浮江北，聯吟就幾篇。", "梅花知老矣，流水尚依然。", "倚杖臨臯別，東風白髮前。", "官途三載遠，世事古人先。", "疋布心曾許，交情後莫傳。", "蕭蕭瓜井暮，瑟瑟故廬烟。", "衰病身如木，懷思淚欲泉。", "磨詩終未穩，空向月嬋娟。"]'),
('876741d9-badd-4d42-afa3-6604467a6c50','述夢寄趙紫芝','徐璣','宋','宋诗','song-poetry','','[]','江水何滔滔，渡江相別離。',108,'全唐诗/poet.song.178000.json','["江水何滔滔，渡江相別離。", "揖子客舍前，對子衣披披。", "問子何所爲，旅客未得歸。", "執手一悲喚，驚覺妻與兒。", "起坐不得省，清風在簾帷。", "平明出南門，將以語所知。", "過子舊家處，寒花出疎籬。", "蕭蕭黄葉多，裊裊歸步遲。", "子去不早還，何以慰我思。"]'),
('88d1ed30-a952-45fd-bfb6-8669311e790c','漳州別王仲言祕書','徐璣','宋','宋诗','song-poetry','','[]','百草各有種，春至不栽培。',132,'全唐诗/poet.song.178000.json','["百草各有種，春至不栽培。", "交情重故知，豈論才不才。", "相識十年初，再見天之涯。", "共飲一盃酒，粲若紅顔開。", "人生有此樂，知復能幾回。", "契闊幾已深，矧爾病與衰。", "朔風從何來，吹白枝上梅。", "天寒日欲莫，又乃行色催。", "君去江水西，我歸近天台。", "東西道路長，未可心膂摧。", "明朝碧雲多，佇思良徘徊。"]'),
('fb7d920d-1fdb-4d8e-9e08-8ebb4206f05a','記述二十韻爲趙沂公作','徐璣','宋','宋诗','song-poetry','','[]','日月交輝際，乾坤欲整時。',240,'全唐诗/poet.song.178000.json','["日月交輝際，乾坤欲整時。", "謀謨無遠近，顧盼有安危。", "國倚宗臣重，人惟正統推。", "將軍兼問古，中尉不言私。", "美德開初禩，清風起四維。", "山河春藹藹，雨露夜垂垂。", "川浩黿鼉穴，田豐鼠兔窺。", "險辭萋莫已，深網障無遺。", "流謗看金策，純誠表竹枝。", "丹心元未改，隻影去奚疑。", "能勝歸天道，云亡忽事宜。", "蜀關幾犬豕，淮岸邇旌旗。", "將相通新好，朝廷說舊規。", "渠奸甘授首，盛代鞏丕基。", "褒敘還宗祏，光昭在鼎彝。", "凄凉餘謚法，慷慨付諸兒。", "汨水芬芳地，三閭絕好詞。", "子蘭真已矣，靳尚亦奚爲。", "樂事云悲事，新知匪故知。", "續騷何日了，千古泪如絲。"]'),
('8d9669b5-cd23-4dcf-b8e0-c8fa8681491d','監造御茶有所爭執','徐璣','宋','宋诗','song-poetry','','[]','森森壑源山，嫋嫋壑源溪。',291,'全唐诗/poet.song.178000.json','["森森壑源山，嫋嫋壑源溪。", "脩脩桐樹林，下蔭茶樹低。", "桐風日夜吟，桐雨洒霏霏。", "千叢高下青，一叢千萬枝。", "龍在水底吟，鳳在山上飛。", "異物呈嘉祥，上奉玉食資。", "臘餘春未新，素質藴芳菲。", "千夫{口砉}登壠，叫嘯風雷隨。", "雪芽細若針，一夕吐清奇。", "天地發寶祕，鬼神不敢知。", "舊制遵御膳，授職各有司。", "分綱製品目，簿尉監視之。", "雖有領督官，焉得專所爲。", "初綱七七夸，次綱數弗差。", "一以薦郊廟，二以瀹賓夷。", "天子且謙受，他人奚可希。", "柰何貪瀆者，憑陵肆姦欺。", "品嘗珍妙餘，倍稱求其私。", "初非狐鼠媚，忽變狼虎威。", "巧計百不行，叱怒面欲緋。", "再拜長官前，茲事非所宜。", "性命若螻蟻，蠢動識尊卑。", "朝廷設百官，責任無細微。", "所守儻在是，恪謹焉可違。"]'),
('c9a19058-d9e2-4f9f-984a-ba5c63a2eb8a','奉和翁千四知縣千十四隠居山中作','徐璣','宋','宋诗','song-poetry','','[]','翁侯兩兄弟，志尚等高獨。',240,'全唐诗/poet.song.178000.json','["翁侯兩兄弟，志尚等高獨。", "閑心沒江鷗，逸興狎山鹿。", "難兄早登第，高風動喬木。", "湘南花滿汀，百里正膏沐。", "歸作山水游，詞源傾百斛。", "令弟小謝徒，深沉鬰林麓。", "優游千卷書，平生幾竿竹。", "能琴絃不理，少飲巾未漉。", "兄倡復弟酬，音調諧擊筑。", "晝卧小窗南，煩暑在荷屋。", "凉風從何來，池花動輕䔩。", "顧□傳新章，爽氣滌炎伏。", "如臨古澗旁，泓澄碧環復。", "如倚青林下，松風對心讀。", "善詩如善韻，警響間圓熟。", "但令契人心，勿令駭人目。", "我愛二君子，芳馨襲蘭菊。", "迎秋月色新，佳香滿晴宿。", "安得扁舟去，□□蔭溪谷。", "論詩暮繼朝，吟思俱毣毣。"]'),
('73806ce8-2290-4aaf-951f-ea12bf4aae5a','登三層樓與王仲言聯句','徐璣','宋','宋诗','song-poetry','','[]','南州冬日佳，風和霜氣收。',288,'全唐诗/poet.song.178000.json','["南州冬日佳，風和霜氣收。", "出門訪良友，散策尋清游。", "負郭有野趣，荒草带寒流。", "信步任所止，款扉得深幽。", "初若隠者居，忽上雲中樓。", "攬以三層顛，恍與萬象浮。", "綠野寬作圍，青山遠相蟉。", "凌然欲輕舉，久乃思冥搜。", "團團荔枝林，往往叢葉稠。", "時於陰木間，略見碧瓦溝。", "蒼然晚烟集，紅者楓樹頭。", "竚立思轉賒，顧盼目不周。", "何意城中身，而對海上州。", "要須千幅盡，未可一語酬。", "時已梅萼春，景邁浙水秋。", "遠地得心賞，良會非宿籌。", "黄柑况可餐，綠酒方出篘。", "十年真契闊，再見方綢繆。", "矧茲天一方，無異水上漚。", "把盞不知暮，論文殊未休。", "俄驚庭葉落，始覺昏鴉投。", "獨憐下弦月，未掛初旬鈎。", "絕景尚可揖，歸途諒匪脩。", "何當鴈蕩間，相與老一丘。"]'),
('353de776-369c-4660-986f-824fdfdf15b4','水仙花篇','徐璣','宋','宋诗','song-poetry','','[]','成陣風作車，宓妃波爲茵。',168,'全唐诗/poet.song.178000.json','["成陣風作車，宓妃波爲茵。", "良夕忽會遇，明月寒鋪銀。", "環珮凌秋空，笙簫亦具陳。", "何以慰寥廓，樂此相知新。", "採珠拾翠羽，言笑生華春。", "贈以金琅玕，捧以白玉人。", "酌醴動芳氣，妙與蘭茝紉。", "歡娛有聚散，美寶無賤珍。", "至今寒花種，清徹瑩心神。", "霜皚衆枿藁，孤媚良舒伸。", "杜鵑望帝魂，啼血何嚚嚚。", "妃子眠海棠，荒湎焉足鄰。", "姮女手栽桂，光彩相依因。", "故知蓬瀛姿，不染纖點塵。"]'),
('a805ddab-1599-4993-9ba5-d2d53eeadab7','婁家梅篇','徐璣','宋','宋诗','song-poetry','','[]','婁家屋西梅，梅老枝更清。',108,'全唐诗/poet.song.178000.json','["婁家屋西梅，梅老枝更清。", "衆樹吐齊白，密萼含微清。", "下有碧池波，照此鷗鷺翎。", "寒雲拂縞衣，遥空淡明星。", "薄言種樹時，兩世且百齡。", "樹亦匪難老，一歲一彫零。", "我嗟人事遷，且愛樹伶俜。", "回桓不能去，月來孤影生。", "倚樹一長吟，寫我寥曠情。"]'),
('3c2b1d80-b1c1-4a3a-8cbf-99bc11120e53','松風樓篇','徐璣','宋','宋诗','song-poetry','','[]','松聲欲動風聲催，細非笙簧大非雷。',64,'全唐诗/poet.song.178000.json','["松聲欲動風聲催，細非笙簧大非雷。", "松間便使無風起，亦有爽氣如風來。", "傍松作樓古爲務，小著軒楹省斤鋸。", "樓低要與綠陰平，勿令高過松梢去。"]'),
('f574d7a5-c98d-4cae-8d98-613eec08764a','訪梅','徐璣','宋','宋诗','song-poetry','','[]','訪梅行近郊，寒氣初淅瀝。',60,'全唐诗/poet.song.178000.json','["訪梅行近郊，寒氣初淅瀝。", "欲開未開時，三點兩點白。", "清枝何蕭疎，幽香况岑寂。", "頗知天姿殊，絕似人有德。", "逢君天一方，歡然舊相識。"]'),
('1e2cb793-bdf4-405b-ab73-bee4bb3b959d','題林氏學海樓','徐璣','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江欲趨海，日夜不肯休。',84,'全唐诗/poet.song.178000.json','["長江欲趨海，日夜不肯休。", "終然至海後，大小同一流。", "君家學海名，舊有江上樓。", "取義誠在斯，終始志欲侔。", "雲門接滄波，碧玉浩遠浮。", "一瞬便可得，垂則良易求。", "茲道無小成，勉矣歸藏脩。"]'),
('d1d5e3b9-127a-42d9-9e81-b5460f58b620','九月初四日分韻得然字','徐璣','宋','宋诗','song-poetry','','[]','去載羈旅身，千里望群賢。',84,'全唐诗/poet.song.178000.json','["去載羈旅身，千里望群賢。", "今夕良燕會，况乃佳節前。", "凉風日已多，歲序日已遷。", "春時種藂菊，秋花滿籬邊。", "採之不盈把，泛彼清清泉。", "行樂不易得，貧賤焉可捐。", "惟當從爾游，吟哦思陶然。"]'),
('36de8fe6-aff3-48d8-a3bd-7768aeecc87e','寄上泉州許參政福州薛端明謫居','徐璣','宋','宋诗','song-poetry','','[]','性懶修書苦，題詩寄海濱。',72,'全唐诗/poet.song.178000.json','["性懶修書苦，題詩寄海濱。", "閩中今樂地，遷客舊名臣。", "乍嚼檳榔澀，初餐荔顆珍。", "園林春易老，鄉岸雨難勻。", "世慮千峯靜，時賢一聘新。", "閑居尋釣石，朝晚待歸人。"]'),
('62d5ea07-0c21-4029-8791-f417b3b7d4a9','送趙狀元赴湖州幕','徐璣','宋','宋诗','song-poetry','','[]','玉陛傳臚曉，身居第一功。',96,'全唐诗/poet.song.178000.json','["玉陛傳臚曉，身居第一功。", "絕班知禮異，專局信儒崇。", "賢俊科名上，邦家事業中。", "規模垂廣遠，鼎鼐蓄含洪。", "更化方今務，經時志已通。", "蒞人惟簡直，修己在謙沖。", "日旦清風發，江晴野霧空。", "奉親游宦喜，初向水晶宮。"]'),
('248334fe-7f2f-4899-8dc5-b3693cbb29bb','送錢省元赴太平州教授','徐璣','宋','宋诗','song-poetry','','[]','王國重熙洽，邦基百世安。',96,'全唐诗/poet.song.178000.json','["王國重熙洽，邦基百世安。", "深源混清濁，直道闡平寬。", "學術知同貴，師儒頗異觀。", "脩名褎蘭省，舊格到蟬冠。", "十載田廬隠，三年客授官。", "括溪方水漲，江左尚春寒。", "論議何時一，行藏此日難。", "宿酲江柳綠，風物强加餐。"]'),
('0261a255-ea47-439a-8ac4-daa0e7923dac','初夏遊謝公巖','徐璣','宋','宋诗','song-poetry','','[]','又取紗衣換，天晴起細風。',48,'全唐诗/poet.song.178000.json','["又取紗衣換，天晴起細風。", "清陰花落後，長日鳥啼中。", "水國乘舟樂，巖扉有路通。", "州民多到此，猶自憶髯公。"]'),
('8e958168-2fd8-4b04-b70c-dbca94a100b4','湘中','徐璣','宋','宋诗','song-poetry','','[]','舊說湘中事，身來又可尋。',48,'全唐诗/poet.song.178000.json','["舊說湘中事，身來又可尋。", "廟存虞帝迹，江照楚臣心。", "爲客人俱遠，題名刻自深。", "春迴洲渚綠，遥望正沉吟。"]'),
('a98cf1db-da38-4d1b-a94d-7b4f0003b38a','泊舟呈靈暉','徐璣','宋','宋诗','song-poetry','','[]','泊舟風又起，繫纜野桐林。',48,'全唐诗/poet.song.178000.json','["泊舟風又起，繫纜野桐林。", "月在楚天碧，春來湘水深。", "官貧思近闕，地遠動愁心。", "所喜同舟者，清羸亦好吟。"]'),
('94e887cc-8841-4adf-8977-2eb345617c47','古郡','徐璣','宋','宋诗','song-poetry','','[]','古郡依蠻楚，身來作冷官。',48,'全唐诗/poet.song.178000.json','["古郡依蠻楚，身來作冷官。", "老憐兄弟遠，貧喜婦兒安。", "分菊乘春雨，移梅待歲寒。", "又傳家信至，入夜著燈看。"]'),
('ca31efce-a9ea-4f89-8cbc-5c7374c7128d','送徐照先回江西','徐璣','宋','宋诗','song-poetry','','[]','骨體先如鶴，離家歲已周。',48,'全唐诗/poet.song.178000.json','["骨體先如鶴，離家歲已周。", "欲知詩思遠，曾共楚鄉游。", "窮達身將老，分携菊正秋。", "江西看舊友，歸計少遲留。"]'),
('8a2b7e29-f30f-45f2-a1e1-b05d4487d161','憑高','徐璣','宋','宋诗','song-poetry','','[]','憑高散幽策，綠草滿春坡。',48,'全唐诗/poet.song.178000.json','["憑高散幽策，綠草滿春坡。", "楚野無林木，湘山似水波。", "客懷隨地改，詩思出門多。", "尚有溪西寺，斜陽未得過。"]'),
('0a3673b7-9c48-492d-8a3c-f53ea6f87e8b','喜雨','徐璣','宋','宋诗','song-poetry','','[]','自入春來旱，祈求到夏中。',48,'全唐诗/poet.song.178000.json','["自入春來旱，祈求到夏中。", "數朝人盡恐，今夜雨須通。", "雲氣昏猶散，雷聲隠漸隆。", "池魚先得活，歡喜與予同。"]'),
('17faae41-4629-4e47-aea7-759555ac976a','謝劉明遠華亭惠書','徐璣','宋','宋诗','song-poetry','','[]','別遠心常記，書歸亦到吾。',48,'全唐诗/poet.song.178000.json','["別遠心常記，書歸亦到吾。", "離家非失計，有子已爲儒。", "海淺編魚扈，人清養鶴雛。", "禮優賓館暇，賦詠幾歡娛。"]'),
('f4de94f8-8c5a-46d0-989b-fca13e4ec3d4','不食姑','徐璣','宋','宋诗','song-poetry','','[]','惟誦天童咒，飲泉能不饑。',48,'全唐诗/poet.song.178000.json','["惟誦天童咒，飲泉能不饑。", "只緣多自譽，翻以致人疑。", "賦質全如鶴，謀生却似龜。", "綠華通籍後，會報女仙知。"]'),
('6fa618e9-9de1-4d4c-a3c9-6e71e440a435','贈李丹士','徐璣','宋','宋诗','song-poetry','','[]','曾學輕騰術，長懷萬里心。',48,'全唐诗/poet.song.178000.json','["曾學輕騰術，長懷萬里心。", "江湖雲似水，巴廣石如林。", "好飲身常樂，無言道更深。", "丹砂能愈疾，不用化黄金。"]'),
('9b797efc-062a-4514-994b-c27ca09a6f18','題薛景石瓜廬','徐璣','宋','宋诗','song-poetry','','[]','近舍新爲圃，澆鋤及晚凉。',48,'全唐诗/poet.song.178000.json','["近舍新爲圃，澆鋤及晚凉。", "因看瓜蔓吐，識得道心長。", "隔沼嘉蔬潔，侵畦異草香。", "小舟應買在，門外是漁鄉。"]'),
('f73591bc-f043-4a42-a3a7-caa5eb6790ac','檄途寄翁靈舒','徐璣','宋','宋诗','song-poetry','','[]','聞道長溪令，相留一館閑。',48,'全唐诗/poet.song.178000.json','["聞道長溪令，相留一館閑。", "便令全近舍，尚隔幾重山。", "爲旅春郊外，懷人夜雨間。", "年來疎覽鏡，怕見減朱顔。"]'),
('365f3d2e-7de0-4cc5-804f-4fced117edda','贈薌林後人','徐璣','宋','宋诗','song-poetry','','[]','南北門相對，傳來歲月深。',48,'全唐诗/poet.song.178000.json','["南北門相對，傳來歲月深。", "但添新意趣，不改舊園林。", "花日移朝坐，松風伴夕吟。", "自然忘宦達，非是少知音。"]'),
('1e8666c8-d4c1-4a2d-8611-9797e14fb073','投周益公','徐璣','宋','宋诗','song-poetry','','[]','辭相還家後，清癯带少顔。',48,'全唐诗/poet.song.178000.json','["辭相還家後，清癯带少顔。", "便令凡事足，不似一身閑。", "長日惟開卷，晴天偶看山。", "只應憂國念，到此或相關。"]'),
('b4feef7e-59b6-40f9-9e0d-0ba5e55f43a2','見楊誠齋','徐璣','宋','宋诗','song-poetry','','[]','名高身又貴，自住小村深。',48,'全唐诗/poet.song.178000.json','["名高身又貴，自住小村深。", "清得門如水，貧惟带有金。", "養生非藥鉺，常語盡規箴。", "四海爲儒者，相逢問信音。"]'),
('05c7e511-cdc7-45e1-b9b1-612bd47fd055','登橫碧軒繼趙昌甫作','徐璣','宋','宋诗','song-poetry','','[]','步陟高高寺，徐行不用扶。',48,'全唐诗/poet.song.178000.json','["步陟高高寺，徐行不用扶。", "青天晴又雨，山色有還無。", "句向閑中覓，茶因醉後呼。", "所懷論未足，何乃又征途。"]'),
('86543159-c5b0-4566-8d0d-de637fe58d85','題李商叟半村堂','徐璣','宋','宋诗','song-poetry','','[]','住屋半依村，先生氣貌尊。',48,'全唐诗/poet.song.178000.json','["住屋半依村，先生氣貌尊。", "若非迎好客，長是掩柴門。", "覓句行山影，披蓑釣月痕。", "固貧年八十，惟得令名存。"]'),
('0ff8fbdf-3ab8-48c2-968d-5fcaa3e524ee','十日','徐璣','宋','宋诗','song-poetry','','[]','十日清溪路，新春細雨天。',48,'全唐诗/poet.song.178000.json','["十日清溪路，新春細雨天。", "綠波隨棹起，白鳥望舟眠。", "麥秀初如草，雲濃半是煙。", "明朝可遵陸，還憶此江邊。"]'),
('3d8418cd-6183-4cd5-8081-5f1f128c5a44','嶽麓書院','徐璣','宋','宋诗','song-poetry','','["\u8861\u5c71"]','屋舍如庠序，讀書兼教文。',48,'全唐诗/poet.song.178000.json','["屋舍如庠序，讀書兼教文。", "來茲望南嶽，青似一重雲。", "步遶叢山小，城看隔水分。", "欲知巡狩事，野老間能云。"]'),
('e8948524-94de-44ea-9c5b-a0bda88d7dab','夏日','徐璣','宋','宋诗','song-poetry','','[]','書困當檐立，微風動鬢毛。',48,'全唐诗/poet.song.178000.json','["書困當檐立，微風動鬢毛。", "桐陰遮井暗，鶑語出林高。", "執熱思時雨，如疲得美醪。", "居然吟思起，獨步幾周遭。"]'),
('9afa2e93-de76-40ee-b757-6727aaae3f1a','雨中','徐璣','宋','宋诗','song-poetry','','[]','雨來連幾夕，滿漲一湖波。',48,'全唐诗/poet.song.178000.json','["雨來連幾夕，滿漲一湖波。", "苦似前時少，毋嫌此日多。", "砌荒蝸出舍，屋漏燕移窠。", "今歲翻成稔，田塍亦産禾。"]'),
('65a8e4ee-de1b-4ba6-9885-bf69468399fd','自覺','徐璣','宋','宋诗','song-poetry','','[]','自覺中年後，惟能半夕眠。',48,'全唐诗/poet.song.178000.json','["自覺中年後，惟能半夕眠。", "寒窗微带月，山郡遠聞泉。", "行樂人同尚，遲留我未然。", "題書寄朋舊，歸日是春邊。"]'),
('6ee79484-d071-4871-b32b-1bf0361e9133','別趙汝鬯黄中','徐璣','宋','宋诗','song-poetry','','[]','古道難爲友，相期一見中。',48,'全唐诗/poet.song.178000.json','["古道難爲友，相期一見中。", "但令心事合，不在語言同。", "秋早湘煙白，舟移岸蓼紅。", "別懷如迥野，長與水雲通。"]'),
('b6879540-87b1-4c66-b46f-f58b133580cf','次韻劉明遠移家  其一','徐璣','宋','宋诗','song-poetry','','[]','隠居須是僻，君向數家村。',48,'全唐诗/poet.song.178000.json','["隠居須是僻，君向數家村。", "自以閑爲樂，何嫌貧尚存。", "碧波連草舍，白日掩柴門。", "挂得一瓢在，風來應惡喧。"]'),
('de7658a4-2a8f-448f-96ab-b7fc7b2c117a','次韻劉明遠移家  其二','徐璣','宋','宋诗','song-poetry','','[]','恬淡安身易，新家似舊居。',48,'全唐诗/poet.song.178000.json','["恬淡安身易，新家似舊居。", "徑凉行落葉，池浄數游魚。", "詩得唐人句，碑臨晉代書。", "半生惟此樂，同輩必無如。"]'),
('8c0b18e0-5630-49e3-97c2-5c24c62c2a84','次韻劉明遠移家  其三','徐璣','宋','宋诗','song-poetry','','[]','躬耕儒者事，甘苦自能便。',48,'全唐诗/poet.song.178000.json','["躬耕儒者事，甘苦自能便。", "叩角吟山際，休鋤坐竹邊。", "長年多涉歷，豐歲少憂煎。", "一一舊所好，知君能棄捐。"]'),
('a32cf82b-c9c4-4bb6-9100-f2a525df7ddc','送單丙文先生歸沅州','徐璣','宋','宋诗','song-poetry','','[]','傳得臨池訣，勤勞敢遽忘。',48,'全唐诗/poet.song.178000.json','["傳得臨池訣，勤勞敢遽忘。", "錐沙惟是正，舞劍本非狂。", "舊隠尋芳芷，離懷對碧湘。", "寸心長記面，不似隔他鄉。"]'),
('06e242fe-3c79-4972-ab37-c4555a15fd67','夏夜同靈暉有作奉寄翁趙二友','徐璣','宋','宋诗','song-poetry','','[]','齋居惟少睡，露坐得論文。',48,'全唐诗/poet.song.178000.json','["齋居惟少睡，露坐得論文。", "凉夜如清水，明河似白雲。", "宿禽翻樹覺，幽磬度溪聞。", "欲識他鄉思，斯時共憶君。"]'),
('db153740-25ad-41f9-9bfb-fca56a5a6a00','送翁靈舒遊邊','徐璣','宋','宋诗','song-poetry','','[]','子向江淮去，應懷計策新。',48,'全唐诗/poet.song.178000.json','["子向江淮去，應懷計策新。", "但須先審己，然後可圖人。", "戰野寒猶力，邊城草不春。", "曹劉若無競，閑却卧龍身。"]'),
('130af394-2851-4be1-8baa-0e2641074f06','潘德久挽詞','徐璣','宋','宋诗','song-poetry','','[]','祇爲吟成癖，官閑樂有餘。',48,'全唐诗/poet.song.178000.json','["祇爲吟成癖，官閑樂有餘。", "病惟親筆墨，貧亦買琴書。", "別奠臨西野，春風入故廬。", "悠悠想精魄，如賦釣臺初。"]'),
('c471a401-fd7d-4e70-a93c-0647e073bf13','翁通判挽詞  其一','徐璣','宋','宋诗','song-poetry','','[]','處己先能儉，爲官易得清。',48,'全唐诗/poet.song.178000.json','["處己先能儉，爲官易得清。", "長卿詩最好，叔度德難名。", "歸旐郴江遠，新墳秀嶺平。", "松楸本相望，惆悵不堪情。"]'),
('5aa46d2d-c1a8-400d-9378-bf3f872545ab','翁通判挽詞  其二','徐璣','宋','宋诗','song-poetry','','[]','昔年樓上飲，分韻正秋深。',48,'全唐诗/poet.song.178000.json','["昔年樓上飲，分韻正秋深。", "冷貌長如在，高風不可尋。", "獨遺楊子厚，誰寄惠連音。", "莫向山廬宿，松聲似夜吟。"]'),
('11b9cc60-d9c7-47d9-9a81-6522235f8684','梅夫人挽詞','徐璣','宋','宋诗','song-poetry','','[]','執饋供湯藥，辛勤四十年。',48,'全唐诗/poet.song.178000.json','["執饋供湯藥，辛勤四十年。", "誰知飛蝶夢，翻落鼓盆先。", "丹旐秋城外，寒雲野寺邊。", "送車來闔境，陶侃信能賢。"]'),
('e5f76b76-21c4-4ce5-a7cc-7ae3783c8af5','懷素臺','徐璣','宋','宋诗','song-poetry','','[]','不識張顛面，畫成釵股艱。',48,'全唐诗/poet.song.178000.json','["不識張顛面，畫成釵股艱。", "長存昔年宅，猶塑醉時顔。", "筆與身同葬，池荒墨似斑。", "才清人必重，瀟岸野雲間。"]'),
('55c3e083-932d-4172-a21d-c4ac8948c774','江亭臨眺','徐璣','宋','宋诗','song-poetry','','[]','問得梅花信，寒林動晚聲。',48,'全唐诗/poet.song.178000.json','["問得梅花信，寒林動晚聲。", "雨來山漸遠，潮去水還清。", "寥落尋新句，懽娛解宿酲。", "相携歸路滑，燈火近孤城。"]'),
('6be5d0ee-336a-48a2-8b84-660f904ed88d','春日晚望','徐璣','宋','宋诗','song-poetry','','[]','樓上看春晚，煙分遠近村。',48,'全唐诗/poet.song.178000.json','["樓上看春晚，煙分遠近村。", "曉晴千樹綠，新雨半池渾。", "柳密鶑無影，泥新燕有痕。", "輕寒衫袖薄，杯酌更須溫。"]'),
('9cf87532-372e-4cbd-9bb3-0b24943cca08','同友人乘舟','徐璣','宋','宋诗','song-poetry','','[]','澤國自秋凉，乘舟入渺茫。',48,'全唐诗/poet.song.178000.json','["澤國自秋凉，乘舟入渺茫。", "荷披沙渚碧，花亂暑風香。", "山色含疎雨，蟬聲带夕陽。", "不知歸路杳，相對有篇章。"]'),
('daee058d-3e0c-4023-b5bd-8ba888212b77','送徐照還舊山  其一','徐璣','宋','宋诗','song-poetry','','[]','城闉多汩沒，宜爾向村居。',48,'全唐诗/poet.song.178000.json','["城闉多汩沒，宜爾向村居。", "蔬茹餐僧飯，香茶讀古書。", "秋潮侵岸滿，曉月带星疎。", "相送未相憶，相期同荷鋤。"]'),
('49e67c89-baf5-4825-bdfb-8ecc0a60151b','送徐照還舊山  其二','徐璣','宋','宋诗','song-poetry','','[]','役役勞形器，乾坤一轉蓬。',48,'全唐诗/poet.song.178000.json','["役役勞形器，乾坤一轉蓬。", "暗因凡慮汩，明爲此心空。", "小舍依沙渚，扁舟繫荻叢。", "且能漁釣樂，亦似古人風。"]'),
('5a6e4c28-ed21-443f-8d07-d2174cd63c40','送翁巴陵之官','徐璣','宋','宋诗','song-poetry','','[]','好去巴陵縣，神仙屢此過。',48,'全唐诗/poet.song.178000.json','["好去巴陵縣，神仙屢此過。", "但知存惠愛，自足感弦歌。", "官况湘流碧，詩情楚岫多。", "梅花送征棹，萬里接陽和。"]'),
('d38548fb-03c3-4c14-8be0-c9b91ffc27e4','時魚','徐璣','宋','宋诗','song-poetry','','[]','風晴霜氣合，沙渚夜鳴榔。',48,'全唐诗/poet.song.178000.json','["風晴霜氣合，沙渚夜鳴榔。", "獨喜鱗兼細，時看寸有長。", "月斜寒動影，水碧靜傳香。", "可愛漁翁樂，溪梅次第芳。"]'),
('84befeba-49ef-43e7-b8e7-1be4f9096894','初夏','徐璣','宋','宋诗','song-poetry','','[]','一雨臨初夏，驚雷昨夜新。',48,'全唐诗/poet.song.178000.json','["一雨臨初夏，驚雷昨夜新。", "地晴烟冉冉，堤漲淥鱗鱗。", "蘭麝銷衣潤，珊瑚浄几塵。", "牆陰舊無竹，筍過謝東鄰。"]'),
('f4fe5a10-b7ee-47e5-8476-d7096fb1c14a','送劉明遠客和州  其一','徐璣','宋','宋诗','song-poetry','','[]','邊郡三年守，知陪後乘安。',48,'全唐诗/poet.song.178000.json','["邊郡三年守，知陪後乘安。", "遠遊登覽易，老大別離難。", "紅日千峰曉，清霜幾樹丹。", "江臯一回首，念爾去凌寒。"]'),
('f4e6d981-dbb2-462d-b7d8-5f77c719306e','送劉明遠客和州  其二','徐璣','宋','宋诗','song-poetry','','[]','十載知心友，文才爾獨兼。',48,'全唐诗/poet.song.178000.json','["十載知心友，文才爾獨兼。", "病諳孤寢樂，貧識茹蔬甜。", "冬暖梅花早，年豐酒價廉。", "不愁無遠信，佳句日應添。"]'),
('01ddb65f-6e50-41d5-b4d5-fa4cd6306eee','年家生張主簿經過相尋率爾贈別','徐璣','宋','宋诗','song-poetry','','[]','上世喜同登，論交建水清。',48,'全唐诗/poet.song.178000.json','["上世喜同登，論交建水清。", "故人逢客裏，明日又離情。", "佳闕東南少，卑官遠近行。", "秋風分手地，霜葉滿江城。"]'),
('4c87e679-5ee4-4736-b626-183afcfe5648','中川別舍弟','徐璣','宋','宋诗','song-poetry','','[]','中川人語別，南國夜何其。',48,'全唐诗/poet.song.178000.json','["中川人語別，南國夜何其。", "江迥風來急，山低月落遲。", "纜從前浦遠，角在古城吹。", "五畝耕鋤地，何當手共治。"]'),
('52b28098-9793-4036-bd34-2b88fb6c3700','冬日書懷','徐璣','宋','宋诗','song-poetry','','[]','閑庭黄葉滿，園樹盡玲瓏。',48,'全唐诗/poet.song.178000.json','["閑庭黄葉滿，園樹盡玲瓏。", "寒水終朝碧，霜天向晚紅。", "蔬餐如野寺，茅舍近溪翁。", "非是分囂寂，由來趣不同。"]'),
('7959abb0-65fe-4793-b370-fb96a0e07285','送朱學諭遊建上赴陳提舉約','徐璣','宋','宋诗','song-poetry','','[]','星郎復持節，垂榻待君來。',48,'全唐诗/poet.song.178000.json','["星郎復持節，垂榻待君來。", "又醉閩溪酒，因沾謝屐苔。", "天寒松子落，臘月茗花開。", "白髮傷離緒，何堪節物催。"]'),
('8a9b482c-24df-44e6-a30f-95d08746af57','一雨','徐璣','宋','宋诗','song-poetry','','[]','一雨郊原綠，高田水過低。',48,'全唐诗/poet.song.178000.json','["一雨郊原綠，高田水過低。", "荷鋤煩稚子，饁畝伺良妻。", "老去知誰許，歸歟得自犂。", "緩行溪上石，吟詠到鴉棲。"]'),
('cddba989-8925-4041-b6f5-6507238c2ba6','宿寺','徐璣','宋','宋诗','song-poetry','','[]','古木山邊寺，深松徑底風。',48,'全唐诗/poet.song.178000.json','["古木山邊寺，深松徑底風。", "獨吟侵夜半，清坐雜禪中。", "殿靜燈光小，經殘磬韻空。", "不知清夢遠，啼鳥在林東。"]'),
('31936957-c526-444b-9ee7-eeca5ab5ddff','亥月','徐璣','宋','宋诗','song-poetry','','[]','亥月霜澄霽，幽窗晚更明。',48,'全唐诗/poet.song.178000.json','["亥月霜澄霽，幽窗晚更明。", "文書隨意閲，蘭菊與心清。", "洗硯須池暖，燃香得火輕。", "妻孥渾笑我，作計亦平平。"]'),
('340c6a09-10f4-431c-8825-4727a9165cdd','孤坐','徐璣','宋','宋诗','song-poetry','','[]','晨起猶孤坐，瓶泉待煮茶。',48,'全唐诗/poet.song.178000.json','["晨起猶孤坐，瓶泉待煮茶。", "寒烟添竹色，疎雪亂梅花。", "獨喜忘時事，誰知改歲華。", "多君能過此，人里似山家。"]'),
('5cf1c7e3-b345-4960-88d5-d4d050db256f','霜','徐璣','宋','宋诗','song-poetry','','[]','詩鬢曉星星，霜天似水清。',48,'全唐诗/poet.song.178000.json','["詩鬢曉星星，霜天似水清。", "風當窗眼入，冰向硯池生。", "已瘦梅枝影，猶乾竹葉聲。", "夜來天地潔，惟是月華明。"]'),
('feb534ce-57c6-4fe1-9018-6132e7cba089','夏夜懷趙靈秀','徐璣','宋','宋诗','song-poetry','','[]','古郡草爲城，懷賢隔此扃。',48,'全唐诗/poet.song.178000.json','["古郡草爲城，懷賢隔此扃。", "水風凉遠樹，河影動疎星。", "江國晴猶潤，煙林暮轉青。", "荷鋤曾有約，獨喜带騷經。"]'),
('ad1ace06-c11f-499e-b15c-56c0f735de15','夏日湖上訪隠士','徐璣','宋','宋诗','song-poetry','','[]','煩暑何能避，孤舟訪隠人。',48,'全唐诗/poet.song.178000.json','["煩暑何能避，孤舟訪隠人。", "水鄉菱藕熟，晴野稻苗新。", "爲學師前輩，談空悟宿身。", "鏡湖三百頃，不似此湖濱。"]'),
('b1ec7102-c07c-49be-a540-f340e2350b88','又寄','徐璣','宋','宋诗','song-poetry','','[]','庭深自無暑，苔徑復縈紆。',48,'全唐诗/poet.song.178000.json','["庭深自無暑，苔徑復縈紆。", "賓客不長到，兒童亦可娛。", "荷花晴带粉，蒲葉曉凝珠。", "與爾城闉隔，茲歡想不殊。"]'),
('6cedfebe-923c-41f0-8885-ca18ae6f2e52','題石門洞','徐璣','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','瀑水東南冠，廬山未足論。',48,'全唐诗/poet.song.178000.json','["瀑水東南冠，廬山未足論。", "飛來長似雨，流處不知源。", "洞裏龍爲宅，溪邊石作門。", "修行謝康樂，庵有故基存。"]'),
('e1d90943-0296-434d-8583-0c4c52eae487','臘日同朱學諭登翠麓亭','徐璣','宋','宋诗','song-poetry','','[]','緩行循翠麓，凝睇俯清灣。',48,'全唐诗/poet.song.178000.json','["緩行循翠麓，凝睇俯清灣。", "舟楫蘆花外，江山夕照間。", "天寒雖日短，歲晚亦身閑。", "高樹梅初發，與君相共攀。"]'),
('bc097d84-011a-42b8-9100-e1c619874774','山居','徐璣','宋','宋诗','song-poetry','','[]','柳竹藏花塢，茅茨接草池。',48,'全唐诗/poet.song.178000.json','["柳竹藏花塢，茅茨接草池。", "開門驚燕子，汲水得魚兒。", "地僻春猶靜，人閑日自遲。", "山禽啼忽住，飛起又相隨。"]'),
('53b3bbc8-9e00-4bd8-a610-8d71a7a70b2b','西興渡壓雨贈同邸李計議','徐璣','宋','宋诗','song-poetry','','[]','客裏遭多難，相逢意已降。',48,'全唐诗/poet.song.178000.json','["客裏遭多難，相逢意已降。", "酒殽同晚店，煙雨隔秋江。", "許國心猶壯，論兵世少雙。", "將門尋舊績，應不記蓬窗。"]'),
('61cae138-b81a-407a-b99b-30e79c87ed10','謝步石鼓山','徐璣','宋','宋诗','song-poetry','','[]','謝公曾步處，石鼓尚依然。',48,'全唐诗/poet.song.178000.json','["謝公曾步處，石鼓尚依然。", "地狹川多漲，山高浦欲旋。", "不因詩句說，更復有誰傳。", "懷望徘徊久，寒郊起暮煙。"]'),
('6f05ca9a-c819-4918-a247-a3cdc2652566','黄碧','徐璣','宋','宋诗','song-poetry','','[]','黄碧平沙岸，陂塘柳色春。',48,'全唐诗/poet.song.178000.json','["黄碧平沙岸，陂塘柳色春。", "水清知酒美，山瘦識民貧。", "雞犬田家靜，桑麻歲事新。", "相逢行路客，半是永嘉人。"]'),
('6285e5d0-8eeb-4dfd-9da1-def377f80662','題李氏山亭','徐璣','宋','宋诗','song-poetry','','[]','斗建魁星地，城隅李氏亭。',48,'全唐诗/poet.song.178000.json','["斗建魁星地，城隅李氏亭。", "竹高隨路有，山靜隔江青。", "人在雲間語，潮生戶外汀。", "憑高一長望，疑欲入滄溟。"]'),
('9542b697-0d7f-4bb6-93f3-04ce609595b5','送華亭薛運幹','徐璣','宋','宋诗','song-poetry','','[]','三任來得祿，茲行亦是緣。',48,'全唐诗/poet.song.179000.json','["三任來得祿，茲行亦是緣。", "地宜惟有鶴，清職但看船。", "浙水通清海，吳門隔遠烟。", "別離春欲半，草色正芊芊。"]'),
('b04f44da-15ad-404c-a6fc-ab9860afd4ad','讀徐道暉集','徐璣','宋','宋诗','song-poetry','','[]','悟得玄虛理，能令句律精。',48,'全唐诗/poet.song.179000.json','["悟得玄虛理，能令句律精。", "生前惟瘦苦，身後得名清。", "朋友裒錢葬，先生有筆評。", "林頭舊題石，苔蘚带雲生。"]'),
('6ff1d47d-e68c-44b4-b704-8f3be476efc8','送宋省元教授吉州','徐璣','宋','宋诗','song-poetry','','[]','州名因水得，此地昔曾遊。',48,'全唐诗/poet.song.179000.json','["州名因水得，此地昔曾遊。", "自有歐公宅，常多儒者流。", "野花開別岸，春色在行舟。", "勉就詩書教，名高不用求。"]'),
('e38abe7b-cb00-4ec7-81c6-9e38bcce0907','浄光山四首 宿覺庵','徐璣','宋','宋诗','song-poetry','','[]','欲問庵中事，無論後與先。',48,'全唐诗/poet.song.179000.json','["欲問庵中事，無論後與先。", "還因一宿覺，不用再參禪。", "門遠青山曲，簷依古木邊。", "誰當秋夜靜，來看月孤圓。"]'),
('7c2004b3-99bf-47d5-9460-2b01f7cdd04d','浄光山四首 絕境亭','徐璣','宋','宋诗','song-poetry','','[]','行向最高處，惟將物色參。',48,'全唐诗/poet.song.179000.json','["行向最高處，惟將物色參。", "郡城依藪澤，地勢轉東南。", "對景身垂老，題詩興欲酣。", "可能清曉出，四面有晴嵐。"]'),
('b0394c71-9287-4198-b194-28c639646d74','浄光山四首 會景軒','徐璣','宋','宋诗','song-poetry','','[]','屋自與山背，西原景最清。',48,'全唐诗/poet.song.179000.json','["屋自與山背，西原景最清。", "凉風從下起，新月向前明。", "林靜聞僧語，田虛見鷺行。", "此方多積翠，略似鎮南城。"]'),
('8b8b81af-2e53-4b7b-8ef8-238367a1b505','浄光山四首 茶山堂','徐璣','宋','宋诗','song-poetry','','[]','山是朝廷賜，名從古昔傳。',48,'全唐诗/poet.song.179000.json','["山是朝廷賜，名從古昔傳。", "爲堂居此地，汲水記前賢。", "雨露餘根在，荆榛細蔓緣。", "困來求一盞，打坐亦安禪。"]'),
('3f7b73ba-cc49-447d-86bb-25f1c8263fc2','鴈山','徐璣','宋','宋诗','song-poetry','','[]','鴈山深又僻，無數石巖奇。',48,'全唐诗/poet.song.179000.json','["鴈山深又僻，無數石巖奇。", "皆是僧分住，最先誰得知。", "逐時多異景，前輩少題詩。", "南渡名方著，唐人不到茲。"]'),
('ffa2ad56-7e0e-4d2a-bb93-680ff43f1a61','大龍湫','徐璣','宋','宋诗','song-poetry','','[]','瀑水數千尺，何曾貼石流。',48,'全唐诗/poet.song.179000.json','["瀑水數千尺，何曾貼石流。", "還疑衆山坼，故使半空浮。", "霧雨初相亂，波濤忽自由。", "道場從建後，龍去任人游。"]'),
('27c7cd72-fa64-4c98-97f7-10acf537c681','靈峰寺洞','徐璣','宋','宋诗','song-poetry','','[]','洞在寺之右，昔存羅漢蹤。',48,'全唐诗/poet.song.179000.json','["洞在寺之右，昔存羅漢蹤。", "石峯排似筍，山勢裂因龍。", "自有泉甘美，無愁路疊重。", "聖燈云照夜，宿客間曾逢。"]'),
('53fdf1a8-5ea7-4f3c-b573-2d046985c803','浄名寺','徐璣','宋','宋诗','song-poetry','','[]','萬法先除病，誰能識病多。',48,'全唐诗/poet.song.179000.json','["萬法先除病，誰能識病多。", "因來浄名寺，認得老維摩。", "海水峯前聽，秋山雨後過。", "提刑舊題句，韻調復如何。"]'),
('6266c582-17f0-4c86-a2cf-b31abace277e','贈東庵約老','徐璣','宋','宋诗','song-poetry','','[]','一閣手自建，一庵居在東。',48,'全唐诗/poet.song.179000.json','["一閣手自建，一庵居在東。", "既然頭欲白，不用剃令空。", "門掩春山綠，檐依曉日紅。", "玄微知有旨，混在話言中。"]'),
('dbedcb0a-c4f9-436b-9be6-7585c65505ae','西征有寄翁趙徐三友','徐璣','宋','宋诗','song-poetry','','[]','窮冬逆旅身，薄宦此艱辛。',48,'全唐诗/poet.song.179000.json','["窮冬逆旅身，薄宦此艱辛。", "渡水添愁思，看山憶故人。", "煙生村落晚，雨過竹松新。", "昨夜還鄉夢，逢君苦未真。"]'),
('8d2ba2e6-d59e-44b4-af26-93d40d4c2dee','晨起','徐璣','宋','宋诗','song-poetry','','[]','晨起風吹面，朝晴野霧收。',48,'全唐诗/poet.song.179000.json','["晨起風吹面，朝晴野霧收。", "高峰多遠見，淺水少平流。", "世事非難了，塵勞獨未休。", "今年看鬢髮，已變一莖秋。"]'),
('2653e12f-e26f-45aa-96cf-600fb25ccd6d','送趙靈秀赴筠州幕予亦將之湖外','徐璣','宋','宋诗','song-poetry','','[]','郡以竹爲名，因知此地清。',48,'全唐诗/poet.song.179000.json','["郡以竹爲名，因知此地清。", "溪來城下綠，山到市邊平。", "入幕非無客，能文必有聲。", "江湖共遊宦，相望若爲情。"]'),
('75a181c2-e380-4bc3-82ad-b87c174492b6','湘水','徐璣','宋','宋诗','song-poetry','','[]','湘水幾千里，平流少激湍。',48,'全唐诗/poet.song.179000.json','["湘水幾千里，平流少激湍。", "數家分市井，列石起峰巒。", "豈是昔曾到，猶疑畫上看。", "吟詩身漸老，向此作微官。"]'),
('3df4660a-4ee4-435c-877a-610fa60f2ef4','題陳待制湖莊','徐璣','宋','宋诗','song-poetry','','[]','園無三畝地，四面水連天。',48,'全唐诗/poet.song.179000.json','["園無三畝地，四面水連天。", "行向樓高處，却如身在船。", "野花春渚外，山色海雲邊。", "一任人來往，茲懷亦浩然。"]'),
('fbb75656-f332-4ce3-870e-10f6d28f5731','寄陳西老','徐璣','宋','宋诗','song-poetry','','[]','長日無吟伴，閑庭佇物華。',48,'全唐诗/poet.song.179000.json','["長日無吟伴，閑庭佇物華。", "竹枝斜带雨，草色浄侵沙。", "風度平生友，鄰居幾十家。", "前曾乘小醉，訪爾一甌茶。"]'),
('bb0f4884-7b36-49f5-9f06-a29c2a87db65','喜奭上人至','徐璣','宋','宋诗','song-poetry','','[]','住與佛居近，僧閒稍問詩。',48,'全唐诗/poet.song.179000.json','["住與佛居近，僧閒稍問詩。", "湖山明月夜，風露菊花時。", "達意言常省，微吟步自遲。", "老來朋舊少，愛爾得相隨。"]'),
('69d4a911-1ef1-4eb7-8420-45aa38a09bc9','題方上人房古梅','徐璣','宋','宋诗','song-poetry','','[]','曾聽道公語，先師愛此梅。',48,'全唐诗/poet.song.179000.json','["曾聽道公語，先師愛此梅。", "但知傳說老，不記若年栽。", "半樹枯仍發，疎花晚自開。", "方兄頭又白，常喜故人來。"]'),
('4d7f9ffe-c4e0-486f-a1b6-cb2fc7644c60','春日遊張提舉園池','徐璣','宋','宋诗','song-poetry','','[]','西野芳菲路，春風正可尋。',48,'全唐诗/poet.song.179000.json','["西野芳菲路，春風正可尋。", "山城依曲渚，古渡入脩林。", "長日多飛絮，遊人愛綠陰。", "晚來歌吹起，惟覺畫堂深。"]'),
('17d0540b-37f6-4847-9093-b7754c7148df','送戴文子赴定海主簿','徐璣','宋','宋诗','song-poetry','','[]','江天經雨後，秋意轉新高。',48,'全唐诗/poet.song.179000.json','["江天經雨後，秋意轉新高。", "遠棹送行客，凉颸生細濤。", "高人初祿仕，判語亦風騷。", "若到海西岸，佛光盈翠袍。"]'),
('d0c872ea-4080-4657-b43e-0b759f2ce083','夏日懷友','徐璣','宋','宋诗','song-poetry','','[]','流水階除靜，孤眠得自由。',48,'全唐诗/poet.song.179000.json','["流水階除靜，孤眠得自由。", "月生林欲曉，雨過夜如秋。", "遠憶荷花浦，誰吟杜若洲。", "良宵恐無夢，有夢即俱遊。"]'),
('c58ce633-0554-4133-a436-051841620a8d','臘日驪山渡逢故人','徐璣','宋','宋诗','song-poetry','','[]','天寒多木葉，愁思滿溪濱。',48,'全唐诗/poet.song.179000.json','["天寒多木葉，愁思滿溪濱。", "惆悵往來渡，經行多少人。", "時情猶重臘，歲事每占春。", "與爾他鄉旅，誰當懷抱新。"]'),
('ac311f61-68c7-455c-86b5-27f2e6a575d0','登信州靈山閣跨鶴臺','徐璣','宋','宋诗','song-poetry','','[]','清遊吾有分，渾似昔曾來。',48,'全唐诗/poet.song.179000.json','["清遊吾有分，渾似昔曾來。", "野屋憑高住，青山到水回。", "欲看靈岫遠，須待曉雲開。", "漸漸生愁思，鄉心上古臺。"]'),
('bf30bb86-d20f-4a51-91b8-e05ca1098656','書翁卷詩集後','徐璣','宋','宋诗','song-poetry','','[]','五字極難精，知君合有名。',48,'全唐诗/poet.song.179000.json','["五字極難精，知君合有名。", "磨礱雙鬢改，收拾一編成。", "泉落秋巖潔，花開野徑清。", "漸多來學者，體法似元英。"]'),
('b7348860-8450-43b7-b310-d76bdf27cb3f','送瑞州張知錄','徐璣','宋','宋诗','song-poetry','','[]','歲暮不惜別，君行是宦遊。',48,'全唐诗/poet.song.179000.json','["歲暮不惜別，君行是宦遊。", "江西多野水，湖上正高秋。", "舊友曾過處，新題必共留。", "官閒可尋訪，竹徑最深幽。"]'),
('95d17b9b-be21-4cbd-90d8-88e991063923','寄舍弟','徐璣','宋','宋诗','song-poetry','','[]','寄問安仁弟，弦歌又一年。',48,'全唐诗/poet.song.179000.json','["寄問安仁弟，弦歌又一年。", "流來溪水遠，清到縣門前。", "故里人情樂，新居物色鮮。", "宦歸言話款，正及早梅邊。"]'),
('ed62aa34-58f1-4625-80f8-cc853038d89e','秋夕懷趙師秀','徐璣','宋','宋诗','song-poetry','','[]','冷落生愁思，衰懷得句稀。',48,'全唐诗/poet.song.179000.json','["冷落生愁思，衰懷得句稀。", "如何秋夜雨，不念故人歸。", "蛩響砌尤靜，雲疎月尚微。", "惟憐籬下菊，漸漸可相依。"]'),
('d204fb32-e46a-4367-bf01-5d302751371d','送趙明叔爲漳浦宰','徐璣','宋','宋诗','song-poetry','','[]','去年官滿處，送子意何如。',48,'全唐诗/poet.song.179000.json','["去年官滿處，送子意何如。", "地接泉山近，人依大澤居。", "南中繁賦役，美政輯田廬。", "公退無他事，彈琴更讀書。"]'),
('9790fbf7-9879-4aca-8ee9-eff41189cdc9','送岳州蔣節推','徐璣','宋','宋诗','song-poetry','','[]','湘水知幾派，到湖相合流。',48,'全唐诗/poet.song.179000.json','["湘水知幾派，到湖相合流。", "煙深雲夢曉，風靜岳陽秋。", "送子方行役，令予憶舊遊。", "文書時正省，賦咏可登樓。"]'),
('fe19c24a-f1cb-445a-b7a7-8c88f6016e91','梅坡','徐璣','宋','宋诗','song-poetry','','[]','淺水低坡幾樹苔，冷光摇動玉塵埃。',64,'全唐诗/poet.song.179000.json','["淺水低坡幾樹苔，冷光摇動玉塵埃。", "橫斜直似安排得，古怪多應折損來。", "潔白要須侵夜看，飄零却是被春催。", "閒來立斷清風影，一片飛香落酒杯。"]'),
('19f05c12-b93e-4a65-8d09-9e4c79bc964d','送徐侍郎南遷','徐璣','宋','宋诗','song-poetry','','[]','已見皇家日月安，更教遠去不辭艱。',64,'全唐诗/poet.song.179000.json','["已見皇家日月安，更教遠去不辭艱。", "若人豈謂元城在，有客先知御史還。", "風急滿江皆白浪，雨收何處不青山。", "天心正欲扶宗社，爲報慈闈得解顔。"]'),
('ff0ef5f2-15e5-4a8c-b039-396a88e026de','淥波亭寄泊晨起有感','徐璣','宋','宋诗','song-poetry','','[]','塵埃幾泯寸心清，晨起孤吟在水亭。',64,'全唐诗/poet.song.179000.json','["塵埃幾泯寸心清，晨起孤吟在水亭。", "晴景淡紅煙景白，近山濃綠遠山青。", "初因薄宦成羈旅，忽伴輕鷗落渚汀。", "安得數年居此地，待須長日補騷經。"]'),
('66b5e50f-6297-4b0f-a0ea-67ddcf6455f0','秋日登玉峰','徐璣','宋','宋诗','song-poetry','','[]','玉琢孤峰壓富沙，人行峰頂步雲霞。',64,'全唐诗/poet.song.179000.json','["玉琢孤峰壓富沙，人行峰頂步雲霞。", "溪流緩去幾回曲，樹色幽分無數家。", "翠拂寒煙平似水，紅飄霜葉遠如花。", "明朝重向城中望，對此孤峰應不差。"]'),
('1279b00c-ec40-4b07-ae3f-90462b9b13a5','壬戌二月','徐璣','宋','宋诗','song-poetry','','[]','山城二月景如何，行處時時聽踏歌。',64,'全唐诗/poet.song.179000.json','["山城二月景如何，行處時時聽踏歌。", "淡色似黄楊葉小，濃香如蜜菜花多。", "春容每到晴時改，天氣偏從雨後和。", "好向溪頭尋釣侶，小溪連夕漲清波。"]'),
('97ac2b40-288c-49e1-9467-a1ce3f10354c','題東山道院','徐璣','宋','宋诗','song-poetry','','[]','古院嶔𡼭石作層，綠苔芳草近郊坰。',64,'全唐诗/poet.song.179000.json','["古院嶔𡼭石作層，綠苔芳草近郊坰。", "溪流偶到門前合，山色偏來竹裏青。", "靜與黄蜂通戶牖，閒將白鳥共沙汀。", "道人亦有能琴者，一曲清徽最可聽。"]'),
('b9ed8644-d4f6-4501-be95-fa6fb0c80c2b','六月歸途','徐璣','宋','宋诗','song-poetry','','[]','星明殘照數峰晴，夜靜惟聞水有聲。',64,'全唐诗/poet.song.179000.json','["星明殘照數峰晴，夜靜惟聞水有聲。", "六月行人須早起，一天凉露濕衣輕。", "宦情每向途中薄，詩句多於馬上成。", "故里諸公應念我，稻花香裏計歸程。"]'),
('3565b01f-333f-4c10-b755-e51c45bc60fd','訪湖友','徐璣','宋','宋诗','song-poetry','','[]','城中日日望南湖，乞得閒來訪隠居。',64,'全唐诗/poet.song.179000.json','["城中日日望南湖，乞得閒來訪隠居。", "漸有秋霖籬菊長，纔無暑氣渚蓮疎。", "壁間古畫多賢像，案上塵編半佛書。", "未見主人逢稚子，不通姓字獨踟躇。"]'),
('b5216f30-5d3a-4d35-b608-5157f0870a60','中秋集鮑樓作','徐璣','宋','宋诗','song-poetry','','[]','秋在湖樓正可過，扁舟窈窕逐菱歌。',64,'全唐诗/poet.song.179000.json','["秋在湖樓正可過，扁舟窈窕逐菱歌。", "淡雲遮月連天白，遠水生凉入夜多。", "已是高人難會聚，矧逢佳節共吟哦。", "明朝此集喧城市，應說風流似永和。"]'),
('76296bd0-e9e1-4dc9-9787-d9c12e209166','登滕王閣','徐璣','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','重重樓閣倚江干，岸草汀煙遠近間。',64,'全唐诗/poet.song.179000.json','["重重樓閣倚江干，岸草汀煙遠近間。", "春水生時都是水，西山青外別無山。", "雲歸長若真人在，風過猶疑帝子還。", "自古舟船城下泊，幾人來此望鄉關。"]'),
('895cbe71-0c39-420f-bb7a-36aad638072c','贈趙師秀','徐璣','宋','宋诗','song-poetry','','[]','游宦歸來隔幾春，清羸還是舊時身。',64,'全唐诗/poet.song.179000.json','["游宦歸來隔幾春，清羸還是舊時身。", "養成心性方能靜，化得妻兒不說貧。", "竹長新陰深似洞，梅添怪相老於人。", "亦知曾見高人了，近作文章氣力勻。"]'),
('f2eae90a-a534-4698-bf50-a0a7280bb83f','贈徐照','徐璣','宋','宋诗','song-poetry','','[]','近參圓覺境如何，月冷高空影在波。',64,'全唐诗/poet.song.179000.json','["近參圓覺境如何，月冷高空影在波。", "身健却緣餐飯少，詩清都爲飲茶多。", "城居亦似山中靜，夜夢俱無世慮魔。", "昨日曾知到門外，因隨鶴步踏青莎。"]'),
('67563a5a-029b-4fa7-8835-b76847240cf6','新春書事','徐璣','宋','宋诗','song-poetry','','[]','出門閒步草萋萋，桑柘陰中亦有蹊。',64,'全唐诗/poet.song.179000.json','["出門閒步草萋萋，桑柘陰中亦有蹊。", "幾樹晴煙鶑囀早，一塘春水燕飛低。", "空如陶亮官爲令，難學嚴陵住近溪。", "聖世幸時沾薄祿，不能辛苦又攀躋。"]'),
('85781c7c-b034-4dc5-a72d-1b0de33dd96d','題養拙軒','徐璣','宋','宋诗','song-poetry','','[]','混沌分來便至今，紛紛巧事日成林。',64,'全唐诗/poet.song.179000.json','["混沌分來便至今，紛紛巧事日成林。", "月明未免蝦蟆食，秋至依然蟋蟀吟。", "自歎一身全是幻，誰能萬事不容心。", "到君齋舍清如水，應使凡機盡弗侵。"]'),
('e952864d-9c35-48f6-847e-c7073a993dd9','泊馬公嶺','徐璣','宋','宋诗','song-poetry','','[]','維舟拂曉步平沙，晚泊雲根第一家。',64,'全唐诗/poet.song.179000.json','["維舟拂曉步平沙，晚泊雲根第一家。", "新取菜蔬沾野露，旋編籬落带山花。", "門前相對青峰小，屋後流來白水斜。", "可愛山翁無一事，藤牆西畔看蜂衙。"]'),
('411be2b7-1593-450c-bf6f-6984c5243041','酒','徐璣','宋','宋诗','song-poetry','','[]','才傾一盞碧澄澄，自是山妻手法成。',64,'全唐诗/poet.song.179000.json','["才傾一盞碧澄澄，自是山妻手法成。", "不遣水多防味薄，要令麴少得香清。", "凉從荷葉風邊起，煖向梅花月裏生。", "世味總無如此味，深知此味即淵明。"]'),
('0b11b58f-5cf9-4cce-aab0-089237033255','梅  其一','徐璣','宋','宋诗','song-poetry','','[]','疎芳點點是春冰，應笑浮華去不停。',64,'全唐诗/poet.song.179000.json','["疎芳點點是春冰，應笑浮華去不停。", "石畔長來枝易老，竹間瘦得萼全青。", "孤高自愛香無色，寂寞渾教影問形。", "莫遣豐□種宮苑，野橋流水最清泠。"]'),
('20b5e2ec-367f-4555-ad39-be5da547b05c','梅  其二','徐璣','宋','宋诗','song-poetry','','[]','是誰曾種白玻璃，夐絕寒荒一點奇。',64,'全唐诗/poet.song.179000.json','["是誰曾種白玻璃，夐絕寒荒一點奇。", "不厭壠頭千百樹，最憐窗下兩三枝。", "幽深真似離騷句，枯健猶如賈島詩。", "吟到月斜渾未已，蕭蕭鬢影有風吹。"]'),
('939e7100-6f57-429e-a08f-cdaa514ca435','翁知縣歸自湖湘','徐璣','宋','宋诗','song-poetry','','[]','渺渺秋江带碧鴉，君來應是弔湘涯。',64,'全唐诗/poet.song.179000.json','["渺渺秋江带碧鴉，君來應是弔湘涯。", "懷人也似居無竹，憂世長如飯有砂。", "一袖清風詩思遠，滿汀芳草夕陽賒。", "還歸殊未□顔瘦，已種湖邊遶處花。"]'),
('31425d46-7085-4acc-8265-c2eacd3c9060','奉酬翁松廬見寄','徐璣','宋','宋诗','song-poetry','','[]','客路歸時雨似煙，歸來還近菊花天。',64,'全唐诗/poet.song.179000.json','["客路歸時雨似煙，歸來還近菊花天。", "寸心不到青雲上，一事難成白髮前。", "風外松聲如昨夕，竹間梅蘂接新年。", "閒來得句頻相送，自有高人住屋邊。"]'),
('0214b4fa-9928-4929-a328-1fc0813df93a','送劉和州','徐璣','宋','宋诗','song-poetry','','[]','揚旌遥指歷陽城，霜淡晴天鼓角明。',64,'全唐诗/poet.song.179000.json','["揚旌遥指歷陽城，霜淡晴天鼓角明。", "步騎打圍秋草綠，舳艫傳唱曉江平。", "岸分南北人煙近，地控東南羽檄清。", "牧守只今非易予，九重淵默待盈成。"]'),
('354fc287-24b1-4460-99ba-185d97dd7858','過九嶺','徐璣','宋','宋诗','song-poetry','','[]','斷崖橫路水潺潺，行到山根又上山。',32,'全唐诗/poet.song.179000.json','["斷崖橫路水潺潺，行到山根又上山。", "眼看別峰雲霧起，不知身也在雲間。"]'),
('a6662d00-645d-4812-a696-7ad947e99ed6','題陳西老畫蜀山圖','徐璣','宋','宋诗','song-poetry','','[]','壁立青山带峽溪，閒雲盡日自高低。',32,'全唐诗/poet.song.179000.json','["壁立青山带峽溪，閒雲盡日自高低。", "知他春樹深多少，應有清猿在裏啼。"]'),
('77d6ca10-fd1d-4b45-a0a1-eb14d049f24d','夜涼','徐璣','宋','宋诗','song-poetry','','[]','夜涼扶杖出山齋，身似孤雲倚石崖。',32,'全唐诗/poet.song.179000.json','["夜涼扶杖出山齋，身似孤雲倚石崖。", "吟就不知山月曉，清風滿面落松釵。"]'),
('827128f2-cb93-42d5-97a1-367a4e30c31c','春雨  其一','徐璣','宋','宋诗','song-poetry','','[]','斷橋橫落淺沙邊，沙岸疎梅卧曉煙。',32,'全唐诗/poet.song.179000.json','["斷橋橫落淺沙邊，沙岸疎梅卧曉煙。", "新雨漲溪三尺水，漁翁來覓渡船錢。"]'),
('6d468c4b-d86d-4f59-a7cd-709574a091da','春雨  其二','徐璣','宋','宋诗','song-poetry','','[]','柳著輕黄欲染衣，汀沙漠漠草菲菲。',32,'全唐诗/poet.song.179000.json','["柳著輕黄欲染衣，汀沙漠漠草菲菲。", "曉風吹斷寒煙碧，無數鴛鴦溪上飛。"]'),
('68122010-4900-41ea-a996-0741578dcf04','夏日閒坐','徐璣','宋','宋诗','song-poetry','','[]','無數山蟬噪夕陽，高峰影裏坐陰涼。',32,'全唐诗/poet.song.179000.json','["無數山蟬噪夕陽，高峰影裏坐陰涼。", "石邊偶看清泉滴，風過微聞松葉香。"]'),
('b638079c-f380-43d7-aaaa-3ed5917bb60e','丹青閣','徐璣','宋','宋诗','song-poetry','','[]','翠靄空霏忽有無，筆端誰著此工夫。',32,'全唐诗/poet.song.179000.json','["翠靄空霏忽有無，筆端誰著此工夫。", "溪山本被人圖畫，却道溪山是畫圖。"]'),
('48b7a9de-ca69-40b9-816c-064ef2652a14','移官南浦作','徐璣','宋','宋诗','song-poetry','','[]','簿領初爲建水棲，移官南浦又沈迷。',32,'全唐诗/poet.song.179000.json','["簿領初爲建水棲，移官南浦又沈迷。", "溪山轉處人煙隔，惟有黄鸝一樣啼。"]'),
('be31261a-2d37-4a87-a7da-689a14fbf82a','秋行二首  其一','徐璣','宋','宋诗','song-poetry','','["\u79cb\u5929", "\u5199\u666f"]','戛戛秋蟬響似箏，聽蟬閒傍柳邊行。',32,'全唐诗/poet.song.179000.json','["戛戛秋蟬響似箏，聽蟬閒傍柳邊行。", "小溪清水平如鏡，一葉飛來細浪生。"]'),
('e255df47-12f2-45f0-9f3b-fe4f039ccf1e','秋行二首  其二','徐璣','宋','宋诗','song-poetry','','[]','紅葉枯梨一兩株，翛然秋思滿山居。',32,'全唐诗/poet.song.179000.json','["紅葉枯梨一兩株，翛然秋思滿山居。", "詩懷自歎多塵土，不似秋來木葉疎。"]'),
('c2951efb-b215-41b4-adc0-a1f714795802','建劍道中','徐璣','宋','宋诗','song-poetry','','[]','雲麓煙巒知幾層，一灣溪轉一灣清。',32,'全唐诗/poet.song.179000.json','["雲麓煙巒知幾層，一灣溪轉一灣清。", "行人只在清灣裏，盡日松聲雜水聲。"]'),
('53faae9f-f451-473e-8c84-adb4843d42f6','舟過水口作','徐璣','宋','宋诗','song-poetry','','[]','舟行遥指福城關，天宇開時地勢寬。',32,'全唐诗/poet.song.179000.json','["舟行遥指福城關，天宇開時地勢寬。", "二百里溪平似掌，一帆風色到懷安。"]'),
('dd62708a-6f37-473a-9d82-334cf8eaa833','新涼','徐璣','宋','宋诗','song-poetry','','["\u7530\u56ed", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u5199\u9e1f", "\u9e1f"]','水滿田疇稻葉齊，日光穿樹曉煙低。',32,'全唐诗/poet.song.179000.json','["水滿田疇稻葉齊，日光穿樹曉煙低。", "黄鶑也愛新涼好，飛過青山影裏啼。"]'),
('f59d58dd-9552-44d9-994a-9661b0abfe4d','新春喜雨','徐璣','宋','宋诗','song-poetry','','[]','農家不厭一冬晴，歲事春來漸有形。',32,'全唐诗/poet.song.179000.json','["農家不厭一冬晴，歲事春來漸有形。", "昨夜新雷催好雨，蔬畦麥壠最先青。"]'),
('4dfe89d6-6a0f-4522-8434-96c2a40dde9b','春晚','徐璣','宋','宋诗','song-poetry','','[]','午風庭院綠成衣，春色方濃又欲歸。',32,'全唐诗/poet.song.179000.json','["午風庭院綠成衣，春色方濃又欲歸。", "蝌蚪散邊荷葉出，酴醿香裏柳綿飛。"]'),
('e9e649aa-f431-4266-9d78-d23030a0a25b','漳州圓山','徐璣','宋','宋诗','song-poetry','','[]','輕煙漠漠霧綿綿，野色籠青傍屋前。',32,'全唐诗/poet.song.179000.json','["輕煙漠漠霧綿綿，野色籠青傍屋前。", "盡說漳南風水好，衆山圍繞一山圓。"]'),
('b3117683-ccc9-4b2e-bbbb-ebc5b1120edd','古陵橋','徐璣','宋','宋诗','song-poetry','','[]','西橋西岸柳成絲，春去春來歲歲同。',32,'全唐诗/poet.song.179000.json','["西橋西岸柳成絲，春去春來歲歲同。", "偶被東風吹落絮，又隨流水過橋東。"]'),
('60fd94d2-8b32-4621-907c-37e7aeeefa6d','新秋','徐璣','宋','宋诗','song-poetry','','[]','新秋一雨洗林關，晚色清澄滿望間。',32,'全唐诗/poet.song.179000.json','["新秋一雨洗林關，晚色清澄滿望間。", "風靜白雲橫不斷，山前又疊一重山。"]'),
('4afd03bd-739f-41c3-8ece-8f14c833705d','五里牌邊','徐璣','宋','宋诗','song-poetry','','[]','路繞山根石磴斜，小橋流水樹交加。',32,'全唐诗/poet.song.179000.json','["路繞山根石磴斜，小橋流水樹交加。", "柴門半掩無人到，五里牌邊三四家。"]'),
('3d1735f3-d3d9-4723-9df7-72ef7099dbad','書同安舊酒家壁','徐璣','宋','宋诗','song-poetry','','[]','榕陰綠滿驛程邊，駐馬難尋舊聖賢。',32,'全唐诗/poet.song.179000.json','["榕陰綠滿驛程邊，駐馬難尋舊聖賢。", "只有好山橫迥野，不論朝暮带輕煙。"]'),
('5a311989-001b-4344-9df1-011fc69a272e','永春路','徐璣','宋','宋诗','song-poetry','','[]','路行僻處山山好，春到晴時物物佳。',32,'全唐诗/poet.song.179000.json','["路行僻處山山好，春到晴時物物佳。", "秀色連雲原上麥，清香夾道刺桐花。"]'),
('562a8a6f-71f7-4318-877b-ecfc092961ce','秀峰寺','徐璣','宋','宋诗','song-poetry','','[]','籃輿晚泊近巖隈，精舍門臨古道開。',32,'全唐诗/poet.song.179000.json','["籃輿晚泊近巖隈，精舍門臨古道開。", "僧子相逢便相識，十年三過秀峰來。"]'),
('3687281b-5eae-4504-bf27-5df1022697e1','連江官湖','徐璣','宋','宋诗','song-poetry','','[]','衆山圍繞淥團圓，官木參差古道邊。',32,'全唐诗/poet.song.179000.json','["衆山圍繞淥團圓，官木參差古道邊。", "行盡濃陰全不了，一湖飛雨带輕煙。"]'),
('6d148c8a-38c9-4922-ba84-c991ff59fba5','九日上懷古堂','徐璣','宋','宋诗','song-poetry','','[]','山前事跡古來多，風雨塵埃竟若何。',32,'全唐诗/poet.song.179000.json','["山前事跡古來多，風雨塵埃竟若何。", "惟有白衣秦處士，數篇佳句不曾磨。"]'),
('0c672a91-5e54-4f7f-8d98-b41028a983d7','登薛象先新樓','徐璣','宋','宋诗','song-poetry','','[]','矮簷風雨送蝸牛，有客來誇百尺樓。',64,'全唐诗/poet.song.179000.json','["矮簷風雨送蝸牛，有客來誇百尺樓。", "闔郡池臺皆下瞰，背城湖海亦全收。", "清時未放徒高卧，半世胡爲故倦遊。", "解盡橐金君計決，月明長笛起漁舟。"]'),
('7cfd0f5d-67ae-4d8a-b1c1-c8086fe36dec','夢成','徐璣','宋','宋诗','song-poetry','','[]','向晚菱歌起，風平水不流。',24,'全唐诗/poet.song.179000.json','["向晚菱歌起，風平水不流。", "鴛鴦兩相逐，飛過採蓮舟。"]'),
('344328e2-e224-4df9-ab4a-3c22e27f8def','湖','徐璣','宋','宋诗','song-poetry','','[]','拾得柔條弄淺波，清風吹斷采蓮歌。',32,'全唐诗/poet.song.179000.json','["拾得柔條弄淺波，清風吹斷采蓮歌。", "又移小艇前汀去，蓮葉稠時柳葉多。"]'),
('22686e5a-31e7-4030-bdf7-00fd82632df5','酴醿','徐璣','宋','宋诗','song-poetry','','[]','叢叢扶重蕊，微風動弱枝。',24,'全唐诗/poet.song.179000.json','["叢叢扶重蕊，微風動弱枝。", "北人言語巧，喚作菊酴醿。"]'),
('705d0f09-3c35-4314-9e49-1855f11de1b4','贈九華李丹士','徐璣','宋','宋诗','song-poetry','','[]','長記零陵郡，共看江上峰。',48,'全唐诗/poet.song.179000.json','["長記零陵郡，共看江上峰。", "一生輕世事，幾處認仙蹤。", "轉式驅雷電，封泥伏虎龍。", "三千三百里，今日又相逢。"]'),
('4538a22c-4469-4bb6-a62c-c0f9bd85b49a','壽權漕大卿  其一','徐璣','宋','宋诗','song-poetry','','[]','青陽初動小春華，盡道葱蘢曉氣佳。',64,'全唐诗/poet.song.179000.json','["青陽初動小春華，盡道葱蘢曉氣佳。", "卿月早隨良月誕，繡衣元屬衮衣家。", "仙方養就雙瞳碧，和氣分成兩臉霞。", "看取調羹消息好，年年長带早梅花。"]'),
('c9efb628-219e-446b-986a-9ba2d8640477','壽權漕大卿  其二','徐璣','宋','宋诗','song-poetry','','[]','接物溫溫笑滿眉，步趨登降亦委蛇。',64,'全唐诗/poet.song.179000.json','["接物溫溫笑滿眉，步趨登降亦委蛇。", "非關飾貌邀人譽，祇是存心不自欺。", "王導果能恢德業，謝公端可鎮澆漓。", "聖明天子崇恭儉，合向中朝正羽儀。"]'),
('26b01215-18e9-4f73-b2c3-97051efd5e69','壽湯侍郎','徐璣','宋','宋诗','song-poetry','','[]','東括神仙府，三巖福地通。',120,'全唐诗/poet.song.179000.json','["東括神仙府，三巖福地通。", "異人多接迹，相種况同風。", "質有璠璵粹，姿全鼎鼐隆。", "文章親視草，丰度早乘驄。", "紫橐潜藩貴，金題秘殿崇。", "寬卑時自理，誠恪歲乃豐。", "身在凝香處，人居和氣中。", "鶑聲春藹藹，花影日融融。", "劍佩沙堤近，謳歌建水同。", "願瞻崧嶽表，長與轉洪濛。"]'),
('7378600f-e5d4-46c4-84ce-4704b9c1659a','壽曾漕','徐璣','宋','宋诗','song-poetry','','[]','洪波混浩深無底，分作江河合成海。',320,'全唐诗/poet.song.179000.json','["洪波混浩深無底，分作江河合成海。", "由來分合必有源，一點清澄元不改。", "皇家德澤在人深，人心已洽天眷臨。", "爰産真賢佐隆治，南豐昆季玉與金。", "南豐先生飽文學，筆端璀璨相參錯。", "帝制猶如盤誥風，良史不令遷固作。", "文昭內翰學於兄，文章餘事德業成。", "溫溫氣見春日暖，凜凜議論秋霜明。", "魯公拜相誰當筆，弟草兄制光如日。", "一家盛事今古稀，千載獨瞻門第屹。", "常時此瑞分爲三，朝論鼎立何巉巖。", "乾坤清氣有時合，合作星郎青似藍。", "中秋五日玉宇澄，非烟非霧朝盈庭。", "天上麒麟千載出，人間蟾桂一年輕。", "規模局度尤精粹，望見咸知宰相器。", "全閩飛最一年餘，丹鳳啣書九天至。", "知公文字如南豐，愛公德器文昭同。", "願公復取魯公位，斡補造化通洪濛。", "壽公滿滿稱霞觥，勳業長看雙鬢青。", "乞與芝蘭分玉砌，高歌此頌清風生。"]'),
('7de59e93-0740-483f-8479-71df08afce1d','句','徐璣','宋','宋诗','song-poetry','','[]','薤葉秀且聳，蘭香細而幽。',12,'全唐诗/poet.song.179000.json','["薤葉秀且聳，蘭香細而幽。"]'),
('5f66aa31-ee08-4428-a98e-423bbbf94ec3','宮詞  其一','楊皇后','宋','宋诗','song-poetry','','[]','瑞日曈矓散曉紅，乾元萬國珮丁東。',32,'全唐诗/poet.song.179000.json','["瑞日曈矓散曉紅，乾元萬國珮丁東。", "紫宸北使班纔退，百辟同趨德壽宮。"]'),
('421d6689-2305-4d47-bfe4-499f3fce9dab','宮詞  其二','楊皇后','宋','宋诗','song-poetry','','[]','元宵時雨賞宮梅，恭請光堯壽聖來。',32,'全唐诗/poet.song.179000.json','["元宵時雨賞宮梅，恭請光堯壽聖來。", "醉裏君王扶上輦，鑾輿半仗點燈回。"]'),
('882d025c-29e6-4020-a858-7a5a99787675','宮詞  其三','楊皇后','宋','宋诗','song-poetry','','[]','柳枝挾雨握新綠，桃蕊含風破小紅。',32,'全唐诗/poet.song.179000.json','["柳枝挾雨握新綠，桃蕊含風破小紅。", "天上春光偏得早，嵯峩宮殿五雲中。"]'),
('015fdb87-db81-4289-9ad5-c5507e9fcf86','宮詞  其四','楊皇后','宋','宋诗','song-poetry','','[]','春風淡淡水淙淙，携伴尋芳過小杠。',32,'全唐诗/poet.song.179000.json','["春風淡淡水淙淙，携伴尋芳過小杠。", "惱殺野塘閒送目，鴛鴦無數各雙雙。"]'),
('71df7a15-3d77-4468-83b6-3aa77fedacf3','宮詞  其五','楊皇后','宋','宋诗','song-poetry','','[]','溶溶太液碧波翻，雲外樓臺日月閑。',32,'全唐诗/poet.song.179000.json','["溶溶太液碧波翻，雲外樓臺日月閑。", "春到漢宮三十六，爲分和氣到人間。"]'),
('1365f96a-a670-4eb3-991e-d5f83cf46480','宮詞  其六','楊皇后','宋','宋诗','song-poetry','','[]','曉窗生白已鶑啼，啼在宮花第幾枝。',32,'全唐诗/poet.song.179000.json','["曉窗生白已鶑啼，啼在宮花第幾枝。", "煙斷獸爐香未絕，曲房朱戶夢回時。"]'),
('e98a2ce3-0489-4550-a22e-8110f8647821','宮詞  其七','楊皇后','宋','宋诗','song-poetry','','[]','剪剪輕風二月天，柳絲飄颺倍堪憐。',32,'全唐诗/poet.song.179000.json','["剪剪輕風二月天，柳絲飄颺倍堪憐。", "靜凭雕檻渾無事，細數穿花燕影偏。"]'),
('dd660520-e0f6-49e5-a0a5-36022e57246a','宮詞  其八','楊皇后','宋','宋诗','song-poetry','','[]','一簾小雨怯春寒，禁禦深沉白晝閑。',32,'全唐诗/poet.song.179000.json','["一簾小雨怯春寒，禁禦深沉白晝閑。", "滿地落花紅不掃，黄鸝枝上語綿蠻。"]'),
('97b10df9-356e-4ea7-9d1a-527fa1a0fa8a','宮詞  其九','楊皇后','宋','宋诗','song-poetry','','[]','上林花木正芳菲，內裏爭傳御製詞。',32,'全唐诗/poet.song.179000.json','["上林花木正芳菲，內裏爭傳御製詞。", "春賦新翻入宮調，美人羣唱捧瑶巵。"]'),
('3d23e28d-19a7-4147-8d2c-18f7b60e80bd','宮詞  其一○','楊皇后','宋','宋诗','song-poetry','','[]','海棠花裏奏琵琶，沉碧池邊醉九霞。',32,'全唐诗/poet.song.179000.json','["海棠花裏奏琵琶，沉碧池邊醉九霞。", "禁禦融融春日靜，五雲深護帝王家。"]'),
('22040e00-45e7-40c7-8e43-9b0eb610995a','宮詞  其一一','楊皇后','宋','宋诗','song-poetry','','[]','後院深沉景物幽，奇花名竹弄春柔。',32,'全唐诗/poet.song.179000.json','["後院深沉景物幽，奇花名竹弄春柔。", "翠華經歲無遊幸，多少亭臺廢不修。"]'),
('ba7aaa8c-4a0b-40e3-b638-e449ae2248fd','宮詞  其一二','楊皇后','宋','宋诗','song-poetry','','[]','天申聖節禮非常，躬率羣臣上壽觴。',32,'全唐诗/poet.song.179000.json','["天申聖節禮非常，躬率羣臣上壽觴。", "天子捧盤仍再拜，侍中宣達近龍床。"]'),
('426d133f-b694-4a08-940e-3fcc1572e258','宮詞  其一三','楊皇后','宋','宋诗','song-poetry','','[]','水殿鈎簾四面風，荷花簇錦照人紅。',32,'全唐诗/poet.song.179000.json','["水殿鈎簾四面風，荷花簇錦照人紅。", "吾皇一曲薰絃罷，萬俗泠泠解慍中。"]'),
