('29370145-c996-426e-8dd5-a6dc70027cd6','宮詞  其一五','楊皇后','宋','宋诗','song-poetry','','[]','薰風宮殿日長時，靜運天機一局棋。',32,'全唐诗/poet.song.179000.json','["薰風宮殿日長時，靜運天機一局棋。", "國手人人饒處著，須知聖算出新奇。"]'),
('f4e3df7d-8808-4c1c-9884-588d5dbaea5c','宮詞  其一六','楊皇后','宋','宋诗','song-poetry','','[]','宮殿鈎簾看水晶，時當三伏熾炎蒸。',32,'全唐诗/poet.song.179000.json','["宮殿鈎簾看水晶，時當三伏熾炎蒸。", "翰林學士知誰直，今日傳宣與賜冰。"]'),
('513096e8-f57a-427e-b067-ec2643b5084a','宮詞  其一七','楊皇后','宋','宋诗','song-poetry','','[]','雲影低涵柏子池，秋聲輕度萬年枝。',32,'全唐诗/poet.song.179000.json','["雲影低涵柏子池，秋聲輕度萬年枝。", "要知玉宇凉多少，正在觀書乙夜時。"]'),
('4bc10397-c1e6-405f-a37b-a7284751663a','宮詞  其一八','楊皇后','宋','宋诗','song-poetry','','[]','瑣窗宮漏滴銅壺，午夢驚回落井梧。',32,'全唐诗/poet.song.179000.json','["瑣窗宮漏滴銅壺，午夢驚回落井梧。", "風遞樂聲來玉宇，日移花影上金鋪。"]'),
('8ca3be1f-d856-418b-ae9b-103c82cb1fe5','宮詞  其一九','楊皇后','宋','宋诗','song-poetry','','[]','銀燭瑶觥競上元，□□午月正當軒。',32,'全唐诗/poet.song.179000.json','["銀燭瑶觥競上元，□□午月正當軒。", "棚頭忽喚歌新曲，宛轉餘音出紫垣。"]'),
('0a727be8-51d6-4d29-bf47-41396ce7126a','宮詞  其二○','楊皇后','宋','宋诗','song-poetry','','[]','迎春燕子尾纖纖，拂柳穿花掠翠簷。',32,'全唐诗/poet.song.179000.json','["迎春燕子尾纖纖，拂柳穿花掠翠簷。", "聞道蕊官三十六，美人爭爲捲珠簾。"]'),
('c2460b94-26b5-4c6a-8168-0285ab1091d9','宮詞  其二一','楊皇后','宋','宋诗','song-poetry','','[]','落絮濛濛立夏天，樓前槐樹影初圓。',32,'全唐诗/poet.song.179000.json','["落絮濛濛立夏天，樓前槐樹影初圓。", "傳聞紫殿深深處，別有薰風入舜絃。"]'),
('4cbd96b9-acbb-450c-92fc-63c77f24397f','宮詞  其二二','楊皇后','宋','宋诗','song-poetry','','["\u5199\u96ea", "\u51ac\u5929", "\u96ea"]','紫禁仙輿詰旦來，旌旗遥倚望春臺。',32,'全唐诗/poet.song.179000.json','["紫禁仙輿詰旦來，旌旗遥倚望春臺。", "不知庭霰今朝下，疑是林花昨夜開。"]'),
('61f54c66-cd77-4633-96d2-8f248a7f9572','宮詞  其二三','楊皇后','宋','宋诗','song-poetry','','[]','凉生水殿樂聲遊，釣得金鱗上御鈎。',32,'全唐诗/poet.song.179000.json','["凉生水殿樂聲遊，釣得金鱗上御鈎。", "聖德至仁元不殺，指揮皆放小池頭。"]'),
('a872c33c-31ee-4d43-ba9e-d33ede0c06f3','宮詞  其二四','楊皇后','宋','宋诗','song-poetry','','[]','凉秋結束鬭炎新，宣入毬場尚未明。',32,'全唐诗/poet.song.179000.json','["凉秋結束鬭炎新，宣入毬場尚未明。", "一朵紅雲黄蓋底，千官下馬起居聲。"]'),
('13fd14a8-4615-43d6-8885-84ea40950663','宮詞  其二五','楊皇后','宋','宋诗','song-poetry','','[]','秋高風動角弓鳴，臂徤常嫌斗力輕。',32,'全唐诗/poet.song.179000.json','["秋高風動角弓鳴，臂徤常嫌斗力輕。", "玉陛纔傳看御箭，中心雙中謝恩聲。"]'),
('16e64cc7-491d-43c4-88d9-0853430635ee','宮詞  其二六','楊皇后','宋','宋诗','song-poetry','','[]','思賢夢寢過商宗，右武崇儒帝道隆。',32,'全唐诗/poet.song.179000.json','["思賢夢寢過商宗，右武崇儒帝道隆。", "總覽權綱求治理，羣臣臧否疏屏風。"]'),
('937c2861-cf7f-42b4-b791-bdc202e024b2','宮詞  其二七','楊皇后','宋','宋诗','song-poetry','','[]','用人論理見宸衷，賞罰刑威合至公。',32,'全唐诗/poet.song.179000.json','["用人論理見宸衷，賞罰刑威合至公。", "天下監司二千石，姓名都在御屏中。"]'),
('dec60505-72c4-4467-b2f3-ba4ea29e28a9','宮詞  其二八','楊皇后','宋','宋诗','song-poetry','','[]','家傳筆法學光堯，聖草真行說兩朝。',32,'全唐诗/poet.song.179000.json','["家傳筆法學光堯，聖草真行說兩朝。", "天縱自然成一體，謾誇虎步與龍跳。"]'),
('25b62448-0525-4728-b34d-c957e33746ae','宮詞  其二九','楊皇后','宋','宋诗','song-poetry','','[]','泛索坤寧日一羊，自從正位控辭章。',32,'全唐诗/poet.song.179000.json','["泛索坤寧日一羊，自從正位控辭章。", "好生躬儉超千古，風化宮嬪只淡粧。"]'),
('4d51d6f4-7086-41c9-9b85-49f9fe4337c5','宮詞  其三○','楊皇后','宋','宋诗','song-poetry','','[]','蘭徑香銷玉輦蹤，梨花不肯負春風。',32,'全唐诗/poet.song.179000.json','["蘭徑香銷玉輦蹤，梨花不肯負春風。", "綠窗深鎖無人見，自碾硃砂養守宮。"]'),
('249c3fd6-ed51-4cf7-8fec-52e4e7d47875','宮詞  其三一','楊皇后','宋','宋诗','song-poetry','','[]','缺月流光入綺疏，金壺傳箭夢回初。',32,'全唐诗/poet.song.179000.json','["缺月流光入綺疏，金壺傳箭夢回初。", "秦臺綵鳳無消息，桂影空閑十二除。"]'),
('dda9dd89-638d-43ca-ae61-c76d54ebcc0c','宮詞  其三二','楊皇后','宋','宋诗','song-poetry','','[]','輦路青苔雨後深，銅魚雙鑰晝沉沉。',32,'全唐诗/poet.song.179000.json','["輦路青苔雨後深，銅魚雙鑰晝沉沉。", "詞臣還有相如在，不得當時買賦金。"]'),
('b1f00818-4721-496b-9b57-24e571314bba','宮詞  其三三','楊皇后','宋','宋诗','song-poetry','','[]','擊鞠由來豈作嬉，不忘鞍馬是神機。',32,'全唐诗/poet.song.179000.json','["擊鞠由來豈作嬉，不忘鞍馬是神機。", "牽韁絕尾施新巧，背打星毬一點飛。"]'),
('49b9fa81-fab0-4dde-a311-258b1478dd88','宮詞  其三四','楊皇后','宋','宋诗','song-poetry','','[]','黄鳥驚眠曙色開，慵梳鬟髻意徘徊。',32,'全唐诗/poet.song.179000.json','["黄鳥驚眠曙色開，慵梳鬟髻意徘徊。", "君王早御延英殿，頻喚宮人上直來。"]'),
