('8785bba7-05cd-415d-b6c6-c69569e46041','題馬和之畫四小景  其三','楊娃','宋','宋诗','song-poetry','','[]','清獻先生無一錢，故應琴鶴是家傳。',32,'全唐诗/poet.song.179000.json','["清獻先生無一錢，故應琴鶴是家傳。", "誰知默鼓無弦曲，時向珠宮舞幻仙。"]'),
('15fe4f26-ebc7-4f01-81f9-d49d76f97429','題馬和之畫四小景  其四','楊娃','宋','宋诗','song-poetry','','["\u751f\u6d3b", "\u7530\u56ed"]','雨洗東坡月色清，市人行盡野人行。',32,'全唐诗/poet.song.179000.json','["雨洗東坡月色清，市人行盡野人行。", "莫嫌犖确坡頭路，自愛鏗然曳枝聲。"]'),
('031e5bbf-c047-493b-b221-fe5d136b70e0','題趙伯驌畫','楊娃','宋','宋诗','song-poetry','','[]','蓮開宮沼年年盛，香染斑衣葉葉新。',32,'全唐诗/poet.song.179000.json','["蓮開宮沼年年盛，香染斑衣葉葉新。", "願借琴音奏清雅，薰風凉殿壽雙親。"]'),
('c2534876-9a5d-48fe-8a95-f98b9efa8f46','次韻梅中','汪晫','宋','宋诗','song-poetry','','[]','梅熟雨初過，虛堂枕簟凉。',48,'全唐诗/poet.song.179000.json','["梅熟雨初過，虛堂枕簟凉。", "心閒世自古，事簡日偏長。", "藕葉度清氣，蘭花留晚芳。", "正巾堪一笑，髮短自僧光。"]'),
('d56661a9-08f0-4d0a-9070-a1abd8b3786f','次韻戴顯之晚春夾溪閒行','汪晫','宋','宋诗','song-poetry','','[]','出郭知春晚，陰陰綠滿川。',51,'全唐诗/poet.song.179000.json','["出郭知春晚，陰陰綠滿川。", "小橋橫{木圼}杌，斜柳拂淪漣。", "風急低雙燕，林幽聒一鵑。", "酴醿破香蕊，孤艷殿羣妍。"]'),
('f5530c99-f71a-4270-8918-636ce1a836b2','次韻蓋簿賓春','汪晫','宋','宋诗','song-poetry','','[]','忽頒新曆日，春事到茅簷。',48,'全唐诗/poet.song.179000.json','["忽頒新曆日，春事到茅簷。", "心自丹如故，鬚應白又添。", "微風和拂面，小雨冷侵簾。", "酒竭妨春飲，新將齏甕醃。"]'),
('58229806-5a74-4282-8fa7-7e26b608cb55','次韻蓋簿初春郊行','汪晫','宋','宋诗','song-poetry','','[]','黯淡雲初斂，霏微雨復晴。',48,'全唐诗/poet.song.179000.json','["黯淡雲初斂，霏微雨復晴。", "燒痕回野色，禽語盡春聲。", "駃駃山泉溜，欣欣木葉榮。", "杖藜村店酒，清似好官清。"]'),
('20fcf56f-8ff5-4b9f-8151-2343ad842720','次韻落花','汪晫','宋','宋诗','song-poetry','','[]','新綠滿高樹，殘紅辭舊枝。',48,'全唐诗/poet.song.179000.json','["新綠滿高樹，殘紅辭舊枝。", "馬嵬留襪處，金谷墜樓時。", "巢燕銜香急，川魚弄纈遲。", "詩人無可恨，青子又垂垂。"]'),
('c82b7931-c4b0-4f2b-ab56-eed2591371da','城中春寒即事','汪晫','宋','宋诗','song-poetry','','[]','重來春又半，夢寐念歸期。',48,'全唐诗/poet.song.179000.json','["重來春又半，夢寐念歸期。", "山近衾裯薄，春寒鼓角悲。", "曉鐘風送遠，宿靄日開遲。", "客裏真寥落，愁添兩鬢絲。"]'),
('1e16b765-313d-4f0d-b704-6b35cf28ddc3','秋夕遣興','汪晫','宋','宋诗','song-poetry','','[]','秋月清如水，凉生善養堂。',48,'全唐诗/poet.song.179000.json','["秋月清如水，凉生善養堂。", "鵲驚梧葉墜，露壓稻花香。", "煨芋薦蛆白，開橙擘蟹黄。", "客來隨所有，此興不能忘。"]'),
('41ce6edb-1605-40ec-be62-8b6de0eeecb9','次韻李明甫追和蘇黄門鸂鶒池','汪晫','宋','宋诗','song-poetry','','[]','無穢水常浄，忘機鳥自馴。',48,'全唐诗/poet.song.179000.json','["無穢水常浄，忘機鳥自馴。", "重來圓宿夢，因省是前身。", "尤物遺靈在，珍毛薦瑞頻。", "何當還抱子，池上啄游鱗。"]'),
('c8f83987-ebb6-47f5-85c1-999dddfa96b9','次韻丁簿雜興  其一','汪晫','宋','宋诗','song-poetry','','[]','詩壇一何峻，尋盟休論且。',48,'全唐诗/poet.song.179000.json','["詩壇一何峻，尋盟休論且。", "弟子性嗜酒，白蓮許入社。", "寒水巫陽峽，暮日蒼梧野。", "大雅久不聞，今侯真作者。"]'),
('668e81ed-ac71-4881-8549-7bcf57a1d8a1','次韻丁簿雜興  其二','汪晫','宋','宋诗','song-poetry','','[]','宴坐讀侯詩，凜凜豎髮毛。',48,'全唐诗/poet.song.179000.json','["宴坐讀侯詩，凜凜豎髮毛。", "平實未是卑，秀爽非爲高。", "清如幽谷花，羞殺李與桃。", "無怨而有哀，請歌楚離騷。"]'),
('8f534497-4795-4217-8a0e-55c7d6e6fb57','次韻丁簿雜興  其三','汪晫','宋','宋诗','song-poetry','','[]','高士亦主簿，漫士可一笑。',48,'全唐诗/poet.song.179000.json','["高士亦主簿，漫士可一笑。", "輕雲出巖阿，皎月生海嶠。", "官曹無公事，老木有鶴叫。", "侯已詩道尊，時亦參衆妙。"]'),
('f284288b-a279-445e-807d-bcdb7fbd86a7','次韻丁簿雜興  其四','汪晫','宋','宋诗','song-poetry','','[]','侯家好兄弟，森森如立竹。',48,'全唐诗/poet.song.179000.json','["侯家好兄弟，森森如立竹。", "侯今白首去，乃復坐矮屋。", "要當振龍鬣，寧更淹驥足。", "吉人天相之，富貴在晚福。"]'),
('e37ba399-564e-4637-9545-13f9c95cdcbb','次韻丁簿雜興  其五','汪晫','宋','宋诗','song-poetry','','[]','祥鳳鳴高梧，𪉄鷃伏短籬。',48,'全唐诗/poet.song.179000.json','["祥鳳鳴高梧，𪉄鷃伏短籬。", "人行謹所趨，畏途或平逵。", "如飲鉢中水，冷暖能自知。", "我願歌考槃，侯遇亦未遲。"]'),
('a7d7a2fd-5ce2-4d1f-80b3-5318073c7d47','初夏同周同人與史尉登西園後山茅亭望遠周君有賦依韻奉和兼呈少府','汪晫','宋','宋诗','song-poetry','','[]','青山一登嘯，陡覺心胸別。',168,'全唐诗/poet.song.179000.json','["青山一登嘯，陡覺心胸別。", "飄飄襟袖寒，恍若御風列。", "汩沒塵埃中，紛紛亂如蠛。", "不期會佳人，成此兩奇絕。", "美哉周氏子，炯炯冰壺月。", "傾蓋便如故，何必素所愜。", "磊落史少府，丰姿瑩霜雪。", "真如汗血駒，才名籍天閲。", "抵掌同一笑，心悟口難說。", "向晚雨初霽，高柳新蟬咽。", "倚檻雲去來，不悞巾角折。", "揮翰有佳句，明珠眩雙睫。", "蹇予非少年，所作盡短拙。", "萬事等白鷗，波間自沒滅。"]'),
('eb940040-7580-45fe-bf16-c8a0475ca1e4','遊翠眉用蘇黄門子由韻','汪晫','宋','宋诗','song-poetry','','[]','黛拂蛾眉兩月彎，虛亭著與小三間。',64,'全唐诗/poet.song.179000.json','["黛拂蛾眉兩月彎，虛亭著與小三間。", "吾翁先見如樗里，此老遺思比峴山。", "千仞遠峰和我瘦，一庭芳草伴春閒。", "登臨涕落當年事，不見仙人玉雪顔。"]'),
('7d3c4cea-c9ca-402d-bf6f-6d6fa0578ec8','次韻王季雄初春','汪晫','宋','宋诗','song-poetry','','[]','春事年年興不窮，野塘冰泮雪初融。',64,'全唐诗/poet.song.179000.json','["春事年年興不窮，野塘冰泮雪初融。", "燒痕彷彿草萌綠，樹影扶疎梅萼紅。", "莫恨一生今老大，還知萬事本虛空。", "饑餐渴飲存吾道，尺雪今年賀歲豐。"]'),
('5ed25bbe-80e5-450e-b68c-5697e1043634','次韻處約兄春行用前韻','汪晫','宋','宋诗','song-poetry','','[]','老去而今技已窮，在人胸次要陶融。',64,'全唐诗/poet.song.179000.json','["老去而今技已窮，在人胸次要陶融。", "三盃村酒兄和弟，一歲春光綠換紅。", "兀坐悠悠閒度日，閉門咄咄靜書空。", "青山顧我多容態，影照清溪秀且豐。"]'),
('21e57063-22d1-4af3-bf23-fdb360486335','次韻胡益之初夏見懷','汪晫','宋','宋诗','song-poetry','','[]','自是胸中三斗塵，詩兵敢敵亞夫營。',64,'全唐诗/poet.song.179000.json','["自是胸中三斗塵，詩兵敢敵亞夫營。", "愁關老子兩肩瘦，春點榴花一樹明。", "雨向梅邊來處細，句從夜半得時清。", "方牀竹枕思君切，幸有吟筒話舊情。"]'),
('c8f0c118-399e-402d-b653-a19ef6732a29','過西園視豁然亭舊址景仰蘇黄門有感用其留題韻示五弟八弟','汪晫','宋','宋诗','song-poetry','','[]','西風落葉滿空山，懷古情悰每愴然。',64,'全唐诗/poet.song.179000.json','["西風落葉滿空山，懷古情悰每愴然。", "詩句尚傳人化鶴，危亭何在草生烟。", "披尋舊址營華構，追繼當時醉玉船。", "要爲故家復遺業，當知此舉合爲先。"]'),
('cc1f12b5-91ad-4d9e-aeab-c1a20b6b61ac','次韻胡約之秋興','汪晫','宋','宋诗','song-poetry','','[]','秋山排闥翠盈軒，似向高人伴酒尊。',64,'全唐诗/poet.song.179000.json','["秋山排闥翠盈軒，似向高人伴酒尊。", "桑葉一庭深不掃，菊花滿院靜無言。", "谷中景物隨時變，案上文書信手翻。", "恰得君詩吟未了，梧桐疎雨滴黄昏。"]'),
('1c03adcb-8b41-408d-b23b-4b45c520dd7f','用尊字韻寄胡約之','汪晫','宋','宋诗','song-poetry','','[]','芙蓉紅晚對高軒，何日論文共一尊。',64,'全唐诗/poet.song.179000.json','["芙蓉紅晚對高軒，何日論文共一尊。", "祇作古詩十九首，不消柱史五千言。", "一聲南鴈霜華重，連夜西風木葉翻。", "自嘆鬚眉今白盡，復愁友道更昏昏。"]'),
('fdb3fc88-4004-4fa2-8c6e-78e93e22e883','次韻呂仲見提幹題翠眉亭','汪晫','宋','宋诗','song-poetry','','[]','亭前詩板有人臨，公去知誰續好吟。',64,'全唐诗/poet.song.179000.json','["亭前詩板有人臨，公去知誰續好吟。", "忽有名人留七字，競傳高價值千金。", "曾扶諸老開皇極，終使微身墜衆陰。", "兩岫至今愁不展，此言應當老師心。"]'),
('99181bd3-d6bf-47ae-b8cf-ed4cd1bb93d7','次韻李明府上事初謁登源廟用蘇黄門韻見示','汪晫','宋','宋诗','song-poetry','','[]','緩引前訶度嶺巔，真祠猶鎮舊山川。',64,'全唐诗/poet.song.179000.json','["緩引前訶度嶺巔，真祠猶鎮舊山川。", "懸知幽德如存日，更有孤忠合老天。", "雙炷爐香祈一稔，兩詩題詠播千年。", "民安善政神應喜，桑蔭兒童犢背眠。"]'),
('a67269e3-b191-4b30-9703-06497f92f12d','即席次韻趙簿縣圃小集呈李明府','汪晫','宋','宋诗','song-poetry','','[]','管領賓僚破費春，座中著白是山人。',64,'全唐诗/poet.song.179000.json','["管領賓僚破費春，座中著白是山人。", "魚游淺綠心機熟，鶑訢殘紅句語新。", "老屋不嫌規制樸，長官最喜土風淳。", "滿園桃李成陰密，留取甘棠浣水濱。"]'),
('6e040d3e-7646-4861-926e-33543229ea63','無題','汪晫','宋','宋诗','song-poetry','','[]','農夫只合老山林，辜負時卿一寸心。',64,'全唐诗/poet.song.179000.json','["農夫只合老山林，辜負時卿一寸心。", "老矣不堪持手板，死時何用覆斜衾。", "有人稱善名非細，對客無慚樂最深。", "回首暮雲天黯淡，誰能更聽伯牙琴。"]'),
('0a46a10a-4389-469a-b0a9-6a08a83cb17d','次韻李明府追和蘇黄門鸂鶒池','汪晫','宋','宋诗','song-poetry','','[]','池上先生詩句香，得公詩句更揄揚。',64,'全唐诗/poet.song.179000.json','["池上先生詩句香，得公詩句更揄揚。", "精神相對陳圭瓚，意氣潜交冶鏌將。", "賢令舊容老文學，山農今見謫仙郎。", "百年剩喜風流續，未有名禽首屢昂。"]'),
('2a3fcc11-5d4e-4c89-a0b7-9fc19b222f9d','次韻春愁','汪晫','宋','宋诗','song-poetry','','[]','風林弄影舞婆娑，水漫池塘綠皺波。',64,'全唐诗/poet.song.179000.json','["風林弄影舞婆娑，水漫池塘綠皺波。", "天上誰人待金馬，人間何路出銅駝。", "千年史冊亂居半，百日春光晴不多。", "飛絮落花還病酒，門前佳客倦相過。"]'),
('dfd0b8c5-75cc-4fcf-9de4-4b7d0732b320','次韻葉子真賢良留題登源先廟','汪晫','宋','宋诗','song-poetry','','[]','文皇當日伐遼東，授鑰忠勳留禁中。',64,'全唐诗/poet.song.179000.json','["文皇當日伐遼東，授鑰忠勳留禁中。", "違命加誣非信史，新詩昭雪有奇功。", "陰兵猶可殲凶悖，甘澤還能作歲豐。", "他日或提遷固筆，刪修訂實望研窮。"]'),
('610c57ad-0f0b-4839-ab2e-1dd4fa833cf2','次韻環谷即事','汪晫','宋','宋诗','song-poetry','','[]','本是偷閒擇一枝，靜中此樂有誰知。',64,'全唐诗/poet.song.179000.json','["本是偷閒擇一枝，靜中此樂有誰知。", "山光照座年年在，世事於人日日非。", "春研有詩吟即事，夜燈無夢到相思。", "漢陰老子機何有，禪病今來減带圍。"]'),
('5b184b2d-663d-4811-9716-543258197d86','九日拜大兄墳','汪晫','宋','宋诗','song-poetry','','[]','携家松底酹蝦蟆，椒荔豚肩薦菊芽。',64,'全唐诗/poet.song.179000.json','["携家松底酹蝦蟆，椒荔豚肩薦菊芽。", "吾父洲中無橘樹，與兄庭下有荆花。", "和羹莫遂箋邊讓，破帽無能落孟嘉。", "衰老傷懷淚痕冷，年來鬚鬢白多些。"]'),
('a0706d32-621b-44fc-ab1e-1f9ba633970e','次韻朱同人携妓見訪留題','汪晫','宋','宋诗','song-poetry','','[]','行過晴溪烏桕彎，清漪猶自照蒼顔。',64,'全唐诗/poet.song.179000.json','["行過晴溪烏桕彎，清漪猶自照蒼顔。", "□□□□□□□，舉酒欣然得綠鬟。", "魚爲知機潛別浦，蘭因避俗住空山。", "老夫自覺無多事，且喜賓朋時往還。"]'),
('6e639534-7b88-423b-bfd3-4ac1b863f480','靜觀堂十偈  其一','汪晫','宋','宋诗','song-poetry','','[]','靜觀打透兩重關，無靜無觀總一般。',32,'全唐诗/poet.song.179000.json','["靜觀打透兩重關，無靜無觀總一般。", "須信靜時非境靜，從知觀處是心觀。"]'),
('4e73bc40-747a-4bfd-b133-65ded8305df2','靜觀堂十偈  其二','汪晫','宋','宋诗','song-poetry','','[]','一間虛室自安然，何必求仙更問禪。',32,'全唐诗/poet.song.179000.json','["一間虛室自安然，何必求仙更問禪。", "儘日焚香閉門坐，饑來喫飯困來眠。"]'),
('80d2fda7-a6c5-4c91-aa13-3357ea4b4369','靜觀堂十偈  其三','汪晫','宋','宋诗','song-poetry','','[]','萬緣一息絲不掛，一箇閒身煞瀟灑。',32,'全唐诗/poet.song.179000.json','["萬緣一息絲不掛，一箇閒身煞瀟灑。", "靜中有味淡如如，啞子得夢難爲話。"]'),
('ae6b5d08-30d6-423b-8b5a-3a3ac02a9d2c','靜觀堂十偈  其四','汪晫','宋','宋诗','song-poetry','','[]','我無官守無言責，自倚欄干時一拍。',32,'全唐诗/poet.song.179000.json','["我無官守無言責，自倚欄干時一拍。", "只因冷眼看破來，笑殺時人空擘畫。"]'),
('a12c08a4-24ed-4331-93db-258d48a71fc0','靜觀堂十偈  其五','汪晫','宋','宋诗','song-poetry','','[]','東風萬物皆舒暢，野色溪光無盡藏。',32,'全唐诗/poet.song.179000.json','["東風萬物皆舒暢，野色溪光無盡藏。", "誰喚春來春不知，草自青青花自放。"]'),
('15ee9e8d-8577-4161-85fc-e7d0010d49f8','靜觀堂十偈  其六','汪晫','宋','宋诗','song-poetry','','[]','春去人間日正長，天工催促綠陰忙。',32,'全唐诗/poet.song.179000.json','["春去人間日正長，天工催促綠陰忙。", "古槐高柳爭新意，自是無人知底凉。"]'),
('70abe5d6-11bc-423f-8e64-2cfc5b22b60e','靜觀堂十偈  其七','汪晫','宋','宋诗','song-poetry','','[]','長空一望如水碧，泉澗幽幽風淅淅。',32,'全唐诗/poet.song.179000.json','["長空一望如水碧，泉澗幽幽風淅淅。", "驚人暑退寒漸生，蓼染春紅映素壁。"]'),
('b4a428b4-f91e-47e8-8e46-fd6fc0ed25d9','靜觀堂十偈  其八','汪晫','宋','宋诗','song-poetry','','[]','香到梅梢歲又還，老天春事不曾閒。',32,'全唐诗/poet.song.179000.json','["香到梅梢歲又還，老天春事不曾閒。", "酸風凍雪侵重戶，僵卧長松獨恃頑。"]'),
('b1b005ef-cc3f-4b80-acfd-d0fdb17b7afc','靜觀堂十偈  其九','汪晫','宋','宋诗','song-poetry','','[]','有時檢點舊閒遊，出岫行雲野渡舟。',32,'全唐诗/poet.song.179000.json','["有時檢點舊閒遊，出岫行雲野渡舟。", "驀地靜中消息好，夕陽西下水東流。"]'),
('83eae12b-04c9-44fc-a197-adce0040a538','贈天竺僧','汪晫','宋','宋诗','song-poetry','','[]','衲被蒙頭付自然，何須八棒十三禪。',32,'全唐诗/poet.song.179000.json','["衲被蒙頭付自然，何須八棒十三禪。", "數聲啼鳥青山外，驚起幽窗一覺眠。"]'),
('782a7368-db8b-446f-a0b8-969fa6652966','柳','汪晫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','淡黄初弄正纖柔，便向東風舞不休。',32,'全唐诗/poet.song.179000.json','["淡黄初弄正纖柔，便向東風舞不休。", "猶記西湖相識舊，只今縷縷是春愁。"]'),
('451d519d-1ffe-47f2-8b32-78eb5b48104b','復陰','汪晫','宋','宋诗','song-poetry','','[]','雲鎖浮丘六六山，東風又作夜來寒。',32,'全唐诗/poet.song.179000.json','["雲鎖浮丘六六山，東風又作夜來寒。", "枝間杏蕊開還禁，陌上春泥滑未乾。"]'),
('49380766-4423-420f-9f43-234d815b3099','環谷初夏','汪晫','宋','宋诗','song-poetry','','[]','荷錢新綠點池塘，竹枕方牀午夢長。',32,'全唐诗/poet.song.179000.json','["荷錢新綠點池塘，竹枕方牀午夢長。", "山鳥數聲簾影寂，松窗風遞煮茶香。"]'),
('c76b5c49-4e2c-470f-b3db-06c18afb7966','寫真','汪晫','宋','宋诗','song-poetry','','[]','鬚眉數得莖莖古，果是環谷山中人。',32,'全唐诗/poet.song.179000.json','["鬚眉數得莖莖古，果是環谷山中人。", "道眼靜觀付一笑，借問兩箇若箇真。"]'),
('581edcca-1419-4fc1-93be-f36ead396b5a','景蘇堂新復上李明府','汪晫','宋','宋诗','song-poetry','','[]','先生德政殊清明，斯堂故以景蘇名。',128,'全唐诗/poet.song.179000.json','["先生德政殊清明，斯堂故以景蘇名。", "可憐向苦糟麯厄，東撐西柱懸河傾。", "一從公來忽嗟嘆，不日雲斤還舊觀。", "敗棟宅鼠壁篆蝸，湧翠流光復輝煥。", "坐想岷峨遠山碧，先生已矣遺陳迹。", "華陽三十六篇詩，今日拂塵炯全璧。", "自來蘇李兩名家，斯堂二賢愈光華。", "看公了却此縣債，步武先生雲路快。"]'),
('3df45261-9a12-4cf4-abdc-1355552d413e','某衰年未了初度復臨伏辱時賢載酒爲壽且揮灑佳章增光枯朽即席次韻見謝意','汪晫','宋','宋诗','song-poetry','','[]','白髮衰翁歲已老，惜花有心猶起早。',144,'全唐诗/poet.song.179000.json','["白髮衰翁歲已老，惜花有心猶起早。", "無事曉窗但高眠，閉關苔青門不掃。", "和靖風流屋後梅，濂溪氣味窗前草。", "近與鄒軻同窠臼，亦欲集義以養浩。", "不解吟詩著書冊，自愛嚴君平一箇。", "無復求仙事老聃，寧更尋禪參達磨。", "皇天見憐尚不死，牽率時賢持酒賀。", "不才自當明主棄，非敢櫝玉爲懷寶。", "致君堯舜須公等，山中槁夫勿多道。"]'),
('bbca6aff-21e1-4bb7-b14c-a8ae6643928d','感興四章章五句  其一','汪晫','宋','宋诗','song-poetry','','[]','暑往寒來如電泡，年年門外閒花草，世事紛紛自顛倒。',40,'全唐诗/poet.song.179000.json','["暑往寒來如電泡，年年門外閒花草，世事紛紛自顛倒。", "青山眼底最多情，日日向人渾不老。"]'),
('a79bca10-6e9a-41f4-ac58-e0fdd1fb4ebc','感興四章章五句  其二','汪晫','宋','宋诗','song-poetry','','[]','膠擾浮生事若麻，世路崎嶇易覆車，爭如清浄山人家。',40,'全唐诗/poet.song.179000.json','["膠擾浮生事若麻，世路崎嶇易覆車，爭如清浄山人家。", "靜觀撫掌付一笑，出戶䔩䔩飛松花。"]'),
('824cdf39-0222-42ce-b90e-8c9da267867b','感興四章章五句  其三','汪晫','宋','宋诗','song-poetry','','[]','一樹雪花白如玉，辛夷爲車荷爲屋，閒中享此亦清福。',40,'全唐诗/poet.song.179000.json','["一樹雪花白如玉，辛夷爲車荷爲屋，閒中享此亦清福。", "一雙沙禽竹上啼，對客取琴彈一曲。"]'),
('30f94645-1ba8-44be-8029-8bac16a45a66','感興四章章五句  其四','汪晫','宋','宋诗','song-poetry','','[]','坐讀南華一卷經，富貴百年如郵亭，人生怒癭空成瓶。',40,'全唐诗/poet.song.179000.json','["坐讀南華一卷經，富貴百年如郵亭，人生怒癭空成瓶。", "香爐縷烟風浩蕩，白鳥點破前山青。"]'),
('f7e0ad5a-524c-4a23-8344-d3388dbaa1d7','句  其一','汪晫','宋','宋诗','song-poetry','','[]','山寒杏未花。',6,'全唐诗/poet.song.179000.json','["山寒杏未花。"]'),
('7e146f06-fa08-433b-85ed-3a8f341a016d','句  其二','汪晫','宋','宋诗','song-poetry','','[]','滅燭閔蛾傷。',6,'全唐诗/poet.song.179000.json','["滅燭閔蛾傷。"]'),
('db7acac6-a381-442b-9c3c-7c16c937321b','句  其三','汪晫','宋','宋诗','song-poetry','','[]','梨花院落春宵短。',8,'全唐诗/poet.song.179000.json','["梨花院落春宵短。"]'),
('f115df3d-d891-4780-b6a9-6e23e49272c3','句  其四','汪晫','宋','宋诗','song-poetry','','[]','片片飛紅已謝春，紅移榴蕊更精神。',16,'全唐诗/poet.song.179000.json','["片片飛紅已謝春，紅移榴蕊更精神。"]'),
('cff49ea4-579f-4018-93cd-bf11cb97a047','偈頌一百零一首  其一','釋慧性','宋','宋诗','song-poetry','','[]','萬疊峯巒秀，清虛杳靄間。',24,'全唐诗/poet.song.179000.json','["萬疊峯巒秀，清虛杳靄間。", "跨門一句子，擬議隔重關。"]'),
('6a211848-9e80-4b21-a087-ab839f213865','偈頌一百零一首  其二','釋慧性','宋','宋诗','song-poetry','','[]','指天指地，有甚巴鼻。',34,'全唐诗/poet.song.179000.json','["指天指地，有甚巴鼻。", "目顧四方，不知失利。", "累及後代兒孫，以此遞相鈍置。"]'),
('0027b97e-de36-464c-a75d-0f3f2d61ed69','偈頌一百零一首  其三','釋慧性','宋','宋诗','song-poetry','','[]','電激雷奔，以毒攻毒。',36,'全唐诗/poet.song.179000.json','["電激雷奔，以毒攻毒。", "撒土拋沙，拗直作曲。", "箇裏翻身控角弓，誰能背手抽金鏃。"]'),
('5672338d-3b65-406f-ad2f-d712fdfc90e9','偈頌一百零一首  其四','釋慧性','宋','宋诗','song-poetry','','[]','不知立處高多少，回頭四顧白雲低。',32,'全唐诗/poet.song.179000.json','["不知立處高多少，回頭四顧白雲低。", "等閑移步毗盧頂，拽轉南辰安向西。"]'),
('d70c9e61-407d-4d55-b3d4-7e3a438dbbc0','偈頌一百零一首  其五','釋慧性','宋','宋诗','song-poetry','','[]','要入牯牛隊，還披水牯皮。',24,'全唐诗/poet.song.179000.json','["要入牯牛隊，還披水牯皮。", "全身行異類，拽杷又牽犁。"]'),
('fc2f0579-013b-4beb-b00a-0144d4ec98b6','偈頌一百零一首  其六','釋慧性','宋','宋诗','song-poetry','','[]','行盡迢迢路，無山不是家。',24,'全唐诗/poet.song.179000.json','["行盡迢迢路，無山不是家。", "跨門一句子，擬議隔天涯。"]'),
('19ab21eb-307d-48c3-a6fa-e8d1f729b87a','偈頌一百零一首  其七','釋慧性','宋','宋诗','song-poetry','','[]','有語中無語，達磨九年空面壁。',36,'全唐诗/poet.song.179000.json','["有語中無語，達磨九年空面壁。", "無語中有語，空生巖畔花狼藉。", "南斗八，北斗七。"]'),
('c1ca0ac3-adf6-4431-b2b2-645c8683bdc3','偈頌一百零一首  其八','釋慧性','宋','宋诗','song-poetry','','[]','啞却我口禿我舌，明眼衲僧難辨別。',32,'全唐诗/poet.song.179000.json','["啞却我口禿我舌，明眼衲僧難辨別。", "今朝撒向諸人前，須彌燈王笑不徹。"]'),
('a7ec0309-05bd-4c63-a931-6f530b946ecd','偈頌一百零一首  其九','釋慧性','宋','宋诗','song-poetry','','[]','天寒日短，三平二滿。',20,'全唐诗/poet.song.179000.json','["天寒日短，三平二滿。", "虎咬大蟲，雄鷄生卵。"]'),
('06297144-a116-4458-bb7c-91ca9da4a63b','偈頌一百零一首  其一○','釋慧性','宋','宋诗','song-poetry','','[]','言發非聲，舌頭無骨。',20,'全唐诗/poet.song.179000.json','["言發非聲，舌頭無骨。", "色前不物，狐狸戀窟。"]'),
('8098d88c-a1c6-4f68-9df6-9c915178c206','偈頌一百零一首  其一一','釋慧性','宋','宋诗','song-poetry','','[]','新梅雪裏依稀拆，愛日窗前迤邐長。',48,'全唐诗/poet.song.179000.json','["新梅雪裏依稀拆，愛日窗前迤邐長。", "漏泄東君好消息，分明遍界不能藏。", "但得到家田地穩，更無佛法可商量。"]'),
('bcafa2e5-c42c-44bb-8e2b-5c343af56ec5','偈頌一百零一首  其一二','釋慧性','宋','宋诗','song-poetry','','[]','烏牙絕頂，結制安居。',32,'全唐诗/poet.song.179000.json','["烏牙絕頂，結制安居。", "包羅萬有，吞却十虛。", "切忌從它覓，迢迢與我疎。"]'),
('dd2ae430-c142-42d5-b8c1-430788fd3824','偈頌一百零一首  其一三','釋慧性','宋','宋诗','song-poetry','','[]','往來無間，動靜一源。',50,'全唐诗/poet.song.179000.json','["往來無間，動靜一源。", "瞥然而往，瞥然而還。", "大方無內無外，管甚新年舊年。", "歸來偃卧青松下，只這些兒妙不傳。"]'),
('f45cecfe-23da-48ce-8288-717295c7faca','偈頌一百零一首  其一四','釋慧性','宋','宋诗','song-poetry','','[]','方挹新春，又迎朱夏。',58,'全唐诗/poet.song.179000.json','["方挹新春，又迎朱夏。", "山不爲高，水不爲下。", "梅雨連綿，虛空貼卦。", "浸爛石烏龜，黄梅添話欛。", "烏牙峯頂浪滔天，犀牛扇子增高價。"]'),
('eac791d1-677c-4440-87ee-519f04782829','偈頌一百零一首  其一五','釋慧性','宋','宋诗','song-poetry','','[]','秋風清，秋月白。',56,'全唐诗/poet.song.179000.json','["秋風清，秋月白。", "雁過長空，蟬噪庭柏。", "踢出鐵崐崘，大機要頓發。", "好肉剜瘡，覻著即瞎。", "隔山人唱太平歌，元是胡笳十八拍。"]'),
('e0827e58-e0f9-48ee-ab43-fc48756ec9a3','偈頌一百零一首  其一六','釋慧性','宋','宋诗','song-poetry','','[]','爽氣生襟袂，清飈襲四維。',40,'全唐诗/poet.song.179000.json','["爽氣生襟袂，清飈襲四維。", "白雲抱幽石，冷淡更清奇。", "玲瓏八面自回合，峭峻一方誰敢窺。"]'),
('24f4c317-b72e-4fab-808a-7e82d87a984d','偈頌一百零一首  其一七','釋慧性','宋','宋诗','song-poetry','','[]','毒蛇頭上能揩痒，正是吾家跳竈兒。',48,'全唐诗/poet.song.179000.json','["毒蛇頭上能揩痒，正是吾家跳竈兒。", "竊得這些窮伎倆，白拈手裏覓便宜。", "萬仞崖頭獨足立，頭長三尺知是誰。"]'),
('d049dfe2-9cb9-496e-bf59-d2058eb8bb1f','偈頌一百零一首  其一八','釋慧性','宋','宋诗','song-poetry','','[]','十五日已前，一冬二冬，叉手當胸。',56,'全唐诗/poet.song.179000.json','["十五日已前，一冬二冬，叉手當胸。", "十五日已後，背手抽金鏃，翻身控角弓。", "正當十五日，風從虎兮雲從龍，擡眸鷂子過遼東。"]'),
('e981af8b-20b8-4b07-9ec0-6cf11982dea8','偈頌一百零一首  其一九','釋慧性','宋','宋诗','song-poetry','','[]','春行萬國春無跡，臘雪消殘始見功。',38,'全唐诗/poet.song.179000.json','["春行萬國春無跡，臘雪消殘始見功。", "頭頭應現，處處流通。", "木馬泥牛吼，花柳撼春風。"]'),
('8db8b57b-688c-44f2-b258-4c18ac922bbe','偈頌一百零一首  其二○','釋慧性','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','春山青，春水綠。',32,'全唐诗/poet.song.179000.json','["春山青，春水綠。", "草茸茸，花簇簇。", "若能喪盡目前機，便見廬山真面目。"]'),
('1efbeb5c-593b-4a1f-b99d-e1599c838af6','偈頌一百零一首  其二一','釋慧性','宋','宋诗','song-poetry','','[]','元宵正月半，是處金蓮現。',34,'全唐诗/poet.song.179000.json','["元宵正月半，是處金蓮現。", "貪看燈明佛，蹉過新羅箭。", "閃電光中，聊通一線。"]'),
('e38fdda8-392a-49b0-9c5d-c507002836ea','偈頌一百零一首  其二二','釋慧性','宋','宋诗','song-poetry','','[]','法社棟梁，叢林綱紀。',56,'全唐诗/poet.song.179000.json','["法社棟梁，叢林綱紀。", "全殺全活，建立宗旨。", "雙放雙收，總在這裏。", "虎嘯風生，龍吟霧起。", "大家扶起破砂盆，無限清風來未已。"]'),
('af4fa9bb-a01b-4414-b57a-2a3afc9400b5','偈頌一百零一首  其二三','釋慧性','宋','宋诗','song-poetry','','[]','句中句，絕露布。',16,'全唐诗/poet.song.179000.json','["句中句，絕露布。", "閃電裏，分緇素。"]'),
('a0b0af49-ffda-42b1-853a-6f828ce43df7','偈頌一百零一首  其二四','釋慧性','宋','宋诗','song-poetry','','[]','向上一路滑，壁立萬仞嶮。',48,'全唐诗/poet.song.179000.json','["向上一路滑，壁立萬仞嶮。", "石火電光鈍，定乾坤句錯。", "水牯牛常甘水草，麒麟只有一隻角，千手大悲難摸索。"]'),
('f81774d6-51da-4ba6-9ab2-bea2ce1518f4','偈頌一百零一首  其二五','釋慧性','宋','宋诗','song-poetry','','[]','主中賓，賓中主，南山大蟲元是虎。',40,'全唐诗/poet.song.179000.json','["主中賓，賓中主，南山大蟲元是虎。", "踢起眉毛著眼看，閃電光中急薦取，發機須是千鈞弩。"]'),
('a6e1ea73-60ff-4eb6-acad-457e4ad6fe42','偈頌一百零一首  其二六','釋慧性','宋','宋诗','song-poetry','','[]','知有底人，眼中著屑。',36,'全唐诗/poet.song.179000.json','["知有底人，眼中著屑。", "盡底掀翻，只得一橛。", "堪笑巴陵老古錐，解道銀椀裏盛雪。"]'),
('8d867753-e08b-42d1-87b1-bbc7d895699f','偈頌一百零一首  其二七','釋慧性','宋','宋诗','song-poetry','','[]','歸宗見成行貨，別無單傳心要。',58,'全唐诗/poet.song.179000.json','["歸宗見成行貨，別無單傳心要。", "二時展鉢開單，逐日痾屎送尿。", "饑餐渴飲一般，露柱燈籠大笑。", "毗婆尸佛早留心，直至而今不得妙。"]'),
('24075670-da25-4a8a-a561-cd920dcdda54','偈頌一百零一首  其二八','釋慧性','宋','宋诗','song-poetry','','[]','風蕭蕭兮疎林葉落，月皎皎兮虎嘯猿啼。',46,'全唐诗/poet.song.179000.json','["風蕭蕭兮疎林葉落，月皎皎兮虎嘯猿啼。", "或聞或見，或悟或迷。", "會與不會，脫體全提，鼻孔元是向下垂。"]'),
('c1671dea-e474-4dc7-b6e4-7659b6c1a4c2','偈頌一百零一首  其二九','釋慧性','宋','宋诗','song-poetry','','[]','一葉落，天下秋。',46,'全唐诗/poet.song.179000.json','["一葉落，天下秋。", "一塵起，大地收。", "明明祖師意，明明百草頭。", "相頭買帽，看樓打樓，更嫌何處不風流。"]'),
('12b1975f-4e8b-425c-8bdb-3f40134d8877','偈頌一百零一首  其三○','釋慧性','宋','宋诗','song-poetry','','[]','秋色連天浄，秋花滿地香。',24,'全唐诗/poet.song.179000.json','["秋色連天浄，秋花滿地香。", "圓通門大啟，切忌錯商量。"]'),
('f148483d-e62e-4825-ba88-d38ea71a8ffe','偈頌一百零一首  其三一','釋慧性','宋','宋诗','song-poetry','','[]','丹霞燒木佛，院主眉鬚落。',42,'全唐诗/poet.song.179000.json','["丹霞燒木佛，院主眉鬚落。", "兩箇無孔鐵鎚，彼此將錯就錯。", "焦磚打著連底凍，笑它普化摇鈴鐸。"]'),
('f719ea64-977a-4d38-a9f3-95cb876fc198','偈頌一百零一首  其三二','釋慧性','宋','宋诗','song-poetry','','[]','雪覆千山，孤峯不白。',46,'全唐诗/poet.song.179000.json','["雪覆千山，孤峯不白。", "突出難辨，覻著則瞎。", "鐵樹花開，冰河焰發。", "不萌枝上月三更，切忌龍門遭點額。"]'),
('2397cf35-7f6a-430e-9f36-17bd8e31e79a','偈頌一百零一首  其三三','釋慧性','宋','宋诗','song-poetry','','[]','摇唇鼓舌，展事投機。',40,'全唐诗/poet.song.179000.json','["摇唇鼓舌，展事投機。", "千佛出世，不通懺悔。", "焦巴焦巴，有葉無丫。", "長天秋水，孤鶩落霞。"]'),
('751b862f-4d8b-4139-bc6e-f99e222cc83d','偈頌一百零一首  其三四','釋慧性','宋','宋诗','song-poetry','','[]','歸宗無法可商量，獨掇單提不覆藏。',32,'全唐诗/poet.song.179000.json','["歸宗無法可商量，獨掇單提不覆藏。", "有問西來端的意，天寒日短夜偏長。"]'),
('e201ddff-27af-4cb6-9663-ddcd2e631486','偈頌一百零一首  其三五','釋慧性','宋','宋诗','song-poetry','','[]','指天指地獨稱尊，攪動乾坤海嶽昏。',32,'全唐诗/poet.song.179000.json','["指天指地獨稱尊，攪動乾坤海嶽昏。", "自從賺殺人無數，直至而今無腦門。"]'),
('73b825d1-928b-425e-9058-77b54e7c804c','偈頌一百零一首  其三六','釋慧性','宋','宋诗','song-poetry','','[]','雨過長空，簷頭滴滴。',32,'全唐诗/poet.song.179000.json','["雨過長空，簷頭滴滴。", "覿面相呈，人信不及。", "信得及，萬古長空元不濕。"]'),
('6cb57cae-b9ac-4689-9aad-ff4f2e81f6b0','偈頌一百零一首  其三七','釋慧性','宋','宋诗','song-poetry','','[]','一即一切，一切即一。',46,'全唐诗/poet.song.179000.json','["一即一切，一切即一。", "拈青玉峽，向焦螟眼中。", "撮大地來，如粟米粒。", "會則事同一家，不會則知我受屈。"]'),
('2a4c551d-a8e9-4087-9215-dd6a7c401394','偈頌一百零一首  其三八','釋慧性','宋','宋诗','song-poetry','','[]','獨標萬象，物外宣揚。',20,'全唐诗/poet.song.179000.json','["獨標萬象，物外宣揚。", "天長地久，地久天長。"]'),
('a3009103-b0fb-45d1-8462-bf3a47448401','偈頌一百零一首  其三九','釋慧性','宋','宋诗','song-poetry','','[]','無作無爲，無說無示。',36,'全唐诗/poet.song.179000.json','["無作無爲，無說無示。", "可以濟群，類統萬邦。", "同六虛，融三際，此是吾家第一義。"]'),
('88e6202d-a98e-42d9-83ed-637180a8bdb0','偈頌一百零一首  其四○','釋慧性','宋','宋诗','song-poetry','','[]','瀑布懸崖落半空，等閑平步廣寒宮。',32,'全唐诗/poet.song.179000.json','["瀑布懸崖落半空，等閑平步廣寒宮。", "乘時坐斷孤峯頂，千聖從教立下風。"]'),
('f99f77c2-5647-4f9f-a5c1-015bf90333f8','偈頌一百零一首  其四一','釋慧性','宋','宋诗','song-poetry','','[]','祖禰不了，兒孫遭累。',34,'全唐诗/poet.song.179000.json','["祖禰不了，兒孫遭累。", "祝著磕著，無處回避。", "不辭禮拜燒香，也要遞相鈍置。"]'),
('abdcc364-c774-4849-873d-955dbaab2a62','偈頌一百零一首  其四二','釋慧性','宋','宋诗','song-poetry','','[]','作家爐鞴，本分鉗鎚。',26,'全唐诗/poet.song.179000.json','["作家爐鞴，本分鉗鎚。", "不用埋兵施陷虎，白拈手裏覓便宜。"]'),
('fbb05a28-b63c-4f08-8db0-6e12b1c9fa9d','偈頌一百零一首  其四三','釋慧性','宋','宋诗','song-poetry','','[]','喝散白雲，穿開碧落。',22,'全唐诗/poet.song.179000.json','["喝散白雲，穿開碧落。", "一步闊一步，一著高一著。"]'),
('488c6776-edcd-4fdf-a95e-a4f32b018add','偈頌一百零一首  其四四','釋慧性','宋','宋诗','song-poetry','','[]','未舉先知孰與論，掀騰海嶽動乾坤。',32,'全唐诗/poet.song.179000.json','["未舉先知孰與論，掀騰海嶽動乾坤。", "嶮崖句裏翻身轉，盤走珠兮珠走盤。"]'),
('7f346fc3-4769-47bb-8ff9-821252b9fa3c','偈頌一百零一首  其四五','釋慧性','宋','宋诗','song-poetry','','[]','一真含法界，大用等虛空。',40,'全唐诗/poet.song.179000.json','["一真含法界，大用等虛空。", "千祥如霧集，萬善若雲臻。", "用祝吾皇無量壽，天高無極地無窮。"]'),
('919a1144-eb36-4761-8474-cb35b2eccbbe','偈頌一百零一首  其四六','釋慧性','宋','宋诗','song-poetry','','[]','郊原雨過，春日熙熙。',44,'全唐诗/poet.song.179000.json','["郊原雨過，春日熙熙。", "桃紅李白，發最上機。", "啞却口，落盡眉。", "就中一曲江南好，蘆管迎風撩亂吹。"]'),
('5df11f48-b8d7-4514-a495-9527f0cdae53','偈頌一百零一首  其四七','釋慧性','宋','宋诗','song-poetry','','[]','聲前一句，十方顯露。',20,'全唐诗/poet.song.179000.json','["聲前一句，十方顯露。", "佛祖不知，衲僧罔措。"]'),
('7a7301bf-1c31-4400-8614-1b821a72a7ad','偈頌一百零一首  其四八','釋慧性','宋','宋诗','song-poetry','','[]','萬壑千巖，雲霞鎖霧。',32,'全唐诗/poet.song.179000.json','["萬壑千巖，雲霞鎖霧。", "洞然明白，覿面分付。", "鴈影落寒潭，孤舟橫野渡。"]'),
('f86f225c-854f-4eb2-9198-423adc2c2002','偈頌一百零一首  其四九','釋慧性','宋','宋诗','song-poetry','','[]','毗盧師，法身主，縱奪臨機些子許。',32,'全唐诗/poet.song.179000.json','["毗盧師，法身主，縱奪臨機些子許。", "目前分付與阿誰，踢起眉毛急薦取。"]'),
('701ce6b2-f756-4e96-8731-30e1b643fa15','偈頌一百零一首  其五○','釋慧性','宋','宋诗','song-poetry','','[]','去聖時遥，人多懈怠。',61,'全唐诗/poet.song.179000.json','["去聖時遥，人多懈怠。", "逆則生嗔，順則生愛。", "不嗔不愛，東海剪刀，西番布袋。", "解脫門頭緊著關，休誇鋪席無人買。", "腦後見腮，和贓捉敗。"]'),
('3c247345-889c-4470-b049-2d32eba88571','偈頌一百零一首  其五一','釋慧性','宋','宋诗','song-poetry','','[]','一番秋雨一番凉，道路無塵野菊香。',60,'全唐诗/poet.song.179000.json','["一番秋雨一番凉，道路無塵野菊香。", "翻笑昔年陶令尹，攢眉歸去錯商量。", "恁麽不恁麽，破鏡不重光。", "若把拈花微笑是，切忌將奴喚作郎。"]'),
('2e1184e0-8967-45af-8fc7-c2fa69677339','偈頌一百零一首  其五二','釋慧性','宋','宋诗','song-poetry','','[]','鼓沒絃琴，吹無孔笛。',26,'全唐诗/poet.song.179000.json','["鼓沒絃琴，吹無孔笛。", "共樂堯年同舜日，達磨九年空面壁。"]'),
('f8b7e327-01a3-41ef-8ca8-97ed3e17163c','偈頌一百零一首  其五三','釋慧性','宋','宋诗','song-poetry','','[]','久雨不晴，纔晴又雨。',42,'全唐诗/poet.song.179000.json','["久雨不晴，纔晴又雨。", "陰陽交泰，萬物得所。", "明明百草頭，能爲萬象主。", "覿面相呈，切忌莽鹵。"]'),
('b31aac8d-ae4f-4675-9eca-ba1620b5d628','偈頌一百零一首  其五四','釋慧性','宋','宋诗','song-poetry','','[]','秋風離離，秋色依依。',50,'全唐诗/poet.song.179000.json','["秋風離離，秋色依依。", "秋雲淡佇，秋月分輝。", "篆不彫之心印，狀似鐵牛之機。", "阿呵呵，力咄希，再三撈摝始應知。"]'),
('63959aa7-a810-4af3-894f-995f61e68ed0','偈頌一百零一首  其五五','釋慧性','宋','宋诗','song-poetry','','[]','月掛長空，孤峯獨宿。',48,'全唐诗/poet.song.179000.json','["月掛長空，孤峯獨宿。", "幽鳥數聲清，白雲斷處續。", "佛眼難窺，拗直作曲。", "羚羊掛角絕蹤由，無限清風生八極。"]'),
('87b6c79f-97e5-4ec6-be00-44de74d4ed0f','偈頌一百零一首  其五六','釋慧性','宋','宋诗','song-poetry','','[]','是句亦剗，非句亦剗。',48,'全唐诗/poet.song.179000.json','["是句亦剗，非句亦剗。", "瞞瞞頇頇，生鐵門限。", "如斯出世爲人，瞎却衲僧正眼。", "子細撿點將來，也是徐六擔板。"]'),
('9fa86b82-aaf6-4117-920c-ec70650cb597','偈頌一百零一首  其五七','釋慧性','宋','宋诗','song-poetry','','[]','瞿曇夜半見明星，碓觜挑開眼裏筋。',58,'全唐诗/poet.song.179000.json','["瞿曇夜半見明星，碓觜挑開眼裏筋。", "四十九年無畏說，至今錯認定盤星。", "將頭不猛，带累三軍。", "曹溪波浪如相似，無限平人被陸沈。"]'),
('1dc9954e-b2b2-4180-968c-eb7450d640ed','偈頌一百零一首  其五八','釋慧性','宋','宋诗','song-poetry','','[]','草離離，煙漠漠，雨如膏，雲如鶴。',40,'全唐诗/poet.song.179000.json','["草離離，煙漠漠，雨如膏，雲如鶴。", "說了也，錯錯錯。", "五老峯高徹骨寒，野猿啼斷山月落。"]'),
('dab1b08d-4aad-4d64-87e8-1cce96d9f315','偈頌一百零一首  其五九','釋慧性','宋','宋诗','song-poetry','','[]','天得一，地得一，王得一兮無等匹。',48,'全唐诗/poet.song.179000.json','["天得一，地得一，王得一兮無等匹。", "一得一，又何必，閃電光中加霹靂。", "朝來細雨灑危層，八面風清照紅日。"]'),
('e6b0680a-b71f-4e5d-becf-7cca0d1989ff','偈頌一百零一首  其六○','釋慧性','宋','宋诗','song-poetry','','[]','大包無外，細入無間。',62,'全唐诗/poet.song.179000.json','["大包無外，細入無間。", "內外絕瑕疵，古今無背面。", "森羅萬象影中藏，四聖六凡光裏現。", "分明常在諸人前，未審諸人見不見，鐵壁銀山通一線。"]'),
('6d8142e0-aac5-45df-836b-7ad684a469e1','偈頌一百零一首  其六一','釋慧性','宋','宋诗','song-poetry','','[]','雪埋松徑，梅著寒梢。',34,'全唐诗/poet.song.179000.json','["雪埋松徑，梅著寒梢。", "露倮倮，赤灑灑，獨孤標。", "寒山逢拾得，撫掌笑呵呵。"]'),
('b70af790-25fc-40c5-9f01-bd20a73ac4a4','偈頌一百零一首  其六二','釋慧性','宋','宋诗','song-poetry','','[]','初三十一，中九下七。',32,'全唐诗/poet.song.179000.json','["初三十一，中九下七。", "更不囊藏，當陽拈出。", "一氣轉洪鈞，八方開壽域。"]'),
('5d013e62-e517-4159-90bd-8d60d5f026c8','偈頌一百零一首  其六三','釋慧性','宋','宋诗','song-poetry','','[]','心月孤圓，清光皎潔。',34,'全唐诗/poet.song.179000.json','["心月孤圓，清光皎潔。", "吞盡十方空，銀椀裏盛雪。", "本光瑞如此，笑倒燈明佛。"]'),
('03d94ab3-84b4-4895-8d3b-7af3cf76cbba','偈頌一百零一首  其六四','釋慧性','宋','宋诗','song-poetry','','[]','本犀花散一山秋，更約清風作勝游。',56,'全唐诗/poet.song.179000.json','["本犀花散一山秋，更約清風作勝游。", "笑傲幽香翻葉底，西來祖意在枝頭。", "沒回互，興悠悠，遼天鼻孔齊穿却，更嫌何處不風流。"]'),
('9727b400-475d-41c9-b02e-e6af885eca18','偈頌一百零一首  其六五','釋慧性','宋','宋诗','song-poetry','','[]','殺人刀，活人劍，劈破虛空成兩片。',52,'全唐诗/poet.song.179000.json','["殺人刀，活人劍，劈破虛空成兩片。", "千妖百怪盡潜蹤，萬象森羅光影現。", "艾人與門神，端的見不見。", "拄杖子聊通一線。"]'),
('be809ebe-1243-4e98-a7f0-4e987c5273c9','偈頌一百零一首  其六六','釋慧性','宋','宋诗','song-poetry','','[]','有結有解俱錯，到底無繩自縛。',54,'全唐诗/poet.song.179000.json','["有結有解俱錯，到底無繩自縛。", "一夏九十日終，箇箇眉鬚墮落。", "入水長人，填溝塞壑。", "相逢只解那斯祁，明眼衲僧休卜度。"]'),
('bbbab21c-750b-41d5-b2b7-b8f086182b3b','偈頌一百零一首  其六七','釋慧性','宋','宋诗','song-poetry','','[]','纔開口又成剩語，不開口又成增語，發機須是千鈞弩。',48,'全唐诗/poet.song.179000.json','["纔開口又成剩語，不開口又成增語，發機須是千鈞弩。", "草店家風別，翻雲又覆雨。", "若是陶淵明，攢眉便歸去。"]'),
('54466e8c-fc4d-45c8-b82d-8dcabc6115b3','偈頌一百零一首  其六八','釋慧性','宋','宋诗','song-poetry','','[]','松蘿影裏，積翠堆中。',52,'全唐诗/poet.song.179000.json','["松蘿影裏，積翠堆中。", "白雲爲蓋，流泉作琴。", "隻影獨標巖上月，不知那箇是知音。", "耳卓朔，頭蓬鬆，擡眸鷂子過遼東。"]'),
('e029c65e-576a-417b-a63e-a9991bc31ec4','偈頌一百零一首  其六九','釋慧性','宋','宋诗','song-poetry','','[]','言語動用沒交涉，非言語動用亦沒交涉。',44,'全唐诗/poet.song.179000.json','["言語動用沒交涉，非言語動用亦沒交涉。", "傾腸倒腹，爲楔出楔。", "啞却我口禿却舌，明明萬里一條鐵。"]'),
('555ac5f0-de46-4f68-84c8-911f8cbdb8f0','偈頌一百零一首  其七○','釋慧性','宋','宋诗','song-poetry','','[]','點撿將來，罪過不少。',20,'全唐诗/poet.song.179000.json','["點撿將來，罪過不少。", "只憑拄杖，一切靠倒。"]'),
('fa160d1c-5dbd-4a25-b217-b1a8292c0db9','偈頌一百零一首  其七一','釋慧性','宋','宋诗','song-poetry','','[]','掀翻四大海，踢倒須彌盧。',38,'全唐诗/poet.song.179000.json','["掀翻四大海，踢倒須彌盧。", "心粗膽大，少實多虛。", "夜見明星曾落節，兒孫隨後受塗糊。"]'),
('7b999bd4-d4e4-4d6e-9fb1-db17fc596dca','偈頌一百零一首  其七二','釋慧性','宋','宋诗','song-poetry','','[]','木落高秋玉露垂，慎終追遠又思惟。',100,'全唐诗/poet.song.179000.json','["木落高秋玉露垂，慎終追遠又思惟。", "無端一世滅胡種，累及兒孫說向誰。", "啞却口，落盡眉。", "牽犁拽杷，带水拖泥。", "順捋虎鬚拈蝎尾，白拈手裏覓便宜。", "家肥生孝子，誰是五逆兒。", "嗚咿，嗚咿。", "秋露春風消息在，不知誰薦上頭機。"]'),
('095b80fc-eff2-4193-a660-8e0d3678048b','偈頌一百零一首  其七三','釋慧性','宋','宋诗','song-poetry','','[]','喝散白雲，穿開碧落。',20,'全唐诗/poet.song.179000.json','["喝散白雲，穿開碧落。", "須彌燈王，無處摸索。"]'),
('70281b60-061d-45e0-93bb-705652eaa81a','偈頌一百零一首  其七四','釋慧性','宋','宋诗','song-poetry','','[]','深藏古寺老垂垂，冷暖相諳只自知。',32,'全唐诗/poet.song.179000.json','["深藏古寺老垂垂，冷暖相諳只自知。", "不謂使符相苦逼，依然拽杷又牽犁。"]'),
('9adc9b83-6caf-4cd0-8dde-b4d4ab0979bf','偈頌一百零一首  其七五','釋慧性','宋','宋诗','song-poetry','','[]','開門待知識，知識不來過。',28,'全唐诗/poet.song.179000.json','["開門待知識，知識不來過。", "開口不在舌頭上，佇看平地起風波。"]'),
('73893d8b-2943-4e03-a5ae-4fc71df4f9c0','偈頌一百零一首  其七六','釋慧性','宋','宋诗','song-poetry','','[]','佛祖大機，目前密布。',34,'全唐诗/poet.song.179000.json','["佛祖大機，目前密布。", "主中賓，賓中主。", "雲從龍，風從虎，發機須是千鈞弩。"]'),
('4b7e8f47-b4af-48e6-8a14-d1edb1f31d0f','偈頌一百零一首  其七七','釋慧性','宋','宋诗','song-poetry','','[]','歲盡年窮，無可不可。',78,'全唐诗/poet.song.179000.json','["歲盡年窮，無可不可。", "烹露地牛，燒榾柮火。", "野菜只添一筯油，滿鉢和羅唯一飽。", "笑傲煙霞，白雲風拂。", "韶陽一曲自高歌，困來一覺和衣倒。", "淺種深耕得自由，珊瑚枝頭日杲杲。"]'),
('a4bfd436-53f2-405a-a836-5e9595f9bea0','偈頌一百零一首  其七八','釋慧性','宋','宋诗','song-poetry','','[]','東村王老夜燒錢，打著南邊動北邊。',32,'全唐诗/poet.song.179000.json','["東村王老夜燒錢，打著南邊動北邊。", "赤骨歷窮誇富貴，日高三丈尚憨眠。"]'),
('1c0cbc4e-f5d0-48b6-a9dc-4a80a1d05d1b','偈頌一百零一首  其七九','釋慧性','宋','宋诗','song-poetry','','[]','穹窿山裏老於菟，一點圓明爍太虛。',52,'全唐诗/poet.song.179000.json','["穹窿山裏老於菟，一點圓明爍太虛。", "八角磨盤空裏轉，寥落林泉意自殊。", "超物象，絕名模，將爲胡鬚赤，更有赤鬚胡。"]'),
('90cc9ee5-e16c-4440-9707-0fd52f425e5c','偈頌一百零一首  其八○','釋慧性','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','一人道有一人無，正令全提肘後符。',32,'全唐诗/poet.song.179000.json','["一人道有一人無，正令全提肘後符。", "昨夜虛空開口笑，石人吞却洞庭湖。"]'),
('ecccc6ea-66a0-4a3a-a048-2f0aa12a0e94','偈頌一百零一首  其八一','釋慧性','宋','宋诗','song-poetry','','[]','離四句，絕百非。',45,'全唐诗/poet.song.179000.json','["離四句，絕百非。", "一言已出，駟馬難追。", "一任金烏東出，徒教玉兔沈西。", "千鈞之弩，不爲鼷鼠而發機。"]'),
('7f257cc8-1ea1-40a2-8d52-d6c2e17285c4','偈頌一百零一首  其八二','釋慧性','宋','宋诗','song-poetry','','[]','春雨如膏，春雲如鶴。',48,'全唐诗/poet.song.179000.json','["春雨如膏，春雲如鶴。", "客從天外來，正是魔王脚。", "閫外威權，麒麟一角。", "轉身一拶驗來端，外道天魔俱膽落。"]'),
('44bc0620-3dd2-4202-af03-e87d7436325b','偈頌一百零一首  其八三','釋慧性','宋','宋诗','song-poetry','','[]','春山青，春水綠。',60,'全唐诗/poet.song.179000.json','["春山青，春水綠。", "春雨濛濛，春花簇簇。", "春光滿目畫難成，春風萬里何抅束。", "肥馬轆轆，瘦馬轆轆。", "日逐忙忙等閑過，些兒毒氣誰輕觸。"]'),
('22d765f5-9efc-43f3-b4b2-31fcde3d42fb','偈頌一百零一首  其八四','釋慧性','宋','宋诗','song-poetry','','[]','今朝四月初一，萬像難逃影質。',56,'全唐诗/poet.song.179000.json','["今朝四月初一，萬像難逃影質。", "馬祖陞堂，百丈捲席。", "祕魔擎叉，魯祖面壁。", "喚馿作馬，蝦跳不出。", "麒麟一角尖，烏龜三眼赤。"]'),
('48353b5f-7a40-43c0-ad60-a5610f259b5b','偈頌一百零一首  其八五','釋慧性','宋','宋诗','song-poetry','','[]','雲收天際，杲日當空。',36,'全唐诗/poet.song.179000.json','["雲收天際，杲日當空。", "坐立儼然，如何通信。", "自是不歸歸便得，五湖煙浪有誰爭。"]'),
('acf48e4a-0ce8-4642-9573-464287b8b329','偈頌一百零一首  其八六','釋慧性','宋','宋诗','song-poetry','','[]','八還正眼頂門開，悟得門門有善財。',32,'全唐诗/poet.song.179000.json','["八還正眼頂門開，悟得門門有善財。", "要識九旬行道處，薰風依舊自南來。"]'),
('d684ecd8-7b42-4ec5-b914-3a9773fb0b05','偈頌一百零一首  其八七','釋慧性','宋','宋诗','song-poetry','','[]','不與萬法爲侶，咬定牙關錯舉。',46,'全唐诗/poet.song.179000.json','["不與萬法爲侶，咬定牙關錯舉。", "西江吸盡鐵船浮，活提獰龍和角煮。", "倒騎佛殿出三門，翻手爲雲覆手雨。"]'),
('d4f9dfcb-0054-4707-9563-f13f3a33d6c7','偈頌一百零一首  其八八','釋慧性','宋','宋诗','song-poetry','','[]','兔馬有角，牛羊無角。',28,'全唐诗/poet.song.179000.json','["兔馬有角，牛羊無角。", "智不到處，切忌道著。", "拈得鼻孔還失却。"]'),
('b2aed3d8-9971-4f71-b1e9-6b80eb89ed53','偈頌一百零一首  其八九','釋慧性','宋','宋诗','song-poetry','','[]','相見不揚眉，雷轟閃電遲。',42,'全唐诗/poet.song.179000.json','["相見不揚眉，雷轟閃電遲。", "知音纔側耳，擬議落便宜。", "威行閫外，瞥轉機輪，大千捏聚一微塵。"]'),
('962ce23d-0beb-4439-847a-1b4ab6c7b693','偈頌一百零一首  其九○','釋慧性','宋','宋诗','song-poetry','','[]','息庵去世肉猶暖，五逆還它五逆兒。',32,'全唐诗/poet.song.179000.json','["息庵去世肉猶暖，五逆還它五逆兒。", "海湧峯頭行正令，白拈誰敢覓便宜。"]'),
('f13efcfc-10a6-4e0a-8fa6-949f0642fc11','偈頌一百零一首  其九一','釋慧性','宋','宋诗','song-poetry','','[]','金剛圈，栗棘蓬。',34,'全唐诗/poet.song.179000.json','["金剛圈，栗棘蓬。", "拈來便用，耀古騰今。", "格外知音纔領略，四方八面起清風。"]'),
('341576d4-67d6-4ffc-af6d-03a6ba63b7e0','偈頌一百零一首  其九二','釋慧性','宋','宋诗','song-poetry','','[]','無語中有語，名曰死句。',50,'全唐诗/poet.song.179000.json','["無語中有語，名曰死句。", "有語中無語，名曰活句。", "可謂剜肉作瘡，皮穿骨露。", "舉不顧，即差牙，閃電光中走烏兔。"]'),
('e5fd8caa-0355-4080-b31d-27d6da2e916e','偈頌一百零一首  其九三','釋慧性','宋','宋诗','song-poetry','','[]','十五日已前，風吹不入。',44,'全唐诗/poet.song.179000.json','["十五日已前，風吹不入。", "十五日已後，水灑不著。", "正當十五日，月中仙桂和根拔，海底泥牛把角牽。"]'),
('e9088353-25da-4dba-9db1-fae28e2a6abf','偈頌一百零一首  其九四','釋慧性','宋','宋诗','song-poetry','','[]','天寒人寒，大家在這裏。',37,'全唐诗/poet.song.179000.json','["天寒人寒，大家在這裏。", "洗面摸著鼻，喫茶濕却觜。", "向上還有事也無，韓信臨朝底。"]'),
('f2353351-656d-41bd-89d0-a11da8e906e3','偈頌一百零一首  其九五','釋慧性','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u592a\u6e56"]','廬山華藏太湖濱，碓觜挑開眼裏筋。',32,'全唐诗/poet.song.179000.json','["廬山華藏太湖濱，碓觜挑開眼裏筋。", "來趁壽寧爐竈熱，大千獨步見鵬程。"]'),
('515e4ed0-ca07-4fb0-8e98-3af349329bf5','偈頌一百零一首  其九六','釋慧性','宋','宋诗','song-poetry','','[]','智不是道，心不是佛。',20,'全唐诗/poet.song.179000.json','["智不是道，心不是佛。", "輥雪峰毬，舞道吾笏。"]'),
('36842de6-55c4-4a1f-9460-1676ab688536','偈頌一百零一首  其九七','釋慧性','宋','宋诗','song-poetry','','[]','二月春過半，園林一樣新。',58,'全唐诗/poet.song.179000.json','["二月春過半，園林一樣新。", "傍花看蝶舞，近柳聽鶑吟。", "遠客來相訪，還曾悟此心。", "林鄭珍，井底種林檎。", "今年桃李貴，一顆直千金。"]'),
('ceb0e79c-fec8-4d16-98db-bc311b3559d8','偈頌一百零一首  其九八','釋慧性','宋','宋诗','song-poetry','','[]','觀音菩薩將錢買糊餠，放下元來是箇饅頭。',37,'全唐诗/poet.song.179000.json','["觀音菩薩將錢買糊餠，放下元來是箇饅頭。", "相席打令，看樓打樓，不風流處也風流。"]'),
('45bcb814-5988-48e5-af20-29748204b41c','偈頌一百零一首  其九九','釋慧性','宋','宋诗','song-poetry','','[]','燕語鶑吟，俱談實相。',33,'全唐诗/poet.song.179000.json','["燕語鶑吟，俱談實相。", "春風吹動桃李花，淡煙疎雨籠青嶂。", "切忌起模畫樣。"]'),
('b5d66f66-5016-4259-8278-63c463576354','偈頌一百零一首  其一○○','釋慧性','宋','宋诗','song-poetry','','[]','歸宗事理絕，日輪正當午。',34,'全唐诗/poet.song.179000.json','["歸宗事理絕，日輪正當午。", "布袋放憨癡，貓兒捉老鼠。", "若人會得，超佛越祖。"]'),
('a058b753-3a3e-4dba-835c-496ab6010faf','頌古七首  其一','釋慧性','宋','宋诗','song-poetry','','[]','南枝向暖北枝寒，一種春風有兩般。',32,'全唐诗/poet.song.179000.json','["南枝向暖北枝寒，一種春風有兩般。", "寄語高樓莫吹笛，大家留取倚欄干。"]'),
('d4c0fe66-7910-4227-abd5-ad2a66528841','頌古七首  其二','釋慧性','宋','宋诗','song-poetry','','[]','外道懷藏寶鏡時，世尊良久爲高提。',32,'全唐诗/poet.song.179000.json','["外道懷藏寶鏡時，世尊良久爲高提。", "渾如良馬窺鞭影，不覺全身陷鐵圍。"]'),
('93321483-5807-49d1-978f-e0a683620466','頌古七首  其三','釋慧性','宋','宋诗','song-poetry','','[]','明修棧道，暗度陳倉。',22,'全唐诗/poet.song.179000.json','["明修棧道，暗度陳倉。", "刻舟猶覓劍，夜雨過瀟湘。"]'),
('4bb23f49-f6b1-44e4-ba2a-868e9e67322c','頌古七首  其四','釋慧性','宋','宋诗','song-poetry','','[]','只許老胡知，不許老胡會。',28,'全唐诗/poet.song.179000.json','["只許老胡知，不許老胡會。", "白雲盡處是青山，行人更在青山外。"]'),
('90874215-f25f-4f09-a8ec-2ceec982c02a','頌古七首  其五','釋慧性','宋','宋诗','song-poetry','','[]','放兩拋三，瞞神謼鬼。',20,'全唐诗/poet.song.179000.json','["放兩拋三，瞞神謼鬼。", "換盆換盆，誰不識你。"]'),
('70c9fbe7-e58e-41d7-9d95-6ed55d6082d6','頌古七首  其六','釋慧性','宋','宋诗','song-poetry','','[]','溈山養子沒來由，叉手人前不識羞。',32,'全唐诗/poet.song.179000.json','["溈山養子沒來由，叉手人前不識羞。", "更把琵琶半遮面，不令人見轉風流。"]'),
('d162e335-4fe6-4365-add7-481b130e544c','頌古七首  其七','釋慧性','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','當陽利劍斬狸奴，刃下翻身會也無。',32,'全唐诗/poet.song.179000.json','["當陽利劍斬狸奴，刃下翻身會也無。", "脫下草鞋頭戴出，石人吞却洞庭湖。"]'),
('0dec3609-32f0-4cf3-bfad-8a2904d6e5c1','寄顔一齋閤內寂室方氏','釋慧性','宋','宋诗','song-poetry','','[]','即心即佛沒誵訛，不動舌頭意氣多。',32,'全唐诗/poet.song.179000.json','["即心即佛沒誵訛，不動舌頭意氣多。", "打破虛空行活路，夫妻撫掌笑呵呵。"]'),
('04433618-7530-4489-bf65-20f760621d53','付浄徹首座竹篦','釋慧性','宋','宋诗','song-poetry','','[]','竹篦付了復何爲，佛祖當頭劈面揮。',32,'全唐诗/poet.song.179000.json','["竹篦付了復何爲，佛祖當頭劈面揮。", "尺水便能翻逆浪，儘教人薦截流機。"]'),
('93301011-c4e2-4b9d-812a-d38f186793a2','沈安齊草菴號常牧','釋慧性','宋','宋诗','song-poetry','','[]','尚墮功勳不自由，還同死水卧泥牛。',32,'全唐诗/poet.song.179000.json','["尚墮功勳不自由，還同死水卧泥牛。", "何如闊進竿頭步，撒手懸崖萬仞頭。"]'),
('1c35190f-93dd-4d7f-ae1d-24af2981dec8','自贊  其一','釋慧性','宋','宋诗','song-poetry','','[]','紫霄峰下，以毒攻毒。',64,'全唐诗/poet.song.179000.json','["紫霄峰下，以毒攻毒。", "撒土拋沙，拗直作曲。", "撼動四大神州，拳踢掀翻地軸。", "性禪沒興遭逢，切忌望空呵囑。", "坐斷千峰頂𩕳頭，一任虛聲聽杓卜。"]'),
('b8e10dd2-97fa-4cfc-bc53-80629ec8e17b','自贊  其二','釋慧性','宋','宋诗','song-poetry','','[]','橫按吹毛，全提正令。',34,'全唐诗/poet.song.179000.json','["橫按吹毛，全提正令。", "毀佛謗法，因邪打正。", "有時裂轉面皮，天下衲僧乞命。"]'),
('ced08a79-6f54-4222-8eb1-9620911d3b9e','辭世','釋慧性','宋','宋诗','song-poetry','','[]','七十八年，內空外空。',20,'全唐诗/poet.song.179000.json','["七十八年，內空外空。", "撒手便行，萬古清風。"]'),
('5d79ec1f-0bc1-462e-9cfb-e6f1bed60a8e','吾廬寓言','劉學箕','宋','宋诗','song-poetry','','[]','五峯之山環吾廬，五峯之水清溜渠。',286,'全唐诗/poet.song.179000.json','["五峯之山環吾廬，五峯之水清溜渠。", "山水可樂情可娛，五畝之宅奠厥居。", "清湖列嶂開坐隅，白沙峩峩煙岫鋪。", "崇山梅嶺豁望眼，高門堇阜聯襟裾。", "况當春晚積雨餘，綠褥翠疊青珊瑚。", "桑麻滿路人意好，鳴禽上下聲相呼。", "迨今八月九月初，楓林隔水紅凋疎。", "秋場稻熟聽蓬樸，小槽新釀傾真珠。", "昨宵一雪飛璠璵，遠山近山光凝酥。", "羣峯突兀不敢覷，銀壁照耀天鬼塗。", "千金不須買畫圖，丹青縱有畫不如。", "風景萬態朝昏殊，天成此畫人難摹。", "蹊荒圃廢幾朝夕，一日築居天賜予。", "四時遊觀心良舒，考槃在阿歸來乎。", "乃歌曰：採於園兮籃有蔬，釣於水兮筐有魚，余之弗歡兮其誰之歡歟。", "又歌曰：惠風清兮出有車，芸香芬兮讀有書，余之弗樂兮其誰之樂歟。"]'),
('e89a1401-335c-4fc6-9705-e16102869eb1','石假山','劉學箕','宋','宋诗','song-poetry','','[]','潭溪散人方是閒，真山不愛愛假山。',240,'全唐诗/poet.song.179000.json','["潭溪散人方是閒，真山不愛愛假山。", "呼童積疊石磊磈，遠近便擁峯與巒。", "晴嵐滴翠明窗前，清影掛壁方池邊。", "色侵書帙日華薄，丘壑坐上生雲烟。", "雲烟收霏苔蘚綠，山石傍頭更栽竹。", "三竿兩竿韻不俗，摇蕩清風凉意足。", "方是閒人當此時，以假像真人謂奇。", "或來靜對酌美酒，或來宴坐哦新詩。", "吟詩搜索縈心脾，酒醉落魄精神癡。", "吟詩飲酒且不可，况復局上爭枯棋。", "不如對山撫鳴琴，琴心三疊舞胎禽。", "高山流水存至音，古趣澹泊悅我心。", "老泉三峯爛木材，百年沉埋安在哉。", "東坡仇池九華石，只有佳篇傳入集。", "此山亦猶今視昔，與我同生亦同沒。"]'),
('bb8ff60e-9e20-4cf5-bc8c-2bd1a3979996','社日喜晴分韻得前字','劉學箕','宋','宋诗','song-poetry','','[]','夜來急雨淙飛簷，脫驚紅日輝潭川。',192,'全唐诗/poet.song.179000.json','["夜來急雨淙飛簷，脫驚紅日輝潭川。", "梨花有情朝露重，柳带無力春風顛。", "傍簾新燕低拂掠，入檻戯蝶相聯翩。", "今晨天氣亦佳爾，一春未見茲晴暄。", "綠陰林下笑聲好，簫鼓賽社祈豐年。", "金穰屢豐豈不好，米賤更苦人無錢。", "太公九府法已弊，楮幣印出私相權。", "所司轉變無善策，低昂用否難流傳。", "縣官那更租稅急，白紙不問黄榜蠲。", "窮民非負實無有，里正罰責殊可憐。", "吾儂雖樂此日美，釂白醉倒春風前。", "却愁烟雨暗春晚，米價頓長民憂煎。"]'),
('2ea3d3b4-f604-4914-a3f7-cb4095db84f9','插秧歌','劉學箕','宋','宋诗','song-poetry','','[]','農夫戢戢清波闊，秧稻茸茸森石髮。',160,'全唐诗/poet.song.179000.json','["農夫戢戢清波闊，秧稻茸茸森石髮。", "父兒呼喚手拔齊，千把萬把根連泥。", "四更乘月躅隴陌，曉烟漸散東方白。", "歸來喫得飯一盂，擔到田頭汗似珠。", "蹲身擘叢種入土，不問朝昏與亭午。", "肌膚剝裂肉起皮，烈日纔陰又風雨。", "秋收幸值歲稍豐，穀賤無錢私債重。", "連忙變轉了官賦，霜雪凍餓愁窮冬。", "吁嗟四民天地間，服田力穡良獨艱。", "寄言安坐西方輩，汝飽不慚吾厚顔。"]'),
('ed86299a-a532-469d-b3bf-03d398cf84c3','醉歌','劉學箕','宋','宋诗','song-poetry','','[]','讀書求見古人心，閉門不知青春深。',176,'全唐诗/poet.song.179000.json','["讀書求見古人心，閉門不知青春深。", "夜來東風掃浮陰，曉光薄林生遥岑。", "搜尋不覺出門去，綠暗溪邊楊柳路。", "詩章立願不復作，會景那知自成句。", "歸途晤語誰與從，眼前物物俱春工。", "崇桃積李事已晚，牡丹正麗酴醿穠。", "白茶照人冰雪同，紅茶燒空猩血紅。", "金沙雨晴翡翠積，海棠露濕胭脂重。", "急呼詩朋喚酒伴，高堂共泛琉璃鍾。", "夜闌秉燭相對語，謾道今人不如古。", "古士放達醒者稀，今人不飲徒自苦。"]'),
('ade35de8-2924-46ed-bf51-52e9a25574f5','白山茶','劉學箕','宋','宋诗','song-poetry','','[]','白茶誠異品，天賦玉玲瓏。',48,'全唐诗/poet.song.179000.json','["白茶誠異品，天賦玉玲瓏。", "不作燒燈焰，深明韞櫝功。", "易容非世力，幻質本春工。", "皓皓知難污，塵飛謾自紅。"]'),
('577cab28-4518-4ae5-bc8f-b01a7cc67e09','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其一','劉學箕','宋','宋诗','song-poetry','','[]','維昔舊遊，十有八春。',40,'全唐诗/poet.song.179000.json','["維昔舊遊，十有八春。", "中間往來，合散風塵。", "詞翰在壁，瞻之愈新。", "憶我仲弟，眇然懷人。"]'),
('ebd0eaad-677e-48e8-82af-d2ba1de11305','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其二','劉學箕','宋','宋诗','song-poetry','','[]','吁嗟人生，年不滿百。',40,'全唐诗/poet.song.179000.json','["吁嗟人生，年不滿百。", "天地囿形，百代過客。", "去日苦多，來日苦窄。", "我曷不樂，慨念疇昔。"]'),
('91cecd16-7be9-4be0-bbc6-0f0f3ce5511f','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其三','劉學箕','宋','宋诗','song-poetry','','[]','丱角燈窗，硯席是共。',40,'全唐诗/poet.song.179000.json','["丱角燈窗，硯席是共。", "春山朝吟，秋堂夜誦。", "棄背三年，心骨沉痛。", "幾夜見君，似夢非夢。"]'),
('ec9ae2c0-f922-44a5-9cd8-75543759c302','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其四','劉學箕','宋','宋诗','song-poetry','','[]','念昔童稚，汎然若舟。',40,'全唐诗/poet.song.179000.json','["念昔童稚，汎然若舟。", "惟我與君，孤詣同修。", "博文約禮，匪遨匪遊。", "子方盛年，遽赴玉樓。"]'),
('3014d211-9f74-46bd-a747-deab571b5740','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其五','劉學箕','宋','宋诗','song-poetry','','[]','朱垣素壁，醉墨漓淋。',40,'全唐诗/poet.song.179000.json','["朱垣素壁，醉墨漓淋。", "虛堂重臨，思古傷今。", "文不忍誦，盟弗可尋。", "即事即物，抆淚痛心。"]'),
('16e65e77-84ee-4728-9cfc-4aabd19bbc6e','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其六','劉學箕','宋','宋诗','song-poetry','','[]','舊題墨妙，龍蛇戶牖。',40,'全唐诗/poet.song.179000.json','["舊題墨妙，龍蛇戶牖。", "步驟歐虞，模倣顔柳。", "醉裏百篇，冥搜九有。", "天胡奪我，張仲孝友。"]'),
('fe4b8e84-f304-48f9-8df6-dc5aa4bdb006','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其七','劉學箕','宋','宋诗','song-poetry','','[]','屈指友于，祇今存幾。',40,'全唐诗/poet.song.179000.json','["屈指友于，祇今存幾。", "自仲之去，失此奇偉。", "言不勝情，心旌憤悱。", "哀哉蒼天，雨淚如洗。"]'),
('9c8c7a00-c4d6-492b-82bb-b2c0981e5843','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其八','劉學箕','宋','宋诗','song-poetry','','[]','團團庭柯，清美無度。',40,'全唐诗/poet.song.179000.json','["團團庭柯，清美無度。", "今我來斯，忽然老樹。", "偃蹇輪囷，剝蝕摧蠹。", "朱顔舜華，詎得如故。"]'),
('4c99d09f-4be0-44c6-a719-f1be38f6ebf6','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其九','劉學箕','宋','宋诗','song-poetry','','[]','興念陳迹，夢寐吾猶。',40,'全唐诗/poet.song.179000.json','["興念陳迹，夢寐吾猶。", "植杖風雩，某水某丘。", "日居月諸，循環靡休。", "迭爾遄邁，曾不我留。"]'),
('009f3d7c-6097-4395-bbd6-df2d2103be70','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其一○','劉學箕','宋','宋诗','song-poetry','','[]','憶自束髮，茲焉寓居。',40,'全唐诗/poet.song.179000.json','["憶自束髮，茲焉寓居。", "載思載瞻，宛不異初。", "極目遐眺，清風穆如。", "撫事懷人，悲來感余。"]'),
('5fa28e51-6993-4193-9796-06744325da9f','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其一一','劉學箕','宋','宋诗','song-poetry','','[]','少生四方，遊紫之水。',40,'全唐诗/poet.song.179000.json','["少生四方，遊紫之水。", "每有良朋，見止遇止。", "長哦伐木，求友乎此。", "樂以忘憂，云胡不喜。"]'),
('ac9e2de0-ff22-49b0-bc00-efad050234a6','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其一二','劉學箕','宋','宋诗','song-poetry','','[]','維親與朋，雜然滿坐。',40,'全唐诗/poet.song.179000.json','["維親與朋，雜然滿坐。", "華屋連甍，紅紫緐夥。", "半世重遊，霧迷烟鎖。", "慨然撫膺，謬悠老我。"]'),
('602452a4-a774-4b48-b929-b79c3296473d','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其一三','劉學箕','宋','宋诗','song-poetry','','[]','念昔考槃，碩人之薖。',40,'全唐诗/poet.song.179000.json','["念昔考槃，碩人之薖。", "琴豆觴酒，寤寐笑歌。", "逝者弗返，涕泗滂沱。", "念彼不樂，傷如之何。"]'),
('87a2a86e-14f1-4114-91a1-ad5fe55053f1','紫溪莊舍讀癸丑壁間舊題轉眼忽十八年同遊十不存一滋蘭弟亦作古人拂拭灑涕幾不能去因誦歐公詩云人昔共遊今有幾樹猶如此我何堪以是爲韻感懷成十四章庚午四月中澣  其一四','劉學箕','宋','宋诗','song-poetry','','[]','賢乎仲弟，和樂且湛。',40,'全唐诗/poet.song.179000.json','["賢乎仲弟，和樂且湛。", "自我不見，歲籥換三。", "百感交集，憂心如惔。", "山凝暮雲，回首不堪。"]'),
('73765062-40ce-4fd3-b6c6-1b5f9879bc95','舟行三章  其一','劉學箕','宋','宋诗','song-poetry','','[]','桂櫂兮蘭槳，泝流兮沿洄。',60,'全唐诗/poet.song.179000.json','["桂櫂兮蘭槳，泝流兮沿洄。", "天迥兮空明，湍激兮聲哀。", "水落兮石出，路轉兮溪回。", "鷗飛兮山浄，魚戲兮藻開。", "淹留兮何爲，盍賦兮歸來。"]'),
('43794bb1-e4ff-4ce9-86d5-a99bb325e025','舟行三章  其二','劉學箕','宋','宋诗','song-poetry','','[]','扁舟兮容與，浮雲兮舒卷。',60,'全唐诗/poet.song.179000.json','["扁舟兮容與，浮雲兮舒卷。", "波澄兮練橫，山秀兮屏展。", "散髮兮平岡，濯纓兮清淺。", "皇皇兮何之，路長兮悠緬。", "早賦兮歸來，迷途兮未遠。"]'),
('c43d6a25-10eb-4698-8283-2d54e5f4478e','舟行三章  其三','劉學箕','宋','宋诗','song-poetry','','[]','容與兮扁舟，長吟兮閒情。',60,'全唐诗/poet.song.179000.json','["容與兮扁舟，長吟兮閒情。", "白石兮離離，秋雲兮霙霙。", "我思兮先廬，水潭兮山屏。", "帳空兮鶴怨，人去兮猿驚。", "早賦兮歸來，涉園兮欣欣。"]'),
('61e2e68c-a5c6-46be-b0dd-7b63472fcb65','鉛山廨宇題壁','劉學箕','宋','宋诗','song-poetry','','[]','莫遣離愁相絆縈，九州之外盡愁城。',64,'全唐诗/poet.song.179000.json','["莫遣離愁相絆縈，九州之外盡愁城。", "酒頻挹注幽憂浣，詩苦冥搜太瘦生。", "漠漠草茵飛蛺蝶，深深柳幄韻鸝鶊。", "客懷未與成匆遽，三沐三熏慰此情。"]'),
('58516d6c-5495-436a-bd41-fa8d714d258b','道間池亭小酌','劉學箕','宋','宋诗','song-poetry','','[]','一曲芳池萬柄荷，遊鯈潛躍水揚波。',64,'全唐诗/poet.song.179000.json','["一曲芳池萬柄荷，遊鯈潛躍水揚波。", "竹孫楹檻風偏細，梅子江湖雨正多。", "凡物寓時俱意得，謂予不飲柰愁何。", "暫來徙倚又還去，猛拍欄桿浩浩歌。"]'),
('2a620890-36b8-4f4f-b7d0-136e4f094020','太湖書懷','劉學箕','宋','宋诗','song-poetry','','["\u592a\u6e56"]','清風起平湖，白雲生澗陰。',120,'全唐诗/poet.song.179000.json','["清風起平湖，白雲生澗陰。", "佳時慘不樂，羈思苦難任。", "客子熱中腸，浩然懷故林。", "仲夏倏已過，草木鬰蕭森。", "萬物欣有託，吾生何崎嶔。", "念昔歲甫冠，自許雙南金。", "只今墮危塗，不如烟際禽。", "山水所素願，利名非宿心。", "何當返故廬，嘯傲蒼崖深。", "兩鬢豈長綠，勿枉吳霜侵。"]'),
('4264953f-3340-45cc-97b5-78021d406ffb','九月十八日夜夢賞春某氏園池賦春詞二首題柱  其一','劉學箕','宋','宋诗','song-poetry','','[]','芍藥花開日漸長，小窗閒理舊笙簧。',32,'全唐诗/poet.song.179000.json','["芍藥花開日漸長，小窗閒理舊笙簧。", "憑誰爲喚詩宗匠，共賦留雲借月章。"]'),
('7db18be1-2b49-4b74-a145-f195930acfbc','九月十八日夜夢賞春某氏園池賦春詞二首題柱  其二','劉學箕','宋','宋诗','song-poetry','','[]','樓下酴醿壓架香，翠圍帷幄覆池塘。',32,'全唐诗/poet.song.179000.json','["樓下酴醿壓架香，翠圍帷幄覆池塘。", "桃花浪煖魚成陣，人倚雕欄到夕陽。"]'),
('dd87a4c4-0023-42f2-bf4f-4dbcd3dc6520','古交行','劉學箕','宋','宋诗','song-poetry','','[]','君居京江頭，我住武夷曲。',370,'全唐诗/poet.song.179000.json','["君居京江頭，我住武夷曲。", "平生風馬牛，道路幾重複。", "會面情相親，卜室欣相隣。", "傾蓋一笑粲，恍然如故人。", "君家義聚五百指，堂上怡怡奉甘旨。", "收書萬卷不言貧，撫卹孤嫠甚勤止。", "我家煢獨與君似，自我之出誰料理。", "歲晚團圞未得歸，感事捫膺但增恥。", "知君念我留客裏，每見時能具羞匕。", "心吐肺肝所同然，尊酒論文日終晷。", "古靈故家好孫子，披覿芝眉因識李。", "博洽多聞世希比，頃刻龍蛇飛剡紙。", "我慙學術殊不逮二君，二君愛予心良勤。", "交遊情鍾固以類，愧以蕭艾聯蘭薰。", "常恐此時心，易變作甘醴。", "欲君持此心，淡若秋江水。", "古人心交尚道義，今人利交尚權勢。", "古道於今何寂寥，傷心不識古交意。", "兩君姿質俱精金，百煉不改色愈明。", "兩君體性如美玉，渾渾厚厚藴諸櫝。", "上映亭亭巗上千歲之孤松，下方磊磊豐山百世之霜鐘。", "松青不變四時色，鐘鏗一朝振文物。", "予何人哉得附驥，勉勉詎敢自暴棄。", "日莫長歌伐木篇，三復詩人琢磨義。"]'),
('4c9864a2-77b3-4d1f-a4d6-5bdb6dbfba26','蕭長公來訪示以諸公詩卷謂與予遊從之久不能一辭爲贈頗相噍責予賦之不可辭之亦不可皆有說焉名章俊語前後相望無數次乎其間是覩西子之容而自增醜耳所不容却者予年十五時海山官丁受琴於長夫今予年四十與長夫有二十五年之舊辭之弗作其可乎因書長句','劉學箕','宋','宋诗','song-poetry','','[]','人生立志各有癖，浹髓淪肌療無術。',294,'全唐诗/poet.song.179000.json','["人生立志各有癖，浹髓淪肌療無術。", "君不學少年奏賦明光宮，又不能桑麻穀粟去作田舍翁。", "苦心竭慮淡泊音，手携三尺綠綺琴。", "七絃指下叢然鳴，于以求見古人心。", "古音寥寥失微妙，鄭衛淫哇競蟬噪。", "君獨優游夷愉廣厚而高明，鼓有虞氏之南風，賡之以文王宣父之操。", "若人來索便與彈，略不訑訑見顔貌。", "絕之不作衛次公，却之常嗤戴安道。", "顧我與君幽趣同，海山尚憶初相逢。", "我時十五始冠巾，君亦壯年氣如虹。", "夜窗擁衾月流空，促絃初學調商宮。", "別來二十五春風，我猶故吾君學通。", "五音六律知者稀，一生辛勤造精微。", "心存至樂物莫移，殆類聞韶子在齊。", "洋洋盈耳不療饑，任從妻子相號啼。", "浮雲柳絮無根蒂，世事乘除幾榮悴。", "祇今物我俱忘情，與君同尋方子春。"]'),
('b5258ebb-d64b-4bea-91ea-1dd27fec8c93','溪橋晚步','劉學箕','宋','宋诗','song-poetry','','[]','一带清溪淺漾沙，松橋橫渡野人家。',32,'全唐诗/poet.song.179000.json','["一带清溪淺漾沙，松橋橫渡野人家。", "平林盡日霜風勁，楓葉翻丹似落花。"]'),
('4ba61851-57ea-4da9-931d-8e45c7a2a2d4','和張政仲見寄三絕  其一','劉學箕','宋','宋诗','song-poetry','','[]','柘山盡處即屏山，若隔蓬萊弱水間。',32,'全唐诗/poet.song.179000.json','["柘山盡處即屏山，若隔蓬萊弱水間。", "伐木歌餘凝望遠，此心翻羨白雲閒。"]'),
('071afe40-ab52-4d3c-8fc2-f08a82837e43','和張政仲見寄三絕  其二','劉學箕','宋','宋诗','song-poetry','','[]','故人別去復一月，三絕詩章寄我來。',32,'全唐诗/poet.song.179000.json','["故人別去復一月，三絕詩章寄我來。", "我有青州四從事，已令挈至待君開。"]'),
('094c561a-0a90-4c79-8f78-158e1a1d342c','和張政仲見寄三絕  其三','劉學箕','宋','宋诗','song-poetry','','[]','藥畦菜圃足秋雨，菊徑松坡未就荒。',32,'全唐诗/poet.song.179000.json','["藥畦菜圃足秋雨，菊徑松坡未就荒。", "請命當年嵇呂駕，便同看劍引盃長。"]'),
('f5b7bd34-e15e-4b58-896a-da3ce6f95dba','演平渡度姪別入城','劉學箕','宋','宋诗','song-poetry','','[]','前溪積雨浪拍天，人立沙頭催渡船。',64,'全唐诗/poet.song.179000.json','["前溪積雨浪拍天，人立沙頭催渡船。", "溪雲貼水濕不起，岸柳凝愁絲亂牽。", "石泉涓涓響澗谷，山樹濯濯延雲烟。", "客程東西風袂翩，去者自去還者還。"]'),
('29c4d429-d9c3-43ac-b6dd-4da39542c89d','政仲留飲醉書長句','劉學箕','宋','宋诗','song-poetry','','[]','春歸無計堪留連，川原暗綠屯雲烟。',166,'全唐诗/poet.song.179000.json','["春歸無計堪留連，川原暗綠屯雲烟。", "涓涓澗谷聲潺潺，夜來急雨春風顛。", "天公知我愛山癖，晨光薄林曉日出。", "浮陰掃盡山屹立，疊嶂層巒凝黛濕。", "此時來訪故人居，羶葷爲我開兵厨。", "真珠滴槽不用沽，沉酣相忘於江湖。", "我不如阮公籍，相逢一醉六十日。", "君莫傚陶淵明，欲令明朝重抱琴。", "且須相從痛飲師，尊前落魄同襟期。", "何如沉沉深夜剪韭共春酌，細誦工部生前相遇銜杯詩。"]'),
('a298ab9e-45ee-4c50-97d8-a2dfd129d4dd','送連景昭歸三山用其韻  其一','劉學箕','宋','宋诗','song-poetry','','[]','秋風乘興下三山，不憚馳驅涉險艱。',64,'全唐诗/poet.song.179000.json','["秋風乘興下三山，不憚馳驅涉險艱。", "別酒醉來仍更酌，征鞍發去且須攀。", "身安豈畏路千里，道在元知命兩間。", "從此莫教情斷絕，尺書頻寄塞鴻還。"]'),
('8de367a1-9775-42ed-8a10-1ae7dcbac953','送連景昭歸三山用其韻  其二','劉學箕','宋','宋诗','song-poetry','','[]','得意難兼熊掌魚，功名隨分勿求餘。',64,'全唐诗/poet.song.179000.json','["得意難兼熊掌魚，功名隨分勿求餘。", "或先或後時而已，將廢將行命也歟。", "理性明中閒念慮，雲山深處著田廬。", "君歸政好携妻子，泉石尋盟飽讀書。"]'),
('3767b102-b274-49fb-9624-c9e5955acc03','侵曉書懷四絕句  其一','劉學箕','宋','宋诗','song-poetry','','[]','石泉宵泠泠，清響雜寒吹。',24,'全唐诗/poet.song.179000.json','["石泉宵泠泠，清響雜寒吹。", "恍驚山雨來，醒我一覺睡。"]'),
('cd08055f-6a52-4666-9bf0-49bfbc2b9415','侵曉書懷四絕句  其二','劉學箕','宋','宋诗','song-poetry','','[]','幽蟲聲唧唧，感此秋夜長。',24,'全唐诗/poet.song.179000.json','["幽蟲聲唧唧，感此秋夜長。", "起坐彈鳴琴，蘭釭炫餘光。"]'),
('6364054f-fb0f-49d0-b155-32bc4739f20e','侵曉書懷四絕句  其三','劉學箕','宋','宋诗','song-poetry','','[]','披衣啟外戶，晨光清可挹。',24,'全唐诗/poet.song.179000.json','["披衣啟外戶，晨光清可挹。", "綠樹閟蒼烟，遥認楓葉赤。"]'),
('5c7f3be8-6c62-4c2e-907b-1e112631251a','侵曉書懷四絕句  其四','劉學箕','宋','宋诗','song-poetry','','[]','疎星澹河漢，點點在秋水。',24,'全唐诗/poet.song.179000.json','["疎星澹河漢，點點在秋水。", "微瀾漾殘輝，曲沼過游鯉。"]'),
('9f7891e0-acf2-4e36-a91d-896d1d1649fc','田家  其一','劉學箕','宋','宋诗','song-poetry','','[]','稻熟田間笑老農，鼕鼕村鼓樂時豐。',32,'全唐诗/poet.song.179000.json','["稻熟田間笑老農，鼕鼕村鼓樂時豐。", "新篘自酌花甆椀，醉倒扶携夕照中。"]'),
('45faa838-08e7-433c-947b-77d7aa1f12e8','田家  其二','劉學箕','宋','宋诗','song-poetry','','[]','堆槃野柿間山梨，酒美雞肥稻滑匙。',32,'全唐诗/poet.song.179000.json','["堆槃野柿間山梨，酒美雞肥稻滑匙。", "婦子團圞常見面，一生寧識別離悲。"]'),
('58d7adfd-6e78-4888-a441-b84e967a79c1','環洲江氏園','劉學箕','宋','宋诗','song-poetry','','[]','欲覽環洲勝，維舟步石磯。',48,'全唐诗/poet.song.179000.json','["欲覽環洲勝，維舟步石磯。", "踏丹隨野色，穿翠任春霏。", "地迥知山遠，村彎覺水圍。", "東風輕薄甚，桃李亂荆扉。"]'),
('1412ca50-e1db-4244-82a1-12242d20977e','將口道中','劉學箕','宋','宋诗','song-poetry','','[]','沙平路軟足力健，麥細桑柔春意深。',32,'全唐诗/poet.song.179000.json','["沙平路軟足力健，麥細桑柔春意深。", "綠水一灣浮野鶒，青山兩岸喚幽禽。"]'),
('ba4b359b-1e7a-4d81-955d-90b34ec07cbe','妙湛寺','劉學箕','宋','宋诗','song-poetry','','[]','山徑盤紆露石根，一溪流水兩山雲。',32,'全唐诗/poet.song.179000.json','["山徑盤紆露石根，一溪流水兩山雲。", "齋餘緩步青松下，輸與蕭閒老惠勤。"]'),
('ac1c0710-b431-49b1-858c-e384d6f3e1f7','晚望','劉學箕','宋','宋诗','song-poetry','','[]','晚雨逆溪上，寒雲傍山飛。',36,'全唐诗/poet.song.179000.json','["晚雨逆溪上，寒雲傍山飛。", "白鷺去洲渚，潛魚泝灣磯。", "舉頭行跡少，唯見暮樵歸。"]'),
('0f658d16-cacf-4a3d-b9a4-be4938e24ed7','溪園','劉學箕','宋','宋诗','song-poetry','','[]','溪園闢平疇，左右接林麓。',48,'全唐诗/poet.song.179000.json','["溪園闢平疇，左右接林麓。", "沉沉水浮堰，泛泛潭轉曲。", "果木漸成行，臺榭亦營築。", "何時東風來，吹滿枝上綠。"]'),
('4ed5cfbf-cff4-4030-9011-0d54cc407490','栽竹','劉學箕','宋','宋诗','song-poetry','','[]','綠筠移種不多時，添我溪南一段奇。',32,'全唐诗/poet.song.179000.json','["綠筠移種不多時，添我溪南一段奇。", "會看明年春雨後，滿林頭角籜龍兒。"]'),
('63b5b490-a091-46d2-aee3-1c97eb38ddce','種梅','劉學箕','宋','宋诗','song-poetry','','[]','隠淪沖寂澹生涯，芍藥櫻桃厭艷華。',32,'全唐诗/poet.song.179000.json','["隠淪沖寂澹生涯，芍藥櫻桃厭艷華。", "剔亂剪緐疎影瘦，臨溪只合種梅花。"]'),
('5dd63fb8-eb9c-4ee1-8875-8d1ee3bef9c8','書懷','劉學箕','宋','宋诗','song-poetry','','[]','園成日以待東風，綠李黄梅已間叢。',64,'全唐诗/poet.song.179000.json','["園成日以待東風，綠李黄梅已間叢。", "種竹自期千戶等，舉杯誰伴八僊同。", "機忘鷗鳥情相狎，興適琴書趣獨窮。", "坎止流行隨所寓，樂天知命一閒翁。"]'),
('ce389b7c-00d9-403f-b479-1bd1fdf0f264','簡康姪求先君石山','劉學箕','宋','宋诗','song-poetry','','[]','見好山如見高人，遯世冀繭清浄身。',256,'全唐诗/poet.song.179000.json','["見好山如見高人，遯世冀繭清浄身。", "見拳石如接佳友，手摩挲愛逾瓊玖。", "我生嗜好不有冗長物，寓意蕭閒祇在青山并怪石。", "往年都梁得靈壁，名以催詩延座側。", "去載還自嶓冢江，女媧溪頭纔落帆。", "山靈見知情不凡，乞我清波一塊川墨塗巉巗。", "屏山嵯峩高雲衢，五畝下著吾儂居。", "窗扉面面挹山色，真山假山互崷崒。", "舊藏英道數峯碧，怪怪奇奇總拈出。", "一丘一壑在胸臆，烟雲盡向空齋集。", "君家一峯良可惜，埋沒庭除沙土蝕。", "尚思阿翁存手澤，何不遣歸慰岑寂。", "楚人亡弓楚人得，在彼在此理則一。", "小詩代簡言從容，子心坦蕩詎執違與從。", "儻令長鬚勤送似，待予大書特書榜曰飛來峰。"]'),
('0cff5362-fbce-4e27-a473-58836c6f7c31','宿興國寺方丈與客對牀','劉學箕','宋','宋诗','song-poetry','','[]','世間何事能感人，詩人題詠爲多情。',218,'全唐诗/poet.song.179000.json','["世間何事能感人，詩人題詠爲多情。", "我亦執筆書長吟，詩吟未竟情已盈。", "古稱白頭如新，傾蓋如故。", "何似祇今握手見肺肝，開口無毀譽。", "古稱共君一夜話，勝讀十年書。", "何似祇今對牀談子虛，醉歌咍臺笑廬胡。", "昨宵春月如晝明，與君聯詩到三更。", "今宵夜雨如盆傾，與君齁齁直到街鼓鳴。", "醒來莫問陰與晴，但聽簷溜飛泉聲。", "明朝又作穿雲行，巾紗杖竹鞵芒輕。", "遇酒酌彼兕觥，逢花賞其芳馨。", "見賢者如接芝蘭，對俗子譬之蚊蝱。", "勿與物忤競，勿爲事絆縈。", "陶然樂吾真，是謂羲皇人，是謂葛天民。"]'),
('0f1071a8-f8bc-4e8a-b93e-7054e459e643','秋池曉步敗荷萬柄一花挺然可愛伯益賦詩和韻錄呈元翰敬叟君明季僊求同賦','劉學箕','宋','宋诗','song-poetry','','[]','蕭瑟秋池撼曉風，江妃旋旆水雲空。',64,'全唐诗/poet.song.179000.json','["蕭瑟秋池撼曉風，江妃旋旆水雲空。", "未教零落千擎雨，尚借柔酣一點紅。", "弊蓋高低騷客賦，寒衣裁製楚人工。", "誰憐夜枕驚殘夢，恨在緐聲點滴中。"]'),
('cf4a91f7-70c8-4c1b-84bc-772a3acb6e87','楚騷有正有反予既以數語詠獨開荷花諸公寵和工甚輒拾餘意反作一章','劉學箕','宋','宋诗','song-poetry','','[]','一從炎暑變秋風，識破維摩色想空。',64,'全唐诗/poet.song.179000.json','["一從炎暑變秋風，識破維摩色想空。", "豈有三乘無盡法，尚憐孤艷十分紅。", "唯慙寡陋吟懷劣，却愛諸賢句法工。", "共倚欄桿休悵恨，典型猶在四筵中。"]'),
('5d22f770-6e5e-4448-b234-6767f29955dd','長句簡敬叟季僊兼呈端夫申父晦仲','劉學箕','宋','宋诗','song-poetry','','[]','士生樗散甘嘉遯，頫首衡茅敢尤怨。',272,'全唐诗/poet.song.179000.json','["士生樗散甘嘉遯，頫首衡茅敢尤怨。", "良朋益友肯顧臨，講貫漸摩篤明辨。", "年來瘖啞瓶守口，俗子污人如避箭。", "論交謾說笑金蘭，厚貌深情半譏訕。", "念君與我情不薄，一忝從遊一親眷。", "朅來終日坐書樓，喜劇論文幾昏旦。", "麯生風味亦不惡，抵死絕交良可嘆。", "胸中磊磈政須渠，吻噪腸枯頼澆灌。", "孟公舊不論升斗，驚座丰姿發奇觀。", "富文博學子游子，秀楚翹英穎鋒見。", "吾雖不敏逐後塵，斬將搴旗共酣戰。", "祇今便造無何有，相與神期遊汗漫。", "既無三雅伯仲叔，不有巨杯觶角散。", "請觀管輅揚子雲，欲作九原誰可喚。", "酒不離唇元乃就，三斗頓傾辭綺粲。", "二公洞達疏通豪，妙語仍煩下一轉。", "養浩堂中顒惠然，急吐才華染柔翰。"]'),
('5f78fb3b-f4ec-4ce9-8dcb-2f30f8d2185c','余少日不能持養志氣所暴多矣邇來方喜問學之有益也近築小樓藏書樓之下建堂名曰養浩七客落成以善養吾浩然之氣分韻得氣字','劉學箕','宋','宋诗','song-poetry','','[]','吾非北宮黝，挫若撻諸市。',180,'全唐诗/poet.song.179000.json','["吾非北宮黝，挫若撻諸市。", "吾非孟施舍，量慮三軍畏。", "一墮刺客流，一入力戰士。", "知一不知二，遂與聖賢異。", "周孔得其傳，偉哉孟軻氏。", "講明不動心，因問發奇秘。", "氣壹則動志，志一則動氣。", "浩然得所寄，知言有深味。", "嗟予篤學心，一暴十寒廢。", "立志苦不早，少豈達茲義。", "所適昧善惡，幾溺彼功利。", "事情更歷多，晚乃能自礪。", "日用根本原，至大至剛意。", "餒然行有慊，何謂塞天地。", "服膺先格言，造次顛沛是。"]'),
('2ededde6-a527-4045-b950-a2ac23e33b35','與政仲端夫敬叟季僊至舊圃采采芙蓉金菊之妙時之所當艷者江梅海棠爛然照目可無數語紀之爲書長句','劉學箕','宋','宋诗','song-poetry','','[]','秋陽杲杲秋月明，秋風泠泠秋露清。',304,'全唐诗/poet.song.179000.json','["秋陽杲杲秋月明，秋風泠泠秋露清。", "蕭騷池上萬松竹，鳳笙龍管吹秋聲。", "山亭與客坐夕陰，眼照萬象前橫陳。", "一年好處在此好，妙質欲紀難狀名。", "那知天上詩酒星，翩然馳鯨來玉京。", "浩然相對發思奇，句法普現千古情。", "詩成不用世間語，五言七字虛皇吟。", "霞明皎皎芙蓉城，香霏楚楚月魄精。", "海棠婉孌鬭緐艷，江梅冷淡同芳馨。", "東籬采采萬疊金，西疇更刈千頃秔。", "人生得此亦不惡，措辭莫謾悲愁生。", "先生年來真脫俗，看破世間榮與辱。", "胸懷坦蕩適四時，豈但芳華競馳逐。", "祇今忘物物忘我，物我兩忘機印可。", "不知門外秋水深，不識紛紛朝市心。", "榨頭新篘蟻初熟，芡盤剝珠茭切玉。", "是秋是春兩難分，折花薦酒酒痕濕。", "萬緣空處罷休休，八表神期汗漫遊。", "醉鄉廣大塵世促，明日酒醒詩載續。"]'),
('0c795c78-cbad-4380-b566-629bc07dfd33','和劉伯益嘲菊韻','劉學箕','宋','宋诗','song-poetry','','[]','虛隨斗轉屬中宵，草木凌兢菊粲條。',64,'全唐诗/poet.song.179000.json','["虛隨斗轉屬中宵，草木凌兢菊粲條。", "錢疊夕陽金偠㒟，蘂浮秋露玉鎸雕。", "不隨俗子媚時好，長伴幽人避世囂。", "冷炙殘杯愧徵逐，曲肱只合友顔瓢。"]'),
('9a7c4ee8-1d7f-480f-9011-9ff734b222ab','康姪招飲出示古洲所寄盆梅囑坐客賦詩分韻得言字','劉學箕','宋','宋诗','song-poetry','','[]','嵌空奇崛石一拳，綠蒲攢劍森且蕃。',224,'全唐诗/poet.song.179000.json','["嵌空奇崛石一拳，綠蒲攢劍森且蕃。", "虬梅屈折龍蜿蜒，蒼榦蘚蝕低盤根。", "瓊英已露冰樣白，香氣便覺凌芷蓀。", "吁嗟培養幾歲月，巧奪造化移小盆。", "晴窗諦玩意無斁，搜索物理究所原。", "方圓高大僅尺許，典章文獻皆具存。", "橫斜疎瘦無不備，宛若老樹生山園。", "鄉邦疇昔少曾見，此花何自來幽軒。", "云是古洲老詩伯，親手植此冰雪魂。", "不忘交舊情好密，春色分遺歸山樊。", "吾家小阮亦好事，美不獨擅招弟昆。", "更呼賓友同勝集，羅列槃饌開罍尊。", "舉杯對花與劇飲，情話款洽相笑言。", "歸來漸是東方白，醉帽欹傾風袖翻。"]'),
('40f97e63-7b83-49c8-aff7-b95f08474bae','飲東屯庶姪家賦臘梅和陳簡齋韻','劉學箕','宋','宋诗','song-poetry','','[]','釋迦黄面禪可誇，色想熏漬霜中葩。',98,'全唐诗/poet.song.179000.json','["釋迦黄面禪可誇，色想熏漬霜中葩。", "不然安得白玉蘂，而乃幻此黄金花。", "信知造化真有法，蜂鬚釀蜜蜜釀蠟。", "蠟凝花房豐不腴，桃李漫山焉可如。", "緐枝摘索燦栗玉，吟搜西郊信杖扶。", "少須夜窗疎影掛明月，是蠟是花君自別。"]'),
('a346f3df-9c5d-4960-83ed-e973fdcb3b54','北山園山石爲形勢買盜夜半擇其尤者竊去累日懷抱作惡賦詩以紀鬰鬰','劉學箕','宋','宋诗','song-poetry','','[]','素志薄利祿，壯年榮林丘。',240,'全唐诗/poet.song.179000.json','["素志薄利祿，壯年榮林丘。", "種樹疏間泉，鑿沼開中洲。", "堤平水瀰漫，徑遶竹浄修。", "梅塢夜月亂，松岡曉風飂。", "猶以景象淺，欲廣巗壑幽。", "疊石類奇品，置身將侶儔。", "磊塊質偉特，嵌空神琱鎪。", "廬阜几上得，巫峰坐中求。", "每想雲氣噓，遂覺烟練浮。", "曳杖日以樂，縱懷吟無休。", "一朝失警巡，赤眉行盜謀。", "夜半負之去，公然從狗偷。", "檢視所寇攘，嶙峋拔其尤。", "此情實難堪，遣命窮蹤由。", "風聲雖有聞，形勢莫可搜。", "吁嗟世道降，人弗士行修。", "竊玦入志慮，攫金甘輩流。", "不念溺所習，竟爲前哲羞。", "今吾理自喻，委心任去留。", "甑墮雖不顧，璧歸猶冀收。"]'),
('1c163433-d86a-4b42-bacb-b11695a5f103','送術士周柟歸東陽','劉學箕','宋','宋诗','song-poetry','','[]','射策彈冠莫浪言，經丘尋壑且隨緣。',64,'全唐诗/poet.song.179000.json','["射策彈冠莫浪言，經丘尋壑且隨緣。", "誰能守分閒居世，自斷此生休問天。", "久矣知君該妙理，今焉過我話流年。", "歲寒事業相期重，欲植孤松驗果然。"]'),
('97a30a10-3691-48b5-8906-d1fc289268f8','春夜對月彈琴有懷','劉學箕','宋','宋诗','song-poetry','','[]','一春春雨連春陰，今夕何夕月滿林。',160,'全唐诗/poet.song.179000.json','["一春春雨連春陰，今夕何夕月滿林。", "舉頭遥望星漢碧，皎皎明鏡懸東岑。", "欄桿浩歎三顧影，有酒有酒誰與斟。", "我思兩弟怨以喑，邈不可見愁締心。", "含愁更奏綠綺琴，匣中埃蠹塵土侵。", "解絃更張試促軫，怨入懷抱難成音。", "兩君青春竟瓶沉，天闊悵望商與參。", "高高在上杳難詰，矯首涕泗憂思深。", "欲結今生未了因，尚蘄來世盟可尋。", "君遊九泉聞不聞，安知阿兄心悲吟。"]'),
('470d7f95-ff0e-4882-b909-a6b90d89249f','瓊花  其一','劉學箕','宋','宋诗','song-poetry','','[]','團簇緐英玉碎圓，露晞日暖欲生烟。',32,'全唐诗/poet.song.179000.json','["團簇緐英玉碎圓，露晞日暖欲生烟。", "親從后土分奇種，不是人間聚八僊。"]'),
('3eb65133-e412-49de-9b5c-87b93aefe78d','瓊花  其二','劉學箕','宋','宋诗','song-poetry','','[]','蕃釐觀裏舊經遊，五月曾看綠葉稠。',32,'全唐诗/poet.song.179000.json','["蕃釐觀裏舊經遊，五月曾看綠葉稠。", "今日家園玉摶樹，春風吹夢到揚州。"]'),
('41b9faf6-4c09-46d9-ad3d-8e64707c6789','送庾姪親迎延平李先生家','劉學箕','宋','宋诗','song-poetry','','[]','庾郎吾家千里駒，朝莫勤苦讀父書。',192,'全唐诗/poet.song.179000.json','["庾郎吾家千里駒，朝莫勤苦讀父書。", "少年綽有老成態，月旦考訂評鄉閭。", "明當別我擇賢妃，結束琴劍誰挽裾。", "春空吹晴惠風暢，烟草弄色和氣舒。", "野橋融洩柳絮合，石岸慘愴鳴鶢鶋。", "乘龍有期弗獲餞，數椽政葺淵明廬。", "旅愁冥思莫排遣，離恨掛臆難掃除。", "况當春晚氣暄淑，著人欲醉甘醴如。", "修程所囑善養攝，禮畢蚤辦雙輪輿。", "婦翁傳道世大儒，習俗再使淳古初。", "稔知賢舅繼家學，子如從之師有餘。", "歸來阿叔待審訂，義路禮門從廣居。"]'),
('ee22e134-d02e-4e5f-af8f-2f91056adcb5','傷歌行','劉學箕','宋','宋诗','song-poetry','','[]','原原而來，白日跳丸莫可留。',106,'全唐诗/poet.song.179000.json','["原原而來，白日跳丸莫可留。", "混混而去，青春過隙不能返。", "誰憐生者長自懽，不念死者日益遠。", "吁嗟此理從古然，世事浮雲共舒卷。", "我生顧影空伶仃，鴈序零落如曉星。", "悠悠天道不可語，黯黯悲恨無時停。", "可堪嫠婦束行李，挈取稚子同歸寧。"]'),
('7254db88-1bb9-4f2c-9e95-d04c5f8c33b8','夏雨歎','劉學箕','宋','宋诗','song-poetry','','[]','君不見去年六月田作龜兆拆，禱祠乞雨遍村陌。',229,'全唐诗/poet.song.179000.json','["君不見去年六月田作龜兆拆，禱祠乞雨遍村陌。", "時當饑饉民不聊，穀貴有錢無處糴。", "今年六月歲幸豐，十日一雨五日風。", "市積粟米價不長，有穀無錢人更窮。", "吁嗟此道孰識測，街頭細聽老農說。", "往年兵興錫賫多，官會頒行姑濟急。", "舊會既收新會降，所司稱提苦無策。", "朝廷明許同見錢，便當流轉同貨泉。", "不應州縣首逆旨，榜示牆壁徒紛然。", "庫頭令賣小印齪，輸納租稅私相權。", "非錢買齪用不得，執幣嘖嘖煩有言。", "遂令百姓愈惶惑，行之與否誰使然。", "小臣空負濟時術，閶闔九重無路入。", "何當奏計承明廬，傾倒賈生長太息。"]'),
('89647281-c48e-4ec7-8eb0-7f40d012257b','廞庭自三山送荔枝分韻得緗字','劉學箕','宋','宋诗','song-poetry','','[]','炎精孕秀儲氣詳，荔枝結實魁羣芳。',390,'全唐诗/poet.song.179000.json','["炎精孕秀儲氣詳，荔枝結實魁羣芳。", "我有猶子客南服，千里眷念情不忘。", "星馳走寄一千顆，伏暑火熾勞取將。", "筠籃初開氣芬溢，稍覺四座浮清香。", "驪珠燦爛光奪目，琱盤飣餖羅滿堂。", "先廟未獻不敢嗅，色味雖鮮那敢嘗。", "少須祀畢分送似，賓友拉至紛攫攘。", "絳囊初剝拆霞縷，玉臉旋綻流天漿。", "手持奈此水晶粒，地積更詫雲錦裳。", "海鄉因記少日好，遶樹食啗高價償。", "婆娑碧綠擁平野，丹苞縠皺暉朝陽。", "初驚星火爭燿熠，久訝彩鳳爭翱翔。", "薰風吹開碧雲葉，綠水宛類翻頳魴。", "只今老大將底用，食此感激意故長。", "君不見方紅陳紫列紺緗，三十二品裁中郎。", "丁香核小味甘潔，何似釵頭十八孃。", "天生美實限南北，長安路遠價愈强。", "只今生食享至味，不數家漬鹽蒸方。", "又不見宣靖文物全盛時，貢輸不減開元唐。", "輶車縱橫繡衣使，海內騷動封紙黄。", "妙品人家那可得，置以走轍加浮航。", "似聞供上祗纖悉，往往盡入公侯王。", "驪山往事不古鑒，艮嶽馴致烽烟狂。", "祇今故老尚能說，空使悲憤縈肝腸。"]'),
('8e7843e0-27f3-436e-ba2b-7ed8ec75be00','梅花自秦漢而下無一語焉至宋鮑參軍照始賞其韻而寓之詩然則梅之見於賦咏者實自明遠始也用韻二首 落梅','劉學箕','宋','宋诗','song-poetry','','[]','片片玉零亂，寒風生驚嗟。',56,'全唐诗/poet.song.179000.json','["片片玉零亂，寒風生驚嗟。", "凍雀相飛鳴，俛啄苔上花。", "鳴飛饑腸不能實，却上烟梢照斜日。", "愁逢冷淡太寂寥，不似春風艷陽質。"]'),
('96c2e0fc-679b-4ed8-9817-f6facfb8ec69','梅花自秦漢而下無一語焉至宋鮑參軍照始賞其韻而寓之詩然則梅之見於賦咏者實自明遠始也用韻二首 蠟梅','劉學箕','宋','宋诗','song-poetry','','[]','色異政自貴，香清未堪嗟。',56,'全唐诗/poet.song.179000.json','["色異政自貴，香清未堪嗟。", "靈蜂擅造化，幻作姚家花。", "丰姿輕明體充實，染透薔薇毓晴日。", "從稱紫暈黄檀心，桃李依然是凡質。"]'),
('e1412655-5278-48de-96bd-47833d0f30a0','二月二日東屯感懷','劉學箕','宋','宋诗','song-poetry','','[]','春波渺渺柳依依，芳草侵街蛺蝶飛。',64,'全唐诗/poet.song.179000.json','["春波渺渺柳依依，芳草侵街蛺蝶飛。", "萬景橫陳空物是，一區幽僻念人非。", "沉悲逝者去不返，自挽已而今曷歸。", "回首鶺鴒原上路，感懷贏得淚沾衣。"]'),
('a3e1c092-238f-4b53-b918-c8a3efa265c8','野館','劉學箕','宋','宋诗','song-poetry','','[]','野館春歸後，橫塘度柳綿。',48,'全唐诗/poet.song.179000.json','["野館春歸後，橫塘度柳綿。", "輕風翻麥浪，細雨落花天。", "草褥迷三徑，苔紋疊萬錢。", "山禽自呼喚，水竹倍清妍。"]'),
('5b240a67-cf7f-4822-9369-aa920c8da477','閒居即事','劉學箕','宋','宋诗','song-poetry','','[]','山水縈洄處士家，春林環合翠交加。',64,'全唐诗/poet.song.179000.json','["山水縈洄處士家，春林環合翠交加。", "行吟溪岸牽垂柳，坐倚欄桿數落花。", "萬卉萬葩天長養，一丘一壑我生涯。", "長瓶芳草陶然處，不向愁邊感物華。"]'),
('633d43bc-ab83-4fee-97cf-d4d52e949d91','紫溪莊即事','劉學箕','宋','宋诗','song-poetry','','[]','嶂碧楓丹色倍鮮，路回烟裊認前川。',64,'全唐诗/poet.song.179000.json','["嶂碧楓丹色倍鮮，路回烟裊認前川。", "霜陰釀晚意將雨，風厲裂雲時見天。", "古木葉彫烏矍鑠，平田沙泠鷺聯拳。", "稻粱割盡村原迥，落日牛羊傍水眠。"]'),
('80de5b46-4038-4cf3-a836-50cef89b10f9','雲際峽中','劉學箕','宋','宋诗','song-poetry','','[]','野渡烟迷谷，寒潭水漲沙。',48,'全唐诗/poet.song.179000.json','["野渡烟迷谷，寒潭水漲沙。", "入雲千萬岫，出塢兩三家。", "澗古泉仍石，山空菊自花。", "柳塘冰欲結，相對祇棲鴉。"]'),
('4f42d2ed-0b7e-41c0-9366-29abebc1a934','西巗觀瀑水簡沈莊仲三首  其一','劉學箕','宋','宋诗','song-poetry','','[]','雲潤衣裾夕露霑，懸崖一水散疎簾。',32,'全唐诗/poet.song.179000.json','["雲潤衣裾夕露霑，懸崖一水散疎簾。", "精廬隠約青山下，縹緲飛甍出畫檐。"]'),
('f9e75eac-d605-4863-b7f8-039aea6195c6','西巗觀瀑水簡沈莊仲三首  其二','劉學箕','宋','宋诗','song-poetry','','[]','踏石穿雲野興添，傍崖昌歜綠纖纖。',32,'全唐诗/poet.song.179000.json','["踏石穿雲野興添，傍崖昌歜綠纖纖。", "幽人近得安心術，擷滿湘籃意未厭。"]'),
('ad185332-c584-4ac4-85b5-d5c988edabb6','西巗觀瀑水簡沈莊仲三首  其三','劉學箕','宋','宋诗','song-poetry','','[]','暮雲新月一鈎鎌，歸路溪風動碧蒹。',32,'全唐诗/poet.song.179000.json','["暮雲新月一鈎鎌，歸路溪風動碧蒹。", "美酒不妨車後載，夜深無處認青帘。"]'),
('76f92e53-fee2-439d-913c-f3f3e2a434e0','窯前小酌和外舅韻','劉學箕','宋','宋诗','song-poetry','','[]','五馬旌旗去路長，筍輿穿翠度羊腸。',64,'全唐诗/poet.song.179000.json','["五馬旌旗去路長，筍輿穿翠度羊腸。", "霜餘綠橘漿尤美，秋晚黄花氣倍香。", "勝景形容詩入詠，羈情排遣酒傳觴。", "風流太傅何須詫，獨載東山窈窕孃。"]'),
('064ba2bc-9842-4d19-8825-7a01e0271af6','題壁','劉學箕','宋','宋诗','song-poetry','','[]','午日柳陰正，曉風花氣新。',24,'全唐诗/poet.song.179000.json','["午日柳陰正，曉風花氣新。", "川明魚泳水，林靜鳥啼春。"]'),
('65e2ec0c-2b06-40a5-ac8a-164ed80e045c','遊九曲','劉學箕','宋','宋诗','song-poetry','','[]','三十六峯高插天，來遊誰不慕真僊。',32,'全唐诗/poet.song.179000.json','["三十六峯高插天，來遊誰不慕真僊。", "幔亭舊事隨流水，空自溪頭喚釣船。"]'),
('f59fd7ef-77cd-4299-af61-4853357f7e7c','武夷山','劉學箕','宋','宋诗','song-poetry','','[]','十年不到武夷山，幾與神仙絕往還。',64,'全唐诗/poet.song.179000.json','["十年不到武夷山，幾與神仙絕往還。", "九曲依然青嶂裏，一峰仍插畫檐間。", "潺湲野水溪隨轉，縹緲秋雲意自閒。", "我見溪山渾似舊，溪山見我鬢毛斑。"]'),
('27adbb39-fdc1-41f2-b23d-a23082cbc97a','鵝湖道中','劉學箕','宋','宋诗','song-poetry','','[]','去城十里路盤紆，幽徑平岡駕小輿。',32,'全唐诗/poet.song.179000.json','["去城十里路盤紆，幽徑平岡駕小輿。", "認得鵝湖山下路，綠松巗畔擁僧廬。"]'),
('8c5aa7dc-f167-4882-96dc-e68f6fd28a17','分題得雪浪齋石','劉學箕','宋','宋诗','song-poetry','','[]','四海廣大萬山立，奇怪崷崒幾巗石。',144,'全唐诗/poet.song.179000.json','["四海廣大萬山立，奇怪崷崒幾巗石。", "棄而違者庸有之，愛樂每恨沙土蝕。", "忽然一旦獲所遇，刮垢磨光呈美質。", "騷人諷誦脫諸口，世寶不減和氏璧。", "東坡居士豈好奇，偶爾得之心良怡。", "巨盆沃以清漣漪，脈絡雪浪縱橫施。", "平生我屢哦此詩，恨不見石心飛馳。", "何人志古墨寫跡，剡藤染就貼東壁。", "似是而非不可知，誦詩對畫長嗟咨。"]'),
('09587b3c-4b5b-46b1-88af-f9a2178e8a40','伯益以玉舟相酬酢席上口占二絕  其一','劉學箕','宋','宋诗','song-poetry','','[]','新年殊未有吟搜，美酒醺人不自由。',32,'全唐诗/poet.song.179000.json','["新年殊未有吟搜，美酒醺人不自由。", "多謝主人情意厚，玉舟三度轉船頭。"]'),
('ba265661-75f4-44fc-8418-65aed6a342ef','伯益以玉舟相酬酢席上口占二絕  其二','劉學箕','宋','宋诗','song-poetry','','[]','元正講禮詎能忘，便辱留連設酒漿。',32,'全唐诗/poet.song.179000.json','["元正講禮詎能忘，便辱留連設酒漿。", "笑指一船春盎盎，稽山應未愧知章。"]'),
('dff5df01-7766-4743-bf43-b0eeb926fa89','次劉伯益三詠韻 方竹','劉學箕','宋','宋诗','song-poetry','','[]','烟梢修矗畫簷低，春曉叢疎綠玉枝。',64,'全唐诗/poet.song.179000.json','["烟梢修矗畫簷低，春曉叢疎綠玉枝。", "節立孤高虛靜處，身持敬義直方時。", "清風戛玉聲摇佩，明月篩金影散墀。", "寄語幽人勤愛護，莫教斵削俗髠知。"]'),
('9875f83f-e262-455a-b9b2-35544b17a287','次劉伯益三詠韻 耐冬子','劉學箕','宋','宋诗','song-poetry','','[]','雪裏婆娑結子低，山童應亦訝卑枝。',64,'全唐诗/poet.song.179000.json','["雪裏婆娑結子低，山童應亦訝卑枝。", "幾年開落慙無取，一日搜吟信有時。", "紅實纍纍臨曲砌，丹苞簇簇耀幽墀。", "古今未見多題品，却恐君詩取世知。"]'),
('338d3e94-7615-4750-8451-36fb397ecf68','次劉伯益三詠韻 金鳳花','劉學箕','宋','宋诗','song-poetry','','[]','鮮華五色翅飛低，不比尋常鵲踏枝。',64,'全唐诗/poet.song.179000.json','["鮮華五色翅飛低，不比尋常鵲踏枝。", "德茂翱翔丹穴日，琴清調弄紫庭時。", "羞同鷄鶩喧堂宇，笑把金銅鑄殿墀。", "何似花欄自生長，幽芳端不在人知。"]'),
('386ac252-cddc-4947-a76c-676489ab9a12','度姪從事行親迎之禮於傅氏朋舊各賦詩贈別老叔雖凄凉阮巷老大謝家可無數語以餞行色','劉學箕','宋','宋诗','song-poetry','','[]','曉露沁桃臉，東風摇柳絲。',240,'全唐诗/poet.song.179000.json','["曉露沁桃臉，東風摇柳絲。", "小雨斂香塵，山川發華滋。", "今晨天氣新，滿路春融怡。", "祖餞賓從懽，喧譁車馬馳。", "問云何爲者，吾子有所之。", "所之道匪遥，求友貴及時。", "婚婣古則然，制禮今或虧。", "琴瑟因好合，蘋蘩尤謹持。", "擇耦得賢柔，令淑全婦儀。", "豈但榮己身，實將慰母慈。", "冰翁君子儒，材術世吏師。", "聽訟鑑燭物，明不差毫釐。", "子既獲晤承，朝夕廣見知。", "士生三日別，猶以刮目爲。", "此行諒經月，歸計春仲期。", "非吳下阿蒙，行可驗措施。", "心廣體自胖，勿溺小智私。", "門戶要人興，責望夙所蘄。", "廟見事唯謹，遄邁毋或遲。", "語直殆逆耳，願當深致思。"]'),
('5558b684-c34a-4350-9de9-d816c206be44','寄謝叔通宗兄題耕隠詩韻','劉學箕','宋','宋诗','song-poetry','','[]','雲隴躬耕新雨足，東阡南陌水奫淪。',64,'全唐诗/poet.song.179000.json','["雲隴躬耕新雨足，東阡南陌水奫淪。", "市朝軒紱秋多事，鹿豕漁樵欣與隣。", "我欲爲謀三畝地，君能來共一犂春。", "蚤知世路風波險，俛首無令愧野人。"]'),
('6110d593-f953-41e3-9f1d-2fd49187dd1b','寄題吳介夫專壑七詠 壽藏','劉學箕','宋','宋诗','song-poetry','','[]','負鍤劉伯倫，坐壙司空圖。',24,'全唐诗/poet.song.179000.json','["負鍤劉伯倫，坐壙司空圖。", "誰爲後來達，息菴與之俱。"]'),
('d5f78687-28b1-49d4-9a7f-c63bddd16e6e','寄題吳介夫專壑七詠 息菴','劉學箕','宋','宋诗','song-poetry','','[]','日出機事生，日入羣動息。',24,'全唐诗/poet.song.179000.json','["日出機事生，日入羣動息。", "吁嗟利名子，逐逐何所急。"]'),
('49ebde81-ede7-43bc-ab65-8208264cb727','寄題吳介夫專壑七詠 止宿','劉學箕','宋','宋诗','song-poetry','','[]','大路古茅塞，問津欲何從。',24,'全唐诗/poet.song.179000.json','["大路古茅塞，問津欲何從。", "雞黍相款留，賢哉植杖翁。"]'),
('5a836bd9-31c8-4a2a-8434-c7bc77a9047d','寄題吳介夫專壑七詠 負閒','劉學箕','宋','宋诗','song-poetry','','[]','鍾鼎本玩世，富貴徒苦人。',24,'全唐诗/poet.song.179000.json','["鍾鼎本玩世，富貴徒苦人。", "何似天地間，蕭然一閒身。"]'),
('f765cef3-01f5-46bd-9190-f5de517ee450','寄題吳介夫專壑七詠 洪澤','劉學箕','宋','宋诗','song-poetry','','[]','酌彼洪澤水，吾知非盜泉。',24,'全唐诗/poet.song.179000.json','["酌彼洪澤水，吾知非盜泉。", "舉世望甘霖，喚起神蟄淵。"]'),
('91c9ea2a-088d-4762-86a8-66a060d0450f','寄題吳介夫專壑七詠 橫舟','劉學箕','宋','宋诗','song-poetry','','[]','山崦少人渡，夕陽橫釣艖。',24,'全唐诗/poet.song.179000.json','["山崦少人渡，夕陽橫釣艖。", "顛風捲重陰，急浪揚層波。"]'),
('d3ff1b1f-463a-479f-9404-925599b17e18','寄題吳介夫專壑七詠 專壑','劉學箕','宋','宋诗','song-poetry','','[]','竹原與草堂，轉眼事非舊。',24,'全唐诗/poet.song.179000.json','["竹原與草堂，轉眼事非舊。", "一壑今獨專，造物有付授。"]'),
('d3c487fd-ee2e-42cf-b6c8-007b644076f2','余讀林子仁詩云君心恨不走天涯不比衰翁只戀家最是橫塘黄葉路今年無伴折梅花時吟此詩念劉伯益之未返偶檢校前村南枝的皪已三花五蘂矣忽伯益自黄檗歸訪余折歸插玩知友朋之念有同然者對花劇飲用韻述懷','劉學箕','宋','宋诗','song-poetry','','["\u897f\u6e56"]','梅邊春興浩無涯，長憶西湖處士家。',32,'全唐诗/poet.song.179000.json','["梅邊春興浩無涯，長憶西湖處士家。", "我政念君君過我，夜窗同共醉疎花。"]'),
('43e90d62-b5f4-4b7f-942e-937d4e11b4b9','妾薄命','劉學箕','宋','宋诗','song-poetry','','[]','佳人命薄今古悲，苦樂在人知者誰。',192,'全唐诗/poet.song.179000.json','["佳人命薄今古悲，苦樂在人知者誰。", "鏡鸞窺損春黛眉，洞房不出藏繡幃。", "二十許嫁豪家兒，阿爺已受筐篚儀。", "心旌暗許良人隨，那知中道前議非。", "父母反覆志願違，嫁歸只得隨身衣。", "金幣粧飾無所齎，婦德婦容雖守持。", "阿姑色厲妯娌嗤，良人輕賤恩意虧。", "春波不似鴛鴦齊，春風不如雙燕飛。", "妾非無聲不敢啼，妾非無淚不敢垂。", "此身自恨生不時，怨讎父母將何爲。", "不如携將六尺帛，黄泉冥行與世辭。", "父母安用深致思，此身期與良人知。"]'),
('ccfd9380-b1d3-45ab-8ebe-c9d00734a20d','中秋分韻得雲字成三百言','劉學箕','宋','宋诗','song-poetry','','[]','今秋苦淫雨，漲汐添溪濆。',288,'全唐诗/poet.song.179000.json','["今秋苦淫雨，漲汐添溪濆。", "新凉值月夕，密靄高燦雯。", "稽首告天公，懇念心良勤。", "天公知意誠，感應若有聞。", "須臾檄豐隆，蘋末生鱗紋。", "庭皋一震拂，隴首飛秋雲。", "忽然朗穹昊，萬象蒙奇勛。", "舉頭見松梢，光照草樹分。", "乾坤兩瑩徹，爛白無邊垠。", "我歌忽如狂，我醉茫如薰。", "桂酒雜椒漿，醖釀騰馨芬。", "皓魄耿素懷，幽思殊不羣。", "泠然冰雪腸，頓醒麯糵醺。", "便欲浥沆瀣，盤饌遺羶葷。", "遥望瓊樓僊，霧綃青霞裙。", "何當下招呼，上征離塵氛。", "去年當此時，浩飲逢諸君。", "今載復肯來，持杯共論文。", "相從豈無他，羣聚徒飛蟁。", "苟得嗜利輩，抑何掛牙齦。", "豪傑所願交，黄金勝千斤。", "喜得詩謫仙，恨去髯將軍。", "衆子賢共推，奚用區蕕薰。", "愛客綽祖風，滿席生歡欣。"]'),
('8e735960-4191-491c-ac69-488ea6935c1f','賦祝次仲八景 瀟湘夜雨','劉學箕','宋','宋诗','song-poetry','','[]','移艘繫灣浦，傾篷聲更豪。',36,'全唐诗/poet.song.179000.json','["移艘繫灣浦，傾篷聲更豪。", "謾起湘妃恨，長歌靈均騷。", "曉汐漲何許，微茫泛江皋。"]'),
('fbec2f86-45e2-4d2f-b2cc-525cd2e66703','賦祝次仲八景 江天暮雪','劉學箕','宋','宋诗','song-poetry','','[]','雲癡天四合，密雪灑石矼。',36,'全唐诗/poet.song.179000.json','["雲癡天四合，密雪灑石矼。", "野渡滅行跡，岸沙橫孤艭。", "誰憐鶴髮翁，披簑釣寒江。"]'),
('35d90ad2-9b1a-4487-8d4e-9b8dba00c3fe','賦祝次仲八景 山市晴嵐','劉學箕','宋','宋诗','song-poetry','','[]','貿易足魚米，相逢話桑麻。',36,'全唐诗/poet.song.179000.json','["貿易足魚米，相逢話桑麻。", "村墟人蟻紛，日夕山氣佳。", "酒賤醉甆甌，樵漁自生涯。"]'),
('df2620cb-28ac-4750-adb6-e3b9f952a9a2','賦祝次仲八景 烟寺晚鐘','劉學箕','宋','宋诗','song-poetry','','[]','鐘聲烟際來，佛屋棲雲端。',36,'全唐诗/poet.song.179000.json','["鐘聲烟際來，佛屋棲雲端。", "回飆度崖谷，疎韻出林巒。", "東岫上明月，歸僧濯清湍。"]'),
('fc2a9d76-1afc-45a9-bc1e-380a01d8193d','賦祝次仲八景 漁村晚照','劉學箕','宋','宋诗','song-poetry','','[]','輕簑著篷背，日暮漁者還。',36,'全唐诗/poet.song.179000.json','["輕簑著篷背，日暮漁者還。", "新月印淺水，夕陽生亂山。", "誰歌采菱詞，隠隠過前灣。"]'),
('e33eebf8-c561-4a3c-b2ca-b5ffd62cc9af','賦祝次仲八景 洞庭秋月','劉學箕','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','木落露君山，空明夜氣浮。',36,'全唐诗/poet.song.179000.json','["木落露君山，空明夜氣浮。", "冰輪揩鑑浄，皓彩漾波流。", "空外數聲笛，孤吟人倚樓。"]'),
('9369af31-09d1-4e5a-a068-1196bb2f2726','賦祝次仲八景 平沙落鴈','劉學箕','宋','宋诗','song-poetry','','[]','水落洲渚闊，天寒風雪微。',36,'全唐诗/poet.song.179000.json','["水落洲渚闊，天寒風雪微。", "自雲排序下，聚翮與沙依。", "饑啄蘆葦根，何時稻粱肥。"]'),
('902eb876-6a51-4969-8cf8-a37221fe806b','賦祝次仲八景 遠浦歸帆','劉學箕','宋','宋诗','song-poetry','','[]','歸鷺林邊白，落霞天際明。',36,'全唐诗/poet.song.179000.json','["歸鷺林邊白，落霞天際明。", "蒲帆載風急，征棹逐鷗輕。", "稚子候江滸，遥聞嬉笑聲。"]'),
('ababbeb8-815b-4396-95f8-044f211f9b2d','僊洲呈劉伯益沈莊仲','劉學箕','宋','宋诗','song-poetry','','[]','杜門久經時，老我徒謬悠。',168,'全唐诗/poet.song.179000.json','["杜門久經時，老我徒謬悠。", "平生山水心，汩汩不暇謀。", "今辰定何辰，木落風露秋。", "忘懷兩佳士，共約來僊洲。", "杖藜欣躋攀，空濛翠烟浮。", "解带小盤礴，尋勝還經丘。", "捫蘿坐石冷，俯澗穿林幽。", "露重巾屨濕，涉歷青山頭。", "瀑泉盡生寒，晴雪散不收。", "蜒蜿下大壑，一闖千丈虬。", "歸來坐危亭，興與孤雲留。", "野草爲誰好，巗花徒爾愁。", "昔賢有遺蹤，俯仰歲月流。", "慨嘆不自禁，陶然聊消憂。"]'),
('d73deb28-6c34-442d-ad1c-1db36247233d','密菴題柱二首  其一','劉學箕','宋','宋诗','song-poetry','','[]','清鐘靜室破寂歷，灝氣空山生泬寥。',32,'全唐诗/poet.song.179000.json','["清鐘靜室破寂歷，灝氣空山生泬寥。", "長林風送澗水急，聒枕宛似春江潮。"]'),
('635070e5-1187-458b-a0b3-f99330d82a76','密菴題柱二首  其二','劉學箕','宋','宋诗','song-poetry','','[]','五更清夢雞喚醒，八月好景詩爲催。',32,'全唐诗/poet.song.179000.json','["五更清夢雞喚醒，八月好景詩爲催。", "秋蟲夜靜野禽語，風木天寒山雨來。"]'),
('1a35679e-f882-4560-b4ce-cc4252331f41','責庲','劉學箕','宋','宋诗','song-poetry','','[]','我生不辰八歲孤，伯父薨逝叔父無。',352,'全唐诗/poet.song.179000.json','["我生不辰八歲孤，伯父薨逝叔父無。", "長纔十五立志苦，不敢怠惰知讀書。", "汝生父子不識面，母慈育字如捧珠。", "那知汝更命苦極，八齡甫及母亦殂。", "幸有阿叔相持扶，叔亦痛念同氣餘。", "辛勤鞠養力盡瘁，五載爲汝六請師。", "固知門戶要人興，切切訓誨口欲枯。", "有言弗聽日益懶，乖劣氣習移下愚。", "朅來值我有行役，恐汝質變爲小夫。", "携俱不憚數千里，跳走健勝猿與狙。", "水行爲汝愛江湖，出陸每愁山險紆。", "川途憂愁念慮苦，摩拊豈啻親子如。", "傍舟終日撈蝦魚，坐輿人夫肩□□。", "□呶徒自費牙頰，事不獲己施鞭蒲。", "潛窺諦視不少改，謔浪笑傲仍前初。", "聖經有味懶不讀，對字粗曉平側呼。", "吾家七世身業儒，忠孝學術誇鄉閭。", "汝當更明所自出，挺挺當代文公朱。", "不悛祇爲先德羞，失教何異犬馬豬。", "稍長面目益可憎，儕輩戲弄人見疎。", "我今極口復汝說，速宜悔念毋忽諸。", "嬉遊儻更不檢束，命也奈何吾已夫。"]'),
('a1205d3d-07a4-44d7-aeaf-4444f0448166','光化儲丈晨興摘郡圃桃見惠每顆有重十三兩者他州未嘗見頃讀鄴中記勾鼻桃有重二觔者每竊笑之觀此信不誣矣光化去京止六七百里且地脈肥沃疑承平時得種來植','劉學箕','宋','宋诗','song-poetry','','[]','金盤磊磈大如瓜，照乘驪珠未足誇。',64,'全唐诗/poet.song.179000.json','["金盤磊磈大如瓜，照乘驪珠未足誇。", "大矣芳苞含美實，爛然紅臉燦朝霞。", "臙脂細擘漿流液，珠琲輕揮露带華。", "一洗宿酲牙頰爽，瑶池如宴母僊家。"]'),
('2aca42b3-350f-4ef3-962c-248e801344ff','安康中秋書懷','劉學箕','宋','宋诗','song-poetry','','[]','去年中秋吾廬成，月華逾晝風露清。',112,'全唐诗/poet.song.179000.json','["去年中秋吾廬成，月華逾晝風露清。", "今年中秋來安康，風凉雨冷天無光。", "去年把酒諸子與，月落尊空未歸去。", "今年把酒興如故，有月無月不須慮。", "婦翁歡喜婿遠來，阿婦見爺雙靨開。", "是風是雨是明月，管甚陰晴與圓缺。", "但願吾身益强健，莫使骨肉嘆南北。"]'),
('c7e74ed1-4aa0-4c7c-801a-71d2a9aea25f','七禽詠 貫錢石八豆','劉學箕','宋','宋诗','song-poetry','','[]','貫錢石八豆，充腸備粱糗。',56,'全唐诗/poet.song.179000.json','["貫錢石八豆，充腸備粱糗。", "飽嬉遊手兒，初不事耕耨。", "好衣好食街市女，汗珠滴滴田婦苦。", "夫耘婦餉日卓午，朝夕南山捕蟲鼠。"]'),
('2469628d-00f3-4cc9-a98c-0153f2524fbb','七禽詠 不如歸去','劉學箕','宋','宋诗','song-poetry','','[]','不如歸去，愁綠怨紅春欲暮。',57,'全唐诗/poet.song.179000.json','["不如歸去，愁綠怨紅春欲暮。", "汝勸行人歸，行人勸汝住。", "鳴聲不住良苦辛，啼得血流無用處。", "不如歸去吾今歸，千聲萬聲爾何爲。"]'),
('f856d1af-9d92-4706-9a1d-e35902f2904f','七禽詠 泥滑滑','劉學箕','宋','宋诗','song-poetry','','[]','泥滑滑，泥滑滑，前聲住，後聲發。',64,'全唐诗/poet.song.179000.json','["泥滑滑，泥滑滑，前聲住，後聲發。", "不道去年冬沒雪，今年春早已三月。", "月如金，日如血，大麥小麥盡枯竭。", "使君祈禱走阡陌，汝切勿啼泥滑滑。"]'),
('2a68413b-681e-4a6d-811e-75c24618ada0','七禽詠 行不得哥哥','劉學箕','宋','宋诗','song-poetry','','[]','行不得，喚阿兄。',48,'全唐诗/poet.song.179000.json','["行不得，喚阿兄。", "向晚夕，猶悲鳴。", "坦坦之途萬人履，跛鱉不休跬千里。", "汝行不上可奈何，日暮途遠無蹉跎。"]'),
('e2c408b0-6832-40d3-956d-c6929170f6cc','七禽詠 姑惡','劉學箕','宋','宋诗','song-poetry','','[]','姑惡姑惡家道立，汝爲人婦供婦職。',56,'全唐诗/poet.song.179000.json','["姑惡姑惡家道立，汝爲人婦供婦職。", "婦德婦功汝不能，抱恨歿身空怨抑。", "不化秋柏食，不化山頭石。", "化作春鳥鳴，號呶何苦極。"]'),
('fd15c135-ffca-4a6e-ae1d-c9a8ccb016a3','七禽詠 提葫蘆沽美酒','劉學箕','宋','宋诗','song-poetry','','[]','提葫蘆，沽美酒，酒美欲沽何處有。',56,'全唐诗/poet.song.179000.json','["提葫蘆，沽美酒，酒美欲沽何處有。", "官醪道遠不可得，村釀濃酸難入口。", "况當春暮暄暖初，沉浸醲郁醺體膚，客中醉倒無人扶。"]'),
('47e0d00e-4ed5-4185-b7ed-83058cc285c8','七禽詠 早耕早布','劉學箕','宋','宋诗','song-poetry','','[]','早耕早布，節物如流春色暮。',77,'全唐诗/poet.song.179000.json','["早耕早布，節物如流春色暮。", "金房土瘠無稻田，布耕播種種何處。", "一春焦涸旱無雨，麥穗藏頭猶未吐。", "麥穗不吐人不憂，粟田再種秋可收。", "只愁夏料欠輸納，悍吏坐門官不休。"]'),
('5017452d-30e2-4c55-8447-660ae5ea3009','鄖鄉舟中睡覺書懷','劉學箕','宋','宋诗','song-poetry','','[]','晴空揚沙春茫茫，柳絮匝岸東風狂。',178,'全唐诗/poet.song.179000.json','["晴空揚沙春茫茫，柳絮匝岸東風狂。", "篷窗兩畔高插起，收拾萬象供吟章。", "眼中物物盡詩料，應接不暇勞迎將。", "睡魔欺人晴晝長，坦腹一枕追羲皇。", "醒來意興難說似，石鼎細味煎茶香。", "江花無情爲誰芳，江草綠嫩肥牛羊。", "瀰瀰渺渺水曲折，遠遠近近山低昂。", "各懷邂逅良未惡，隠几抱膝聊徜徉。", "故人念我天一方，我亦千里遥相望。", "相思用情何日了，带圍寬剩羞東陽。", "不如且理文字五千卷，搜吟拄腹撐枯腸。"]'),
('96282a42-385c-4db5-99ee-5c3d0d4bfccc','甲口翫月','劉學箕','宋','宋诗','song-poetry','','[]','山頭團團上明月，偏與行人照離別。',64,'全唐诗/poet.song.179000.json','["山頭團團上明月，偏與行人照離別。", "月華只是尋常明，照人離愁愁思盈。", "千古萬古是箇月，如何有愁有歡悅。", "君將此理細推尋，悲歡原自由人心。"]'),
('254655ee-cd62-4296-b73a-ae283b2af133','蜀口枕上','劉學箕','宋','宋诗','song-poetry','','[]','清嘯孤猿半夜啼，子規山狖共酸悲。',32,'全唐诗/poet.song.179000.json','["清嘯孤猿半夜啼，子規山狖共酸悲。", "水風露月烟江冷，正是離人睡覺時。"]'),
('6b9928fc-16b6-4896-a01c-c10941ea32fb','浄口二絕句  其一','劉學箕','宋','宋诗','song-poetry','','[]','一江春水綠油油，遶盡春山去不休。',32,'全唐诗/poet.song.179000.json','["一江春水綠油油，遶盡春山去不休。", "愧我虛舟無定著，追隨曲折與同流。"]'),
('fe84db24-36e9-466e-8120-d76109e1e7ee','浄口二絕句  其二','劉學箕','宋','宋诗','song-poetry','','[]','修修野竹碧琅玕，亂石懸崕劍戟攢。',32,'全唐诗/poet.song.179000.json','["修修野竹碧琅玕，亂石懸崕劍戟攢。", "貪看野禽穿綠樹，不知船已過前灘。"]'),
('f2b283ac-bc72-4cc8-b328-ceda7c5c4ad2','釣磯候舟','劉學箕','宋','宋诗','song-poetry','','[]','可以賦新詩，江清釣石磯。',48,'全唐诗/poet.song.179000.json','["可以賦新詩，江清釣石磯。", "船移山勢動，灘急岸形飛。", "雲日林紅薄，晴烟野翠微。", "長歌漁父句，世事付蓑衣。"]'),
('9aa394b6-5c35-4a1d-b911-3fffcd0f7413','溪亭醉卧用季僊韻','劉學箕','宋','宋诗','song-poetry','','[]','客眠幽夢永，花氣著衣深。',48,'全唐诗/poet.song.179000.json','["客眠幽夢永，花氣著衣深。", "枕借溪中石，雲開體上衾。", "醒來揩亂眼，風雨滌煩襟。", "得句無人解，惟予識子心。"]'),
('78ac4405-b51f-4215-b5f9-4b79fe7fff58','次溪園紀實韻','劉學箕','宋','宋诗','song-poetry','','[]','隨地安身樂有涯，萬鍾於我我何加。',64,'全唐诗/poet.song.179000.json','["隨地安身樂有涯，萬鍾於我我何加。", "左蠻右觸真成幻，浮利虛名總是花。", "草茁玉英新藥籠，火添金鼎舊丹芽。", "異時相見無驚訝，漆點雙瞳臉瑩霞。"]'),
('680c0371-4ebd-4ec4-9f5e-1b82bde32860','新霽和人韻','劉學箕','宋','宋诗','song-poetry','','[]','晚天未霽烟張霧，浮埃蔽空雲擘絮。',64,'全唐诗/poet.song.179000.json','["晚天未霽烟張霧，浮埃蔽空雲擘絮。", "西山遠掛月一眉，澹澹寒輝生綺戶。", "須臾仰視天中央，清飈震拂銀河光。", "人影在地林影散，月出皎兮星斗燦。"]'),
('c8bf8607-899c-42d7-a2c6-42dca7874c20','次叔通推官見寄二首  其一','劉學箕','宋','宋诗','song-poetry','','[]','海錯園蔬富矣哉，杜醪龍壻一時來。',32,'全唐诗/poet.song.179000.json','["海錯園蔬富矣哉，杜醪龍壻一時來。", "放杯停筯情何似，經造無何半日回。"]'),
('1af4bc57-1c7c-49b6-abc0-7984da6dec70','次叔通推官見寄二首  其二','劉學箕','宋','宋诗','song-poetry','','[]','君比昌黎頗似之，號啼不問但吟詩。',32,'全唐诗/poet.song.179000.json','["君比昌黎頗似之，號啼不問但吟詩。", "貯儲甚愧鄰僧誼，不與盧仝更與誰。"]'),
('e0f1c883-dc23-47b6-b019-fe8017fef8e9','久雨秋懷二首  其一','劉學箕','宋','宋诗','song-poetry','','[]','孤雲野鶴情自在，碧水丹山人易安。',64,'全唐诗/poet.song.179000.json','["孤雲野鶴情自在，碧水丹山人易安。", "哀鴻獨叫暮天闊，宿鷺雙飛秋雨寒。", "蔗林遮眼青到市，桕葉漫山紅隔水。", "不將濁酒急驅除，滿意風光誰料理。"]'),
('f25c247c-64f4-41b1-9a97-ef2abd8abb4a','久雨秋懷二首  其二','劉學箕','宋','宋诗','song-poetry','','[]','漢陰抱甕自其志，彭澤折腰非本心。',64,'全唐诗/poet.song.179000.json','["漢陰抱甕自其志，彭澤折腰非本心。", "碧梧委路霜信早，黄菊護籬秋氣深。", "稻場可羨西疇老，紅釀黄雞醉翁媼。", "自笑吾儂計太迂，愁滿吟懷詩未了。"]'),
('49824e1c-ead5-4b4a-bfe6-b9da16cc5b6a','再次叔通來字詩字韻二首  其一','劉學箕','宋','宋诗','song-poetry','','[]','秋雲冥冥未開霽，搔首懷人人未來。',32,'全唐诗/poet.song.179000.json','["秋雲冥冥未開霽，搔首懷人人未來。", "特地送將雙鯉去，果然換得兩詩回。"]'),
('a1d05b36-7bea-4c15-bd23-a2721463cae0','再次叔通來字詩字韻二首  其二','劉學箕','宋','宋诗','song-poetry','','[]','誰念溪翁我念之，折腰爲米見諸詩。',32,'全唐诗/poet.song.179000.json','["誰念溪翁我念之，折腰爲米見諸詩。", "春秧夏穟苦縈抱，不似東坡更似誰。"]'),
('79f88d0f-8d45-4acd-8a0f-9bccfcb08217','次叔通見寄四首韻  其一','劉學箕','宋','宋诗','song-poetry','','[]','萬箱未獲交徧謫，積雨不翅三日霖。',64,'全唐诗/poet.song.179000.json','["萬箱未獲交徧謫，積雨不翅三日霖。", "如將翳處日忽露，似欲霽間雲復深。", "况當邊報置郵速，詎識老儒憂世心。", "讀君詩罷三太息，嘿不晤語行磵陰。"]'),
('876e4d49-b84a-44a5-bf4f-80da30507f62','次叔通見寄四首韻  其二','劉學箕','宋','宋诗','song-poetry','','[]','掀髯停盃一問之，細讀白柄長鑱詩。',64,'全唐诗/poet.song.179000.json','["掀髯停盃一問之，細讀白柄長鑱詩。", "我生託子以爲命，世路艱危徒爾爲。", "北闕不才書莫上，西山有味去何辭。", "流風餘韻只在眼，須信古今同一時。"]'),
('e6d3a877-4a4f-4010-bd6b-674b2204c8ad','次叔通見寄四首韻  其三','劉學箕','宋','宋诗','song-poetry','','[]','江山到眼一披豁，世念攪思三宜休。',64,'全唐诗/poet.song.179000.json','["江山到眼一披豁，世念攪思三宜休。", "文章苦心費雕琢，歲月老我徒謬悠。", "欲譚圓覺識佛祖，更希超舉期浮丘。", "宗盟暮年味嚼蠟，灰木萬念空煩憂。"]'),
('684614f4-d70b-4079-bf28-f5e4d1e8457d','次叔通見寄四首韻  其四','劉學箕','宋','宋诗','song-poetry','','[]','周遭山五峰，環抱潭一曲。',60,'全唐诗/poet.song.179000.json','["周遭山五峰，環抱潭一曲。", "溪頭植楊柳，山下栽松菊。", "盈阡䆉䅉香，遶舍梨柿熟。", "歸來書在牀，出去雲滿屋。", "蕭散樂予心，可謂享清福。"]'),
('feb9cbb3-11c8-4d2f-a652-1cb36d7163de','東屯莊監秤六言三首  其一','劉學箕','宋','宋诗','song-poetry','','[]','讀書不執箋注，治生奚用豐財。',42,'全唐诗/poet.song.179000.json','["讀書不執箋注，治生奚用豐財。", "詩吟一首兩首，酒飲三盃五盃。", "石田茅屋無恙，不與亂生蒼苔。"]'),
('7f46ef2e-2b96-49f6-83f2-cf3b2133e70e','東屯莊監秤六言三首  其二','劉學箕','宋','宋诗','song-poetry','','[]','天末鴻飛無際，沙頭鷺立倍鮮。',42,'全唐诗/poet.song.179000.json','["天末鴻飛無際，沙頭鷺立倍鮮。", "霞明東崦箇裏，烟抹西山那邊。", "上馬吟詩未竟，舉頭望月俄圓。"]'),
('eb124083-fae4-46b6-92ae-bc470fee7a57','東屯莊監秤六言三首  其三','劉學箕','宋','宋诗','song-poetry','','[]','割盡黄雲萬頃，舂成玉粒千倉。',42,'全唐诗/poet.song.179000.json','["割盡黄雲萬頃，舂成玉粒千倉。", "出甑香粳滿舍，壓糟新酒盈堈。", "田家慚愧時熟，官賦催徵可償。"]'),
('2ec6b046-1ad9-47fa-b40d-dfa8cce50029','邀趙行之陳敬叟未至四韻速之','劉學箕','宋','宋诗','song-poetry','','[]','一別親朋歲月催，衿連袂屬肯俱來。',64,'全唐诗/poet.song.179000.json','["一別親朋歲月催，衿連袂屬肯俱來。", "交情聊敘慇懃意，野䔩隨宜三兩杯。", "新月窺簷頻起顧，清風動竹幾驚猜。", "碧雲日暮山環合，竚立柴扉首屢回。"]'),
('ce50e301-16d5-40dc-a90f-aa4c97487e6f','陳洮湖取古今梅詩自鮑明遠降至今日名勝集中所賦悉和之凡千首計三十六卷十日然後讀畢用其敘中四韻和題其後','劉學箕','宋','宋诗','song-poetry','','[]','照眼梅花雪作堆，陰厓寒谷带春回。',64,'全唐诗/poet.song.179000.json','["照眼梅花雪作堆，陰厓寒谷带春回。", "千篇墮我吟邊去，萬里懷人書未來。", "遶樹政須搜苦語，攀條那忍負芳杯。", "長鑱幾度鋤明月，盡是劉郎手自栽。"]'),
('78e20c4f-e1d2-41a8-baf7-225fd2cf0694','和林處士梅詩八首  其一','劉學箕','宋','宋诗','song-poetry','','["\u897f\u6e56"]','年年江上見梅時，憶著西湖處士詩。',64,'全唐诗/poet.song.179000.json','["年年江上見梅時，憶著西湖處士詩。", "香暗影疎清到骨，水邊籬下雪融枝。", "可知寒谷先回律，會是東皇肯與私。", "竹逕松扉留作伴，莫教風伯肆狂吹。"]'),
('0664dade-106e-4f97-bd9b-1283f8eefedb','和林處士梅詩八首  其二','劉學箕','宋','宋诗','song-poetry','','[]','芳菲猶未露春妍，已是梅開溪上園。',64,'全唐诗/poet.song.179000.json','["芳菲猶未露春妍，已是梅開溪上園。", "香靜細參花外意，眼明應笑霧中昏。", "自憐拙思污吟筆，誰賦新詩入夢魂。", "風味滿前難料理，急招佳客對開尊。"]'),
('26c30399-4422-4a1b-980f-f694c61708f4','和林處士梅詩八首  其三','劉學箕','宋','宋诗','song-poetry','','[]','梅花濕露未全乾，青女橫陳故作難。',64,'全唐诗/poet.song.179000.json','["梅花濕露未全乾，青女橫陳故作難。", "卯醉醉如申醉醉，晚寒寒似曉寒寒。", "園林雪後清孤甚，京洛塵中子細看。", "自是丰神無與比，肯同桃李戀雕鞍。"]'),
('df03bd7f-d098-4e30-b60e-68b3836b53d1','和林處士梅詩八首  其四','劉學箕','宋','宋诗','song-poetry','','[]','寂寞吟懷誰與開，前村除是竹邊梅。',64,'全唐诗/poet.song.179000.json','["寂寞吟懷誰與開，前村除是竹邊梅。", "清尊撩觸香三嗅，短日吟搜腸九回。", "石路與風隨袖入，茆簷和月上窗來。", "幾番客散庭空處，獨倚寒梢更一杯。"]'),
('773d8e1b-a6ac-47f4-9ac6-3d57ee971d03','和林處士梅詩八首  其五','劉學箕','宋','宋诗','song-poetry','','[]','犯寒不怕雪蒙頭，蹋石穿林不暫休。',64,'全唐诗/poet.song.179000.json','["犯寒不怕雪蒙頭，蹋石穿林不暫休。", "千首詩成千首意，十分春瘦十分愁。", "飛添宮額粧同艷，斜插鬢雲香共留。", "勉續清吟知筆弱，苦無風度恐花羞。"]'),
('0b4cc86c-f7f7-496a-a678-b4f7378f689c','和林處士梅詩八首  其六','劉學箕','宋','宋诗','song-poetry','','[]','雪皎花明夜不迷，借光何假更然臍。',64,'全唐诗/poet.song.179000.json','["雪皎花明夜不迷，借光何假更然臍。", "詠吟自我形長短，斟唱從渠付淺低。", "誰識摽梅詩什賦，絕勝紅葉御溝題。", "明朝杖履山行去，約束牛羊勿踐蹊。"]'),
('af558991-ba58-4a55-8978-944326f8c0ac','和林處士梅詩八首  其七','劉學箕','宋','宋诗','song-poetry','','[]','一樹纔開玉未殘，忍些風雪耐些寒。',64,'全唐诗/poet.song.179000.json','["一樹纔開玉未殘，忍些風雪耐些寒。", "不須俗子聯翩去，政要幽人自在看。", "白玉堂中春信早，黄金琖裏酒痕乾。", "後凋孰與堅盟約，松竹青青共歲闌。"]'),
('cfa5ddef-f7aa-41f8-9865-f60b37a6b4ba','和林處士梅詩八首  其八','劉學箕','宋','宋诗','song-poetry','','[]','尋春山徑坐班荆，食罍芳尊後乘并。',64,'全唐诗/poet.song.179000.json','["尋春山徑坐班荆，食罍芳尊後乘并。", "觴詠隨宜無限趣，塵囂不到有餘清。", "風流天賦幽閒態，寂寞霜明冷澹情。", "若把春葩歸品藻，此花端的冠羣英。"]'),
('5fbf0749-909a-4f90-82c0-e0e37c0fe081','與政仲山行見梅偶成併和其詩二首  其一','劉學箕','宋','宋诗','song-poetry','','[]','巉巗石壁掛崕嵬，烟檻風篁十數栽。',64,'全唐诗/poet.song.179000.json','["巉巗石壁掛崕嵬，烟檻風篁十數栽。", "約客偶成花外逕，舉頭俄見竹邊梅。", "背陰寒谷無人問，著句陽春有意裁。", "慚愧心腸非鐵石，携壺遶樹日千回。"]'),
('854991ad-9d4d-461a-aedb-f781b1c9be18','與政仲山行見梅偶成併和其詩二首  其二','劉學箕','宋','宋诗','song-poetry','','[]','梅花端的記年芳，每到開時趁一陽。',64,'全唐诗/poet.song.179000.json','["梅花端的記年芳，每到開時趁一陽。", "綠水湖邊和靖句，含章簷下壽陽妝。", "昏昏澹月疎疎影，緩緩清風細細香。", "不比芳春萬紅紫，蕩人狂思費思量。"]'),
('c025bb1f-d80e-4cc8-8d48-dc497d614e4f','水僊花分韻得鴻字','劉學箕','宋','宋诗','song-poetry','','[]','借水開花體態豐，護畦寒日玉瓏璁。',64,'全唐诗/poet.song.179000.json','["借水開花體態豐，護畦寒日玉瓏璁。", "素槃黄琖清尊並，綠箸青簪白髮同。", "楚楚凌波明振鷺，翩翩遵渚潔飛鴻。", "斷腸莫賦招魂句，我政憐渠趣未窮。"]'),
('de09eb5f-f5b5-4f07-bddc-96f726ba312e','感事懷人送春病酒曉起五首  其一','劉學箕','宋','宋诗','song-poetry','','[]','把酒傷春暮，何人慰寂寥。',48,'全唐诗/poet.song.179000.json','["把酒傷春暮，何人慰寂寥。", "才高融未薦，魂斷玉空招。", "賦就青陽曲，吟成白紵謠。", "拊欄三太息，幽憤幾磨消。"]'),
('b07b352a-91b3-40f6-ab44-8c71593f7771','感事懷人送春病酒曉起五首  其二','劉學箕','宋','宋诗','song-poetry','','[]','節物隨時換，朱明斗轉杓。',48,'全唐诗/poet.song.179000.json','["節物隨時換，朱明斗轉杓。", "波肥溪鱮壯，風暖谷鶑嬌。", "青草溪頭岸，紅欄水際橋。", "懷人無數舍，我欲致書招。"]'),
('623de728-5c99-4109-a0b6-f79f8c3b2449','感事懷人送春病酒曉起五首  其三','劉學箕','宋','宋诗','song-poetry','','[]','煮醖青梅且共嘗，遊蜂飛蝶爲誰忙。',64,'全唐诗/poet.song.179000.json','["煮醖青梅且共嘗，遊蜂飛蝶爲誰忙。", "鞦韆綵索迷青草，車馬紅橋鎖綠楊。", "春事戰回蒲劍老，詩腸結盡柳絲長。", "韶光賦別休匆遽，凝佇東風更一觴。"]'),
('e9598385-359b-4a34-8f7d-16b73ecfe47d','感事懷人送春病酒曉起五首  其四','劉學箕','宋','宋诗','song-poetry','','[]','積雨平田水接天，乍晴雲日煥山川。',64,'全唐诗/poet.song.179000.json','["積雨平田水接天，乍晴雲日煥山川。", "浄無餘馥延春艷，縟有繁陰長夏妍。", "泛泛荷衣青倚蓋，輕輕柳絮白飛綿。", "一聲布穀催清曉，節物驚心撓醉眠。"]'),
('a52bb2cd-3b4f-4ae8-8b00-16e8d9c5aab6','感事懷人送春病酒曉起五首  其五','劉學箕','宋','宋诗','song-poetry','','[]','雙眉不皺樂平生，一斗時能對客傾。',64,'全唐诗/poet.song.179000.json','["雙眉不皺樂平生，一斗時能對客傾。", "曉枕恰醒紅日上，篆爐未歇紫烟明。", "畫橋貼水輕飛燕，綠牖依山靜囀鶑。", "隨雨隨晴看天氣，緩扶筇杖遶園行。"]'),
('a6a05c95-dd73-491e-aaad-0f4a72419da2','賓從集藕花堂分韻得園字二十韻','劉學箕','宋','宋诗','song-poetry','','[]','流金爍石火燎燔，何地泄此畏暑袢。',320,'全唐诗/poet.song.179000.json','["流金爍石火燎燔，何地泄此畏暑袢。", "草堂幸有茆三間，冷浸十畝泉有源。", "泉音琮琤下空山，金石戛擊聲潺湲。", "太華峰頭十丈蓮，吾儂玉井親移根。", "開華結實今幾年，紅幛綠蓋風翻翻。", "捲舒萬柄摇蒼烟，香苞芳萼錦綺緐。", "雲將急雨珠濺圓，日焙晴酣香勝蓀。", "龜魚竊廕鷗鷺眠，勾致屬玉棲雙鴛。", "房青子碧甘剝鮮，藕白條翠冰堆盆。", "嚼之清泠醒醉魂，猶可招邀慰文園。", "君胡不聞李謫仙，聲名飄然譽開元。", "忽傳詔草白蓮序，一掃意到無餘言。", "又知蘇州韋不凡，風清月曉之江樊。", "形容委曲識花趣，妙語歷歷成訂論。", "我今對花難著句，挹取香氣臨窗軒。", "俱來亦有二三子，將壇共築旗同攑。", "搜吟速下一轉語，縮手無畏前輩尊。", "但今取之二老間，勿效碔砆亂璵璠。", "少需紅日西沉山，從容特爲開芳尊。", "晚色婉靜更麗娟，詠到東方生曉暾。"]'),
('754702cc-a565-4110-8c62-01b6e323ca6f','外舅安撫遊東湖一聯云潤衣紅濕池荷雨拂面清泠檻竹風即席令足成之','劉學箕','宋','宋诗','song-poetry','','[]','庚伏人間暑氣隆，納凉留客詠詩翁。',64,'全唐诗/poet.song.179000.json','["庚伏人間暑氣隆，納凉留客詠詩翁。", "潤衣紅濕池荷雨，拂面清泠檻竹風。", "沙觜舊痕平不露，野灣新漲曲相通。", "畫橈澹月人歸處，萬蓋翻翻湧翠筩。"]'),
('0abfd6df-92a4-45d7-b120-91209b0d1a43','楊戶曹用外舅二詩韻見寄和以酬之  其一','劉學箕','宋','宋诗','song-poetry','','[]','得不知所止，泛然乘風船。',48,'全唐诗/poet.song.179000.json','["得不知所止，泛然乘風船。", "正大辱啟蒙，似欲駕我僊。", "大哉周孔心，異彼祇漆園。", "講月琢以磨，豈在耘人田。"]'),
('1538aed2-152b-4c70-af07-cd008d9045e8','楊戶曹用外舅二詩韻見寄和以酬之  其二','劉學箕','宋','宋诗','song-poetry','','[]','切問而近思，進進在不已。',48,'全唐诗/poet.song.179000.json','["切問而近思，進進在不已。", "流光駒過隙，遷變一彈指。", "道大無津涯，詎作井蛙喜。", "公私義利分，亦各從其類。"]'),
('77fb3e01-c4a3-425c-a52e-864a19b16aa4','請遊山之日於黎廣文二首寺有萬竹  其一','劉學箕','宋','宋诗','song-poetry','','[]','此君原不俗，幽趣逼蒼官。',48,'全唐诗/poet.song.179000.json','["此君原不俗，幽趣逼蒼官。", "濁世三庚熱，空山六月寒。", "何憂懷抱隘，便㨫水雲寬。", "敬請遊盤日，追隨杖屨看。"]'),
('5de4eb2e-7d01-4ad7-af87-4335287a0131','請遊山之日於黎廣文二首寺有萬竹  其二','劉學箕','宋','宋诗','song-poetry','','[]','聞說江隈裏，雲藏古寺深。',48,'全唐诗/poet.song.179000.json','["聞說江隈裏，雲藏古寺深。", "不妨相喚集，作意共登臨。", "苦茗供朝盌，伊蒲饌晚鬵。", "天風吹皓月，歸路細披襟。"]'),
('9530c54c-bd76-4af6-be7a-f53ff05a49e0','上王通守傳易數','劉學箕','宋','宋诗','song-poetry','','[]','大哉皇羲古神聖，八卦始畫天地闢。',240,'全唐诗/poet.song.179000.json','["大哉皇羲古神聖，八卦始畫天地闢。", "乾效於天坤法地，六子運用眇難測。", "天理人文一宣朗，萬化昭然從此出。", "發明洊更三聖手，動靜機緘皎如日。", "自從戰國周綱頹，是道亦幾乎暫息。", "漢儒衆說徒專門，後世可聞無幾及。", "傳流吾宋盛文物，學老儒宗相繼述。", "濂溪伊洛紹韋編，數至邵公精算策。", "祗今南渡九十年，統會宗元孰探賾。", "恭惟先生藴其祕，口不宣言藏以臆。", "愚雖不敏敢敬請，願執門牆灑掃役。", "先生學識際天人，先生手提六經筆。", "俯察仰觀關鍵透，虛激寸心參太極。", "不鄙愚昧謂之進，啟迪狂迷窺奧閾。", "他年衣鉢得親傳，誓言力造神明德。"]'),
('3e0e1b24-d171-4fdc-99ad-3917d0303fac','宴吳侯致語口號','劉學箕','宋','宋诗','song-poetry','','[]','一昨初登大將壇，弓刀旗幟簇雕鞍。',64,'全唐诗/poet.song.179000.json','["一昨初登大將壇，弓刀旗幟簇雕鞍。", "連營壯士心先服，並塞胡人膽已寒。", "天上麒麟祥可卜，人間日月老應難。", "明年樞府爲公壽，慷慨還知酒量寬。"]'),
('c452e496-d741-4d50-b488-e08c5a7ef766','寄靜菴','劉學箕','宋','宋诗','song-poetry','','[]','天寒日短道路長，白雲飛去知吾鄉。',144,'全唐诗/poet.song.179000.json','["天寒日短道路長，白雲飛去知吾鄉。", "大江之東渭之北，念吾故人何可忘。", "別來楊柳春依依，只今開到梅花香。", "扁舟漫浪歸未得，京塵海裏安行藏。", "身名未立仰天笑，牀頭夜夜鳴干將。", "羨師物外無寵辱，庭前柏樹常蒼蒼。", "吁嗟急羽飛不到，二千里外空相望。", "五雲前墜滿室光，報師之意無以將。", "篇詩滾墨纔淋浪，一聲雁過天南翔。"]'),
('0b956b35-013c-45ac-a569-d58e81fd7b27','和韵','劉學箕','宋','宋诗','song-poetry','','[]','窗燭銷殘轉寂寥，柴門無復野僧敲。',64,'全唐诗/poet.song.179000.json','["窗燭銷殘轉寂寥，柴門無復野僧敲。", "偶來枕上吟詩就，記向心頭欠筆抄。", "鳴竹數聲疑雪片，尋梅清夢到山坳。", "世情雲雨多翻覆，誰是江湖耐久交。"]'),
('2068f0c3-da57-4daa-9ab6-c4605bb781ca','蕭長公來訪示以諸公詩卷謂與予遊從之久不能一辭爲贈頗相噍責予賦之不可辭之亦不可皆有說焉名章俊語前後相望無數次乎其間是覩西子之容面自增醜耳所不容却者予年十五時海山官丁受琴于長夫今予年四十與長夫有二十五年之舊辭之弗作其可乎因書數言','劉學箕','宋','宋诗','song-poetry','','[]','生平不願爲傭書，亦不願作章句儒。',192,'全唐诗/poet.song.179000.json','["生平不願爲傭書，亦不願作章句儒。", "酒酣詩成吐素霓，意氣凜凜吞千夫。", "前年排雲叫閶闔，出門一夜車四角。", "去年海嶠席未溫，一舸乘潮又催□。", "大江之西日本東，廬陵文物常稱雄。", "決科歲占十八九，君當努力提詞鋒。", "才高不用長歎息，四海彌天豈無識。", "壯年懷居亦何有，著眼带礪開胸臆。", "巖巖柏府凌高寒，豪士傾蓋宜交歡。", "我知屠龍不屠豬，食馬政欲食馬肝。", "吳姬壓酒飄香絮，謫仙神遊歌白紵。", "敬亭惟有孤雲閒，欲雨人間亦飛去。"]'),
('eab3d802-c5f6-41a6-8bbe-25e97a275c5a','有所思','劉學箕','宋','宋诗','song-poetry','','[]','憶昔美人初別時，長亭兩岸柳依依。',152,'全唐诗/poet.song.179000.json','["憶昔美人初別時，長亭兩岸柳依依。", "今日美人天之涯，美人美人胡不歸。", "憶昔君別妾，分破青鸞鏡。", "破鏡如破心，與妾表相憶，相憶圖久深。", "憶昔妾別君，剪斷金鳳釵。", "斷釵如斷腸，贈君表相思，相思圖久長。", "一日一日復一日，青鏡鸞孤釵鳳隻。", "未必君相思，能如妾相憶。", "寒衣剪就欲寄君，長安門外無行人。", "雁聲半夜西風惡，窗前一片梧桐落。"]'),
('bd620fec-e6c3-49bb-967e-ca68432980bc','觀猿','劉學箕','宋','宋诗','song-poetry','','[]','掛石攀雲日半斜，亂山深處飽煙霞。',32,'全唐诗/poet.song.179000.json','["掛石攀雲日半斜，亂山深處飽煙霞。", "香林月滿僧歸去，啼落春風幾樹花。"]'),
('153de504-00d1-49de-b3ed-c39bcbb2c48d','失鶴','劉學箕','宋','宋诗','song-poetry','','[]','頂上新成九轉丹，□花日日到春壇。',32,'全唐诗/poet.song.179000.json','["頂上新成九轉丹，□花日日到春壇。", "夜深飛上雲霄去，華表月明風露寒。"]'),
('76401715-06f6-4416-a747-e40da1bd76b4','宿大慈山悟真觀','劉學箕','宋','宋诗','song-poetry','','[]','終南道士學彈琴，門外松蘿鎖翠陰。',64,'全唐诗/poet.song.179000.json','["終南道士學彈琴，門外松蘿鎖翠陰。", "涉海八龍朝出洞，隔山羣鹿夜歸林。", "琪花過雨溪風澹，玉樹籠煙璧月沈。", "三十六壇鐘鼓寂，雲璈聲接步虛音。"]'),
('b8edd7be-78b8-4262-a2cd-1484fc5dc400','賦林景參梅嶼','劉學箕','宋','宋诗','song-poetry','','[]','結廬分得雁山雲，嶼上梅花是四鄰。',64,'全唐诗/poet.song.179000.json','["結廬分得雁山雲，嶼上梅花是四鄰。", "水月一天薌世界，冰霜千古玉精神。", "短檠夜雨西窗夢，長鋏秋風北塞塵。", "我亦煙波綸釣侶，與君同作歲寒人。"]'),
('f8e10a79-74eb-4b67-9d7a-189a01199fea','懷潘鄮屋','劉學箕','宋','宋诗','song-poetry','','[]','洛陽纔解珮，過眼忽秋分。',48,'全唐诗/poet.song.179000.json','["洛陽纔解珮，過眼忽秋分。", "四海一明月，千山共白雲。", "雁煙迷曉樹，蟲露濕香芹。", "滿紙相思字，臨風欲寄君。"]'),
('f630757e-ff5e-4833-a298-8725e6bf059c','吳江道上','劉學箕','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','夜半扁舟出洞庭，客帆初掛早潮平。',64,'全唐诗/poet.song.179000.json','["夜半扁舟出洞庭，客帆初掛早潮平。", "社風纔起海鷹至，嵐露未收江鵠鳴。", "吳岫亂雲擎古塔，楚皋寒葉擁荒城。", "垂虹橋外天連水，無限別離生杜蘅。"]'),
('5a567d6a-12eb-45b0-acc9-c372853aa7cb','登西樓懷湯損之','劉學箕','宋','宋诗','song-poetry','','[]','楊柳飄飃春思長，綠橋流水遶宮牆。',32,'全唐诗/poet.song.179000.json','["楊柳飄飃春思長，綠橋流水遶宮牆。", "碧雲望斷空回首，一半欄干無夕陽。"]'),
('871a58bf-8ceb-4fe5-b2d0-e17d3d4d4952','吳山雪霽','劉學箕','宋','宋诗','song-poetry','','[]','九天宮闕春風滿，陸地樓臺夜月寒。',32,'全唐诗/poet.song.179000.json','["九天宮闕春風滿，陸地樓臺夜月寒。", "鐵笛一聲吹雁落，片雲不到玉欄干。"]'),
('4f12a24b-7783-4d81-a533-c8351a509ada','雙路','劉學箕','宋','宋诗','song-poetry','','[]','王命馳驅不敢輕，文書要覈去來情。',64,'全唐诗/poet.song.179000.json','["王命馳驅不敢輕，文書要覈去來情。", "青山步步生幽意，碧澗悠悠趁遠程。", "春淺禽聲猶自小，泥酥馬蹟正宜晴。", "地名見說名雙路，便舍崎嶇就坦平。"]'),
('bf7a6a2a-4fa4-41cd-a69a-cbd4d5de8539','寶際窗前睡香','劉學箕','宋','宋诗','song-poetry','','[]','瑞錦窠應對錦郎，誰將靈種到幽坊。',32,'全唐诗/poet.song.179000.json','["瑞錦窠應對錦郎，誰將靈種到幽坊。", "山深月冷梅花老，壓盡羣英是此香。"]'),
('34665039-354a-475c-a8d5-5937d107b4dd','石橋樓待  其一','劉學箕','宋','宋诗','song-poetry','','[]','當年立雪直齊腰，宗旨流傳到石橋。',32,'全唐诗/poet.song.179000.json','["當年立雪直齊腰，宗旨流傳到石橋。", "風急窗寒燈影遠，疎梅無語夜香銷。"]'),
('c85b94c5-b0af-473d-b9c5-4a5ae1b642da','石橋樓待  其二','劉學箕','宋','宋诗','song-poetry','','[]','手筆華嚴梵笈新，更開寶地接迷津。',32,'全唐诗/poet.song.179000.json','["手筆華嚴梵笈新，更開寶地接迷津。", "一聲金磬人初靜，月照空山草自春。"]'),
('b704b907-9951-4427-996f-fcccc613e89b','聞寺中曉鼓','劉學箕','宋','宋诗','song-poetry','','[]','靈鼉一鼓振潮音，征夢迢遥枕畔聞。',32,'全唐诗/poet.song.179000.json','["靈鼉一鼓振潮音，征夢迢遥枕畔聞。", "語斷頻伽天正曉，松風吹散滿山雲。"]'),
('cba0a6f5-9eba-4e8d-9d77-07f2009dec9b','跨水道間','劉學箕','宋','宋诗','song-poetry','','[]','店舍總迢遥，山深轉寂寥。',48,'全唐诗/poet.song.179000.json','["店舍總迢遥，山深轉寂寥。", "看鷗臨遠水，下馬過危橋。", "晴雪林間少，春風野外饒。", "此行爲王事，旅食任蕭條。"]'),
('9a63e6c5-c518-4302-96de-57bc54fb17ad','峮山鋪','劉學箕','宋','宋诗','song-poetry','','[]','未說路行難，山深分外寒。',48,'全唐诗/poet.song.179000.json','["未說路行難，山深分外寒。", "晚村林隠寺，春澗石鳴灘。", "薄宦曾無補，勞生敢自安。", "羽書雖較少，備禦莫教寬。"]'),
('5022b39b-a476-4b7c-8dd6-37e61535bc90','杏塘','劉學箕','宋','宋诗','song-poetry','','[]','境接江東界，郵程是杏塘。',48,'全唐诗/poet.song.179000.json','["境接江東界，郵程是杏塘。", "雨喧茅屋小，泥滑草橋長。", "曠野人稀少，平田水渺茫。", "半生遊歷地，未若此荒涼。"]'),
('e2374fb8-2aac-4c62-99bf-a45a035f4224','四安焚惠藏殿','劉學箕','宋','宋诗','song-poetry','','[]','劫火不能焚，空中轉法輪。',48,'全唐诗/poet.song.179000.json','["劫火不能焚，空中轉法輪。", "風霜鴟殿古，金碧貝函塵。", "物本由成數，人言不壞身。", "却憐無問者，遺蹟竟成陳。"]'),
('723b8b91-23eb-491f-b58f-944d2e2c88a9','上司諫曹先生','劉學箕','宋','宋诗','song-poetry','','[]','聲名滿世重如山，果見延登左掖班。',64,'全唐诗/poet.song.179000.json','["聲名滿世重如山，果見延登左掖班。", "天子虛心求國是，先生著手濟時艱。", "要看出處諸公上，只在精神一轉間。", "前此極言雖引去，安危理亂正相關。"]'),
('f282b78a-4e44-4744-909c-9441cdc440d0','池萍  其一','劉學箕','宋','宋诗','song-poetry','','[]','一番雨過一番多，間挾晴風漲綠波。',32,'全唐诗/poet.song.179000.json','["一番雨過一番多，間挾晴風漲綠波。", "柳絮吹殘遊蹟在，謝池點點是陽和。"]'),
('69d91e80-7802-451c-b298-011d48404413','池萍  其二','劉學箕','宋','宋诗','song-poetry','','[]','竹籬茅舍去相安，誰與移根入畫欄。',32,'全唐诗/poet.song.179000.json','["竹籬茅舍去相安，誰與移根入畫欄。", "儘道重簾妨暖日，疎枝却得護春寒。"]'),
('176b2ffc-920f-49ab-b561-f49ad55935c8','池萍  其三','劉學箕','宋','宋诗','song-poetry','','[]','風標漫與萬花殊，可有塵埃染得渠。',32,'全唐诗/poet.song.179000.json','["風標漫與萬花殊，可有塵埃染得渠。", "把住瓊枝相晤語，只疑身在玉堂居。"]'),
('576e3044-416b-4595-8193-8c319a08cf81','和陸明叟','劉學箕','宋','宋诗','song-poetry','','[]','了無閒事上眉纖，一炷清香靜晝簾。',64,'全唐诗/poet.song.179000.json','["了無閒事上眉纖，一炷清香靜晝簾。", "造化自從回暖律，芬華頓覺轉窮簷。", "輕風度柳春情薄，細雨催花土脈黏。", "所愧微官相束縛，何因共訪酒家帘。"]'),
('b0cf33d8-4377-4447-89a7-eff07610b8e3','夜窗聽雨','劉學箕','宋','宋诗','song-poetry','','[]','一炷夜香清，挑燈聽雨聲。',48,'全唐诗/poet.song.179000.json','["一炷夜香清，挑燈聽雨聲。", "雖然添客夢，却可助詩情。", "澤沁蘭心重，泥酥笋角萌。", "山行頻有約，日日候晴明。"]'),
('04fec595-78a1-4e4d-9cba-7d7d8a2b8862','破榴','劉學箕','宋','宋诗','song-poetry','','[]','蜂殻盈盈萬顆珠，潤於瑪瑙浸冰壺。',32,'全唐诗/poet.song.179000.json','["蜂殻盈盈萬顆珠，潤於瑪瑙浸冰壺。", "吟心先自清如水，嚼了寒霜骨更臞。"]'),
('8e32165e-94dd-4ec7-a519-f3b9522ac472','登應天塔','劉學箕','宋','宋诗','song-poetry','','[]','雲級湧青冥，金鰲載寶輪。',48,'全唐诗/poet.song.179000.json','["雲級湧青冥，金鰲載寶輪。", "地高心自逸，天近足無塵。", "圖畫千峰晚，樓臺萬井春。", "三生許元度，曾此證前身。"]'),
('06a52482-5cf3-46ba-9d77-0ea6f94bbd20','鰻井','劉學箕','宋','宋诗','song-poetry','','[]','人言此井有靈源，潮落潮生透海門。',32,'全唐诗/poet.song.179000.json','["人言此井有靈源，潮落潮生透海門。", "陵谷未須窮變易，朱牆裏是濮王園。"]'),
('8055d59c-3ad9-448a-8039-19f32fbe871a','大能仁寺','劉學箕','宋','宋诗','song-poetry','','[]','規模應甲剎，殿閣擁金仙。',48,'全唐诗/poet.song.179000.json','["規模應甲剎，殿閣擁金仙。", "歲歉炊煙絕，城低野色連。", "客僧皆散去，主者獨安眠。", "成毀難逃數，山門八百年。"]'),
('4fcd3818-d07c-4f7e-aed9-3ed4928d2c50','留滯','劉學箕','宋','宋诗','song-poetry','','[]','何期蹤跡又遲留，行止於人自不由。',64,'全唐诗/poet.song.179000.json','["何期蹤跡又遲留，行止於人自不由。", "夢境固知空似蟻，生涯却笑拙於鳩。", "碧涵一鏡晴天闊，翠擁千峰宿雨收。", "從此公餘須杖屨，未應草草度春休。"]'),
('900f11a5-5048-4659-9804-667eee7a99b0','曉寒','劉學箕','宋','宋诗','song-poetry','','[]','曲曲屏山憶夢中，峭寒成陣入簾櫳。',32,'全唐诗/poet.song.179000.json','["曲曲屏山憶夢中，峭寒成陣入簾櫳。", "宿香銷盡金猊冷，一樹梅花却曉春。"]'),
('216dc403-dc4b-4430-a83b-84f3d33389a2','晚思','劉學箕','宋','宋诗','song-poetry','','[]','客思悠悠幸自安，亦因吟事可相寬。',32,'全唐诗/poet.song.179000.json','["客思悠悠幸自安，亦因吟事可相寬。", "小窗過了廉纖雨，細與東風說晚寒。"]'),
('e6c040b4-2d3e-4af1-872b-69cddb9ae123','用明叟韵併寓山行未成之意','劉學箕','宋','宋诗','song-poetry','','[]','久客住蘭亭，心同晉水清。',48,'全唐诗/poet.song.179000.json','["久客住蘭亭，心同晉水清。", "忘機盟宿鷺，伐木聽雛鶑。", "物亦知人意，春寧有世情。", "幽尋空作計，一夜雨連明。"]'),
('3b3741ab-e599-404a-b0bf-66d5dc8f169d','苦雨','劉學箕','宋','宋诗','song-poetry','','[]','何期一雨成三日，約客同行竟未能。',64,'全唐诗/poet.song.179000.json','["何期一雨成三日，約客同行竟未能。", "春到分時陰不解，夜當深處氣猶凝。", "簷低捲箔看飄灑，礎潤添香散鬰蒸。", "想見故園梅落盡，和羹消息又堪憑。"]'),
('90fd1e7f-0dcf-4135-b4b4-7328546ba476','雨中用雪坡韵','劉學箕','宋','宋诗','song-poetry','','[]','無計酬春獨有詩，倚欄終日候晴暉。',32,'全唐诗/poet.song.179000.json','["無計酬春獨有詩，倚欄終日候晴暉。", "東風漸屬新桃李，簾幕深深燕子飛。"]'),
('e1e41171-6daa-41c1-ae2e-87e0ec1711ac','雪坡以雨阻山行有詩用以次韵','劉學箕','宋','宋诗','song-poetry','','["\u897f\u6e56"]','爲欲看山助眼明，頻占鵲喜報新晴。',64,'全唐诗/poet.song.179000.json','["爲欲看山助眼明，頻占鵲喜報新晴。", "春光已過三之一，塵世難逢四者并。", "詩酒深情殊未適，水蔬薄具亦頻更。", "終來不似西湖好，晴雨皆堪傍柳行。"]'),
('eeb1a9e3-a9d4-4372-a43f-e7dcc2fb8308','月丹和鶴莊韵','劉學箕','宋','宋诗','song-poetry','','[]','靈種飛來鶴頂紅，誰云九轉有仙功。',32,'全唐诗/poet.song.179000.json','["靈種飛來鶴頂紅，誰云九轉有仙功。", "廣庭曾侍東風宴，留得霞杯照晚叢。"]'),
('600ea4d2-db01-4511-a7be-9ee58aa6018e','禹廟','劉學箕','宋','宋诗','song-poetry','','[]','且要盡清歡，須知一出難。',48,'全唐诗/poet.song.179000.json','["且要盡清歡，須知一出難。", "人因晴後喜，春到水邊寬。", "柳長官橋媚，梅飄客袖寒。", "荒祠存禹蹟，得得又來看。"]'),
('9f869fe3-73a2-492a-a984-c847598d7f47','鏡湖一曲','劉學箕','宋','宋诗','song-poetry','','[]','天與平湖老賀郎，春波依舊染晴光。',32,'全唐诗/poet.song.179000.json','["天與平湖老賀郎，春波依舊染晴光。", "可憐千載風流意，付與租符曉夕忙。"]'),
('62697445-713c-467b-a563-06ca783d5bc6','用雪坡春色韵','劉學箕','宋','宋诗','song-poetry','','[]','纔出城門興便濃，晴光野色兩俱融。',64,'全唐诗/poet.song.179000.json','["纔出城門興便濃，晴光野色兩俱融。", "柳方染得三分綠，桃已熏成一半紅。", "山湧林巒荒寺隠，湖分港汊小舟通。", "相携各自論年事，幾度春風一鬢蓬。"]'),
('5e74be3d-c821-4526-9a83-d864cbd96dea','用梅溪鏡湖韵','劉學箕','宋','宋诗','song-poetry','','[]','畎畝鏡中分，滄波雜斷雲。',48,'全唐诗/poet.song.179000.json','["畎畝鏡中分，滄波雜斷雲。", "向來官裏賜，今屬野人耘。", "懷古天難問，貪吟日易曛。", "羽衣傳遺本，起誦想餘芬。"]'),
('b9ed5253-a605-4a65-b16d-7280c051c4e7','天基瑞應宮','劉學箕','宋','宋诗','song-poetry','','[]','金碧擁瓊廬，天開繞電區。',48,'全唐诗/poet.song.179000.json','["金碧擁瓊廬，天開繞電區。", "鳥流周室瑞，蛇斷漢家符。", "石井騰曦馭，瑶壇布斗樞。", "願將皇極福，敷錫徧康衢。"]'),
('5d7e5a60-25f9-4dba-ab0e-e5f13718da88','送東蒲張應發歸永嘉','劉學箕','宋','宋诗','song-poetry','','[]','客裏偶相逢，襟懷亦偶同。',48,'全唐诗/poet.song.179000.json','["客裏偶相逢，襟懷亦偶同。", "對梅吟夜月，新柳間春風。", "子勿言浮梗，余方笑轉蓬。", "歸程經雁蕩，得句附郵筒。"]'),
('9905f763-f4c8-49dc-99d1-92975c51c87d','碧桃','劉學箕','宋','宋诗','song-poetry','','[]','月浸虛庭夜未央，一枝靜對白雲鄉。',32,'全唐诗/poet.song.179000.json','["月浸虛庭夜未央，一枝靜對白雲鄉。", "三生自結玄都約，來伴疎梅到玉堂。"]'),
('478e4b3a-d6e4-44e2-872b-083b17456e97','一春屢有陽明之約雨輒尼之將旋幙侍外舅來游邂逅二羽衣一能參上道一能知天丹竟日留話喜賦二解時清明日也  其一','劉學箕','宋','宋诗','song-poetry','','[]','幾有行山約，山靈早得知。',48,'全唐诗/poet.song.179000.json','["幾有行山約，山靈早得知。", "仙家寧易到，塵世亦何爲。", "草潤非煙石，花流止水池。", "不晴還不雨，正是賣餳時。"]'),
('72700d96-7703-4713-91bb-7d8c416223b0','一春屢有陽明之約雨輒尼之將旋幙侍外舅來游邂逅二羽衣一能參上道一能知天丹竟日留話喜賦二解時清明日也  其二','劉學箕','宋','宋诗','song-poetry','','[]','裂石未嘗關，毋將俗眼觀。',48,'全唐诗/poet.song.179000.json','["裂石未嘗關，毋將俗眼觀。", "虛中原有愛，造藴亦何難。", "羽客能談道，雲房識候丹。", "只應仙有分，風響步虛壇。"]'),
('55252c0d-6fe7-436c-9b50-d2b8862e10eb','道間見桃李花','劉學箕','宋','宋诗','song-poetry','','[]','東風到處競繁華，不問窮簷與大家。',32,'全唐诗/poet.song.179000.json','["東風到處競繁華，不問窮簷與大家。", "垂柳絲中深院宇，隔牆時有出來花。"]'),
('23da3601-7d64-4d46-93b4-85d2925685ea','古寺','劉學箕','宋','宋诗','song-poetry','','[]','應天曾建塔，又此結精廬。',48,'全唐诗/poet.song.179000.json','["應天曾建塔，又此結精廬。", "釋氏緣何熟，詩人念總疎。", "壁荒遺盡水，僧老學醫書。", "笑我重來者，經年不定居。"]'),
('cca5b0db-f840-4d75-884d-0f253d61ed75','奉和龜翁送別','劉學箕','宋','宋诗','song-poetry','','[]','爲說吟邊事，曾陪讌笑頻。',48,'全唐诗/poet.song.179000.json','["爲說吟邊事，曾陪讌笑頻。", "自慚無韵者，敢對有名人。", "雨洗秦山曉，波明鏡水春。", "匆匆還別去，芳草正如茵。"]'),
('06129473-13ad-4350-9a46-1986bf4143d0','蕭山望城中遺漏','劉學箕','宋','宋诗','song-poetry','','[]','見說天文變，頻占太史臺。',48,'全唐诗/poet.song.179000.json','["見說天文變，頻占太史臺。", "但云星犯月，不料火爲災。", "盡夜看煙滅，逢人問訊來。", "丹心勤戀闕，東鄉極裴徊。"]'),
('59083209-256b-49ce-b68e-f6ff289cbeea','喚渡旋幙','劉學箕','宋','宋诗','song-poetry','','[]','半載蓬萊地，相携只是詩。',48,'全唐诗/poet.song.179000.json','["半載蓬萊地，相携只是詩。", "心懷丹鳳去，夢與白鷗隨。", "俯仰俱無愧，勤勞必有知。", "歸舟平似掌，天亦念孤危。"]'),
('acb7c094-69b0-47b9-adb3-fdcace35d39f','和答劉習之見贈','王文孫','宋','宋诗','song-poetry','','[]','先天奧學果何傳，造化機緘存闔闢。',240,'全唐诗/poet.song.179000.json','["先天奧學果何傳，造化機緘存闔闢。", "精微惝恍入神範，天地謂可俄而測。", "粵從二畫抉秘藴，乾元庶物因首出。", "陽推陰蕩六子成，致用坎離爲月日。", "天人相與妙難詰，斯道豈容秦火息。", "九家分派流愈遠，緯讖紛紛非所及。", "韋編三絕繫聖經，微言尚切明作述。", "我生苦晚心好古，謾索圖書考龜策。", "浩如烟海無津涯，自哂蓬心窺至賾。", "衆言淆亂折以理，是非安敢决諸臆。", "吉凶前定信可推，人事堪憐空役役。", "優游姑樂環中趣，默參經世用皇極。", "較量得失心自知，議論無用形於筆。", "觀君氣宇元靜定，何慮不優入聖閾。", "不鄙謂予可相友，願鑿渾沌以報德。"]'),
('550f03bc-70b7-4952-9407-2f77aa9e51ac','西京少年行','周端臣','宋','宋诗','song-poetry','','[]','西京少年兒，生長豪貴族。',72,'全唐诗/poet.song.179000.json','["西京少年兒，生長豪貴族。", "光浮兩臉紅，春留雙鬢綠。", "常騎大宛馬，多佩于闐玉。", "明珠博美姬，黄金酬麗曲。", "朝從咸陽遊，暮向長陵宿。", "朱門人候歸，夜夜然紅燭。"]'),
('f368d669-09bb-4c27-930e-c5717c661fce','毋忽詩','周端臣','宋','宋诗','song-poetry','','[]','毋忽咫尺水，中恐有伏龍。',84,'全唐诗/poet.song.179000.json','["毋忽咫尺水，中恐有伏龍。", "毋忽尋丈山，中恐有毒蟲。", "是以古君子，不敢欺盲聾。", "審密言語間，戒謹闇室中。", "幾微怠所防，敵國起奴童。", "事固不可忽，理亦不可窮。", "周室八百年，成於垂釣翁。"]'),
('68d28c3b-60d0-4e89-a60d-b5e8285f5c00','僕以紹熙壬子中夏二十有五日始躋風篁探龍井遂至廣福謁三賢像閲舊碑追觀一代風流爲賦此詩適月林依公留設茗供因書以遺之他日能爲我揭詩板于壁間使示來者亦山中之一助也','周端臣','宋','宋诗','song-poetry','','[]','奇石爛橫道，茲山信多姿。',192,'全唐诗/poet.song.179000.json','["奇石爛橫道，茲山信多姿。", "江湖釃兩股，一泓乃孤危。", "相傳龍所家，或恐神護持。", "腥風轉霮䨴，陰崖立淋漓。", "惜無緯蕭勇，探此抱寶癡。", "山僧作屋意，慘澹生幽思。", "胡爲金繆影，顛倒眩俗兒。", "坐來百念失，蒼官導前馳。", "招提果深登，屐痕恍前期。", "咄哉少肉山，著此高顴師。", "端能致遨遊，絕唱相娛嬉。", "過溪亦何事，相送了不疑。", "渠能縛禪律，因來數鬚眉。", "我愛秦郎記，字壓頭陀碑。", "月林只夜夜，人物自一時。", "賢愚盡蟻封，來者吾得知。"]'),
('a8fa6b94-eec0-4f94-ab3b-225484dde141','二月芳草碧寄吳中故人','周端臣','宋','宋诗','song-poetry','','["\u897f\u6e56"]','二月芳草碧，江南新燕來。',120,'全唐诗/poet.song.179000.json','["二月芳草碧，江南新燕來。", "撫茲良歲時，佳人安在哉。", "佳人棄我去，杳在天之涯。", "天涯望不極，叢愁結中懷。", "翠觴不成歡，玉琴有餘哀。", "西湖春事深，林花爲誰開。", "折花無所贈，三嗅空徘徊。", "樓前東流水，湛湛生綠苔。", "去波日千里，還繞姑蘇臺。", "憑水寄我思，旦暮腸九回。"]'),
('85361347-ff6c-44f9-bbf1-6e5c3ee43a5b','聽無悔琴','周端臣','宋','宋诗','song-poetry','','[]','悟琴如悟道，神閒若無營。',48,'全唐诗/poet.song.179000.json','["悟琴如悟道，神閒若無營。", "在心不在指，以意非以聲。", "鏘爾風篁韻，泠然天籟鳴。", "曲終各一笑，相對無虧成。"]'),
('67644b70-6ef1-415c-a047-2437685cf2c1','物蠹','周端臣','宋','宋诗','song-poetry','','[]','太虛運元氣，萬物皆憑倚。',72,'全唐诗/poet.song.179000.json','["太虛運元氣，萬物皆憑倚。", "物或有所違，氣亦隨而否。", "肉蠹則生蟲，木蠹則生蟻。", "嗟哉政亦然，於焉起姦宄。", "蠹久不可爲，氣靡物自毀。", "但得元氣存，不患蠹不死。"]'),
('e2e3151f-fe00-4f8e-9d3b-ec5a5a203b73','奉謝芸居清供之招','周端臣','宋','宋诗','song-poetry','','[]','生平愧彼蒼，得飽非耘種。',204,'全唐诗/poet.song.179000.json','["生平愧彼蒼，得飽非耘種。", "自揆蔑寸長，居然叨薄俸。", "朅來桂玉地，幸了藜藿奉。", "日昨訪芸居，見我如伯仲。", "劇談闢幽荒，妙論洗沉痛。", "呼童張樽罍，芳醪啟春甕。", "乃約屏羶葷，初筵俱清供。", "珠櫻映翠莢，光色交浮動。", "佳境喜漸入，愷之未癡惷。", "屬厭薦春萌，雋永咀秋葑。", "黄獨忽登俎，味借蜂蜜重。", "翻憐少陵翁，山雪入吟諷。", "早韭晚菘輩，吾家所售用。", "列品不自珍，而與朋友共。", "琱盤放手空，適口頗恣縱。", "日暮雨催返，虛窗結清夢。", "寄語五侯鯖，從茲勿勞送。"]'),
('20031160-eabf-4968-92a9-47d1dc0ecf25','孟冬多風霜','周端臣','宋','宋诗','song-poetry','','[]','孟冬多風霜，草木俱披靡。',60,'全唐诗/poet.song.179000.json','["孟冬多風霜，草木俱披靡。", "老柳葉纔脫，拂拂新萌起。", "凍梅如枯榛，班班亦含蘂。", "寒暑運四時，成此歲功美。", "孰知四時間，獨有春不死。"]'),
('91710beb-0ca1-4770-8a45-f346052cabf9','白虎行','周端臣','宋','宋诗','song-poetry','','[]','女脩玄鳥開嬴始，附庸于周自非子。',163,'全唐诗/poet.song.179000.json','["女脩玄鳥開嬴始，附庸于周自非子。", "由襄寖强三十世，末命昭莊踰崛起。", "殺降濺血長平坑，返戈盡篡天王城。", "黷兵不戢恃彊大，物忌太盛終當傾。", "邯鄲賈人識奇貨，發謀不惜千金破。", "窈窕尊前歌舞人，腹中已孕秦家禍。", "怙勢陵威奮餘烈，怨氣愁聲九州裂。", "虎暴狼貪天使然，六國未滅嬴先滅。", "天道何曾長助彊，豈知用柔能勝剛。", "君不見後來項羽戰無敵，却使山河歸漢王。"]'),
('d43807bf-5fff-40f6-a002-0d3449ff1eeb','送翁賓暘之荆湖','周端臣','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','君不見司馬子長志橫秋，少年足跡不肯休。',266,'全唐诗/poet.song.179000.json','["君不見司馬子長志橫秋，少年足跡不肯休。", "胸中盤屈奇偉氣，筆力直與造化侔。", "又不見杜陵子美夸壯遊，一身幾走半九州。", "吟懷吐納天地秀，作爲篇章光斗牛。", "君今去去幾千里，匣劍囊書赴知己。", "知己從來素有情，投機之會趨功名。", "功名豈有作能致，莫辭跋涉長江行。", "長江四月南風起，武昌魚飲秦淮水。", "南風不久又西風，食魚休忘鱸魚美。", "天涯別夢思城東，何日一樽重與同。", "草橋夜醉月明下，桃關晴吟春色中。", "不堪蜀魄相催去，却憐檣燕相留住。", "一片離情去住間，正是遊人腸斷處。", "荆湖右道分南北，勢與中原豈懸隔。", "五湖膏血互吞噬，萬里烟塵入謀畫。", "莫如子長子美但能事文章，蚤歸來獻平戎策。"]'),
('fee1778d-7c74-4516-9918-f489a7076e60','遊下竺枕流亭','周端臣','宋','宋诗','song-poetry','','[]','枕流亭下路，兩歲不曾來。',48,'全唐诗/poet.song.179000.json','["枕流亭下路，兩歲不曾來。", "今日偶重到，夕陽猶未回。", "池乾無水放，地暖有花開。", "後約如能繼，多應爲探梅。"]'),
('885feb2e-77c0-4856-8f18-e8b7f35a18dc','真州梅','周端臣','宋','宋诗','song-poetry','','[]','欹倒幾株梅，黏枝半是苔。',48,'全唐诗/poet.song.179000.json','["欹倒幾株梅，黏枝半是苔。", "相傳前代種，曾歷太平來。", "山冷雪猶在，春深花始開。", "亂離無酒買，嚼蘂當銜杯。"]'),
('de2c191f-c82f-42d0-8e9d-f24feff2092b','書冷泉亭壁','周端臣','宋','宋诗','song-poetry','','[]','一酌野泉香，翛然俗慮忘。',48,'全唐诗/poet.song.179000.json','["一酌野泉香，翛然俗慮忘。", "靜聽山鳥語，如笑世人忙。", "近水苔常濕，無風樹亦凉。", "老僧閒似我，清坐到斜陽。"]'),
('a2a5a211-f00a-44c4-9c73-63a993f45fcd','聞滁陽失守憶表兄','周端臣','宋','宋诗','song-poetry','','[]','猶憶歸淮甸，何期陷敵塵。',48,'全唐诗/poet.song.179000.json','["猶憶歸淮甸，何期陷敵塵。", "祇聞殘破慘，未得死生真。", "夢不諳長路，書難附便人。", "吞聲無限淚，一滴一傷神。"]'),
('5ae4b18e-b669-4c93-bc2b-dea00f5cbeed','裴墳','周端臣','宋','宋诗','song-poetry','','[]','買船穿僻徑，墳古最幽深。',48,'全唐诗/poet.song.179000.json','["買船穿僻徑，墳古最幽深。", "山近風常冷，松蟠晝亦陰。", "來時無速騎，歸路有鳴禽。", "寄語城居者，何人肯訪尋。"]'),
('1c82201c-3aba-41e7-9c95-ecb7535a079a','虛室','周端臣','宋','宋诗','song-poetry','','[]','虛室似僧房，蒲團倚竹床。',48,'全唐诗/poet.song.179000.json','["虛室似僧房，蒲團倚竹床。", "半窗紅日影，一陣紫蘭香。", "誦熟閒居賦，書成急就章。", "數朝門不出，過却幾春光。"]'),
('daa54957-cd55-42b9-b264-ddebcee60ea2','湖天','周端臣','宋','宋诗','song-poetry','','[]','湖天初過雨，晴意有無間。',48,'全唐诗/poet.song.179000.json','["湖天初過雨，晴意有無間。", "春水半侵路，曉雲多礙山。", "酒煩村店暖，詩就野亭刪。", "風靜無啼鳥，垂楊樹樹閒。"]'),
('2f35afc1-2b4a-41b2-a0a4-b6694e2b4319','登駝巘嶺','周端臣','宋','宋诗','song-poetry','','[]','登頓來忘倦，閒常到亦難。',48,'全唐诗/poet.song.179000.json','["登頓來忘倦，閒常到亦難。", "西風摇短鬢，落日倚危欄。", "山迥江湖小，秋高天地寬。", "故園何處是，空遣客眸酸。"]'),
('95c556f7-d18a-4d27-8cfb-379fb6636f3d','富景園詩','周端臣','宋','宋诗','song-poetry','','[]','地比諸園小，池從前代開。',48,'全唐诗/poet.song.179000.json','["地比諸園小，池從前代開。", "猶餘喬木在，曾見上皇來。", "幽徑埋黄葉，空庭老綠苔。", "荒寒吟思怯，落日獨徘徊。"]'),
('c91631e6-6c79-4b55-9b5a-f0dd664fad82','初冬即事','周端臣','宋','宋诗','song-poetry','','[]','初冬天氣暖，小似立春時。',48,'全唐诗/poet.song.179000.json','["初冬天氣暖，小似立春時。", "萬樹無多葉，千花試一枝。", "天紅霜有信，星暈雨先期。", "怕見梅花發，愁懷未辦詩。"]'),
('d7ee7789-f0d1-4399-8e7d-16162c23f637','讀黨籍碑','周端臣','宋','宋诗','song-poetry','','[]','黨籍碑成國步屯，忠臣埋沒瘴鄉塵。',64,'全唐诗/poet.song.179000.json','["黨籍碑成國步屯，忠臣埋沒瘴鄉塵。", "興衰未必皆關數，治亂由來實在人。", "雷昔震陵天已怒，石今漫滅世尤珍。", "九原難叫諸賢起，一掬傷心淚染巾。"]'),
('92aba73e-b8ad-4d5e-b5b7-ed3b88e2e3b3','重陽後一日偕翁賓暘張敬之江樓分韻得臺字','周端臣','宋','宋诗','song-poetry','','[]','一笑江樓把酒杯，闌干倚徧重徘徊。',64,'全唐诗/poet.song.179000.json','["一笑江樓把酒杯，闌干倚徧重徘徊。", "風生別浦潮回去，雲暗前山雨過來。", "秋冷丹楓先葉墜，節遲黄菊未花開。", "憑高引領還興感，昨日誰登戯馬臺。"]'),
('359ea0a3-c1ee-4dd1-ae5a-f78d2f88de02','青銅香鴨詩','周端臣','宋','宋诗','song-poetry','','[]','誰把工夫巧鑄成，銅青依約綠毛輕。',64,'全唐诗/poet.song.179000.json','["誰把工夫巧鑄成，銅青依約綠毛輕。", "自歸騷客文房後，無復王孫金彈驚。", "沙觜莫追蘆葦暖，灰心聊吐蕙蘭清。", "回頭却笑江湖伴，多少遭烹爲不鳴。"]'),
('b3ed2045-f215-4db7-8329-fed353802cf6','送牛首爐與人','周端臣','宋','宋诗','song-poetry','','[]','千載墦間偶得存，傳從鼻祖到雲孫。',64,'全唐诗/poet.song.179000.json','["千載墦間偶得存，傳從鼻祖到雲孫。", "土痕蝕處形摹薄，苔色侵來款識昏。", "製樣想應規象鼎，驗圖只合配犧尊。", "贈君博古齋中去，書傳閒時細討論。"]'),
('a510dbea-386b-4b14-9222-3ea3ca3e7fe8','代上劉郎中','周端臣','宋','宋诗','song-poetry','','["\u8861\u5c71"]','彈壓江湖聳市朝，相逢人盡說風騷。',64,'全唐诗/poet.song.179000.json','["彈壓江湖聳市朝，相逢人盡說風騷。", "詩從南嶽吟逾老，名得西山薦益高。", "半世歷官纔幕府，午年還國尚郎曹。", "兒時曾誦先生句，鏡裏如今已二毛。"]'),
('6413587a-9ac8-41a1-b9d9-53726cc67943','古劍','周端臣','宋','宋诗','song-poetry','','[]','籀文漫滅蘚花殘，膽怯旁人不敢看。',64,'全唐诗/poet.song.179000.json','["籀文漫滅蘚花殘，膽怯旁人不敢看。", "飛去暗防風雨夜，握來光射斗牛寒。", "曾成歃血諸侯約，肯受無魚下客彈。", "寶匣秘藏英氣在，提携終擬斬樓蘭。"]'),
('741c4ec6-9709-46ca-abde-bbc6fc834ae5','送人失官歸','周端臣','宋','宋诗','song-poetry','','[]','浮世功名總是虛，縱然軒冕又何如。',64,'全唐诗/poet.song.179000.json','["浮世功名總是虛，縱然軒冕又何如。", "趁無白髮來侵鏡，好買青山去荷鋤。", "賢聖一丘無用土，英雄幾板可疑書。", "生涯儻了寒暄計，獨抱遺經亦有餘。"]'),
('30655cf5-7c74-4ab0-8a8a-ab97a3ca0767','次韻友人悼寵落梅','周端臣','宋','宋诗','song-poetry','','[]','條脫空嗟萼綠華，俗塵難久駐仙車。',64,'全唐诗/poet.song.179000.json','["條脫空嗟萼綠華，俗塵難久駐仙車。", "數聲畫角單于塞，一曲山香阿母家。", "墮砌尚疑粧後粉，點衣猶認唾時花。", "別來埋沒春風面，幾度虛窗歎月斜。"]'),
('195dc04e-873e-4fec-8baf-d62e3d9b6090','春日即事','周端臣','宋','宋诗','song-poetry','','[]','起來袖手怯寒添，冷落文楸掩玉奩。',64,'全唐诗/poet.song.179000.json','["起來袖手怯寒添，冷落文楸掩玉奩。", "燕子池塘春雨細，杏花庭院曉風尖。", "酒酲未解便欹枕，香炷初熏密下簾。", "百五數來能幾日，黄金柳色已侵簷。"]'),
('eb153669-ecef-4fae-a2e6-f823267a35d1','遊秀府擇勝園','周端臣','宋','宋诗','song-poetry','','[]','擇勝前朝錫雅名，不多花木四時榮。',64,'全唐诗/poet.song.179000.json','["擇勝前朝錫雅名，不多花木四時榮。", "樓當列岫仍臨水，地比諸園最傍城。", "池暖錦鱗冬亦泳，洞寒丹鶴曉先鳴。", "宗王信是神仙侶，創得蓬壺小樣成。"]'),
('52c1c543-fcc0-41ce-b246-1e4c75037363','咏鶴','周端臣','宋','宋诗','song-poetry','','[]','覓來雛鶴養經年，認得呼名傍客前。',64,'全唐诗/poet.song.179000.json','["覓來雛鶴養經年，認得呼名傍客前。", "放去幾隨雲過海，歸來一片雪翻天。", "翎梳脩竹林間日，影照寒梅磵下泉。", "眷戀軒墀應有謂，主人風骨是神仙。"]'),
('ba803e7a-5bbc-4655-86f8-1ea3ece82fc7','落葉','周端臣','宋','宋诗','song-poetry','','[]','燮燮霜紅不自持，半隨流水半霑泥。',64,'全唐诗/poet.song.179000.json','["燮燮霜紅不自持，半隨流水半霑泥。", "歸巢便覺棲禽冷，覓穴空教返蟻迷。", "風徑學花飛上下，夜窗疑雨灑東西。", "滿階不聽家僮掃，擬把新詩逐片題。"]'),
('8cc2a08c-73c1-43fc-89c9-8fd59fe6479a','次韻張敬之桂花','周端臣','宋','宋诗','song-poetry','','[]','年年綠桂著花時，黄雪團枝自一奇。',64,'全唐诗/poet.song.179000.json','["年年綠桂著花時，黄雪團枝自一奇。", "林靜秋風生處早，山高凉月上來遲。", "亭邊露濕欄猶倚，書畔香清枕屢欹。", "惆悵淮南無夢到，楚騷歌罷當吟詩。"]'),
('a7db4c7c-1884-4af9-ba6a-2a9c5a725e73','次韻勿齋蠟梅','周端臣','宋','宋诗','song-poetry','','[]','不與南枝鬭粉光，品題應合讓蘇黄。',64,'全唐诗/poet.song.179000.json','["不與南枝鬭粉光，品題應合讓蘇黄。", "融成蜂蠟千葩秀，散作龍涎幾陣香。", "立悟瞿曇真面目，坐忘姑射舊梳粧。", "好風吹墮檀心句，白雪空驚寡和章。"]'),
('6cae5549-fa8d-4616-8f41-9923966b24b6','碧桃','周端臣','宋','宋诗','song-poetry','','[]','武陵夢覺艷粧空，回首芳姿迥不同。',64,'全唐诗/poet.song.179000.json','["武陵夢覺艷粧空，回首芳姿迥不同。", "萼綠仙留蒼玉佩，蘂珠人在碧霞宮。", "素顋褪粉啼春雨，翠袖籠寒怯曉風。", "惆悵湧金池上路，闌桿倚遍夕陽中。"]'),
('58f3c0a0-4d4a-4876-afe4-58b6a0f362ee','靈隠山前即事','周端臣','宋','宋诗','song-poetry','','[]','猿不聞呼僧已歸，翠煙依舊鎖崔嵬。',64,'全唐诗/poet.song.179000.json','["猿不聞呼僧已歸，翠煙依舊鎖崔嵬。", "水今流向人寰去，山昔飛從佛國來。", "古徑夏寒風落木，蒼崖陰潤雨生苔。", "客纓自喜無塵濯，歌罷滄浪飲一杯。"]'),
('c17de784-3373-4e91-bcf2-5d20d8f3d1db','春日閒居','周端臣','宋','宋诗','song-poetry','','[]','自笑春來縱酒狂，信緣無定恣尋芳。',64,'全唐诗/poet.song.179000.json','["自笑春來縱酒狂，信緣無定恣尋芳。", "盃中似蟻浮來綠，甕裏如鵝脫下黄。", "花底枕琴迷洞府，溪邊濯足憶滄浪。", "一從禁閣辭榮後，不復乘雲入帝鄉。"]'),
('1066b486-c249-41e9-bb04-3740ca1e50c4','劉寺墳園','周端臣','宋','宋诗','song-poetry','','[]','萬竹蒼寒擁寺門，寺牌金字御書存。',64,'全唐诗/poet.song.179000.json','["萬竹蒼寒擁寺門，寺牌金字御書存。", "榮華肯信當年事，儀制空留後世恩。", "影閣有燈塵網暗，殯宮無月土花昏。", "見梅不敢輕攀折，恐是春風水際魂。"]'),
('6468be2c-50f2-49da-b698-b86c33451ac6','棲霞嶺','周端臣','宋','宋诗','song-poetry','','[]','九折崎嶇入杳冥，蒼崖中斷見雲生。',64,'全唐诗/poet.song.179000.json','["九折崎嶇入杳冥，蒼崖中斷見雲生。", "著身高處不知險，回首省時方始驚。", "半嶺雷奔空石墮，滿山花發曉霞明。", "世間豈是無平地，何事吾儂愛此行。"]'),
('1114bac3-6d5f-4812-8130-793189dcc94b','遊籍田','周端臣','宋','宋诗','song-poetry','','[]','國典斯爲重，親耕示不輕。',240,'全唐诗/poet.song.179000.json','["國典斯爲重，親耕示不輕。", "詔涓正月吉，躬率百僚行。", "奉禮儀脩獻，司農器具呈。", "儲胥嚴武備，鹵簿肅文明。", "北闕班春早，東郊賀雨晴。", "青壇晨氣潤，紫陌曉寒清。", "玄武移天仗，鈎陳出帝城。", "停雲依別殿，翔鳥避行營。", "十二蒼龍駕，三千白虎兵。", "園花迎翠輦，田柳拂霓旌。", "少皡陳圭瓚，先農薦特牲。", "紺轅縈黛耜，蒼佩映朱絃。", "俯講三推禮，祗勤萬乘情。", "艱難均土庶，次第及公卿。", "海寓瞻秋稔，山川慶禮成。", "豈惟知稼穡，况乃奉粢盛。", "祈歲稽豳雅，因時昉舜耕。", "顧嚴天下勸，非侈國人榮。", "芸史觀先烈，桑樞歎晚生。", "何當蕆熙事，夷夏頌隆平。"]'),
('c6958c71-4d20-4820-ab87-bc78a0e27a03','古斷腸曲三十首  其一','周端臣','宋','宋诗','song-poetry','','[]','髻雲鬆滑嚲鸞釵，清減羞臨玉鏡臺。',32,'全唐诗/poet.song.179000.json','["髻雲鬆滑嚲鸞釵，清減羞臨玉鏡臺。", "蛺蝶也知人寂寞，一雙飛過杏牆來。"]'),
('caefc58f-e0ee-40b0-b590-eb3202e8e203','古斷腸曲三十首  其二','周端臣','宋','宋诗','song-poetry','','[]','催花一霎雨依微，芳逕泥香草色萋。',32,'全唐诗/poet.song.179000.json','["催花一霎雨依微，芳逕泥香草色萋。", "可是一春天氣冷，牡丹開了未鶑啼。"]'),
('10ccf0d5-f32d-4b80-b23a-0f54d61a1ecb','古斷腸曲三十首  其三','周端臣','宋','宋诗','song-poetry','','[]','被擁嬌寒曉夢春，起來無事翠眉顰。',32,'全唐诗/poet.song.179000.json','["被擁嬌寒曉夢春，起來無事翠眉顰。", "金瓶拈得雙青杏，掐破中心見箇人。"]'),
('22fad092-e658-4571-b0a8-da39dee9ed3d','古斷腸曲三十首  其四','周端臣','宋','宋诗','song-poetry','','[]','竹葉裙紗摺摺香，荷風占斷晚西凉。',32,'全唐诗/poet.song.179000.json','["竹葉裙紗摺摺香，荷風占斷晚西凉。", "年來歡事愁邊減，別後秋更夢外長。"]'),
('73a861e9-4e58-44fd-9742-0bd8747315da','古斷腸曲三十首  其五','周端臣','宋','宋诗','song-poetry','','[]','條風窗戶柳陰陰，雲碧春衫熨水沉。',32,'全唐诗/poet.song.179000.json','["條風窗戶柳陰陰，雲碧春衫熨水沉。", "花裏小欄人不到，流鶑啼起去年心。"]'),
('804e4ce1-3bd9-447f-91d0-44a978d9cd2e','古斷腸曲三十首  其六','周端臣','宋','宋诗','song-poetry','','[]','夢破巫山生色屏，錦囊情薄歇餘馨。',32,'全唐诗/poet.song.179000.json','["夢破巫山生色屏，錦囊情薄歇餘馨。", "關河春晚無消息，腸斷樓前楊柳青。"]'),
('50700886-27dc-4315-84a0-9b53601efecb','古斷腸曲三十首  其七','周端臣','宋','宋诗','song-poetry','','[]','無計消除夜漏長，羅衾熏徹舊時香。',32,'全唐诗/poet.song.179000.json','["無計消除夜漏長，羅衾熏徹舊時香。", "十分又是凄愁處，雨歇芭蕉小院凉。"]'),
('c96bed5d-1011-4b3f-b1c6-4505451c7027','古斷腸曲三十首  其八','周端臣','宋','宋诗','song-poetry','','[]','香凝薇帳春風院，酒涴榴裙夜月樓。',32,'全唐诗/poet.song.179000.json','["香凝薇帳春風院，酒涴榴裙夜月樓。", "閒把花枝思往事，舊懽都變作新愁。"]'),
('b6c04df6-a71e-4775-8f3a-e2deeeb27b5f','古斷腸曲三十首  其九','周端臣','宋','宋诗','song-poetry','','[]','一篩凉雨歇亭臯，菡萏無香可得消。',32,'全唐诗/poet.song.179000.json','["一篩凉雨歇亭臯，菡萏無香可得消。", "玉簟怯秋眠未穩，阿誰樓上夜吹簫。"]'),
('d62aa164-561e-433a-9a79-c1720a295c63','古斷腸曲三十首  其一○','周端臣','宋','宋诗','song-poetry','','[]','團扇多情手尚携，金風庭砌拒霜開。',32,'全唐诗/poet.song.179000.json','["團扇多情手尚携，金風庭砌拒霜開。", "斷腸一夜西樓雁，不带書來带恨來。"]'),
('e34f26a2-3ae5-4a6d-8d08-66bb6d5d77a6','古斷腸曲三十首  其一一','周端臣','宋','宋诗','song-poetry','','[]','破除難盡是恩情，却怕恩生怨亦生。',32,'全唐诗/poet.song.179000.json','["破除難盡是恩情，却怕恩生怨亦生。", "思念不休心惑亂，夢驚人語似郎聲。"]'),
('20f0954a-f02e-4bf3-8c35-b5b8baa60130','古斷腸曲三十首  其一二','周端臣','宋','宋诗','song-poetry','','[]','一股金花擘斷釵，兩行玉筯界香顋。',32,'全唐诗/poet.song.179000.json','["一股金花擘斷釵，兩行玉筯界香顋。", "近來自覺冰肌瘦，柳綠春衫放窄裁。"]'),
('42cab689-bfdd-41a4-9bf2-2ee7f2af6862','古斷腸曲三十首  其一三','周端臣','宋','宋诗','song-poetry','','[]','井梧和雨下銀床，梁燕隨風別畫堂。',32,'全唐诗/poet.song.179000.json','["井梧和雨下銀床，梁燕隨風別畫堂。", "二十五聲秋漏永，夢回各自耐思量。"]');
